export const ENRICH = {"c-22":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-22","factCheck":"Verified: Bill C-22 (Lawful Access Act, 2026), sponsored by the Minister of Public Safety, is at committee study in the House of Commons (second reading and referral to committee on April 20, 2026); it is NOT yet law. It is the standalone successor to the lawful-access provisions (former Parts 14 and 15) stripped out of Bill C-2 in October 2025; its Part 1 narrows the scope of warrantless information requests compared to C-2, but critics (Citizen Lab, Apple, CCLA, Michael Geist) warn its technical-capability mandate could still compel encryption backdoors and require up to one year of metadata retention.","sources":[{"title":"C-22 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-22","type":"official"},{"title":"Bill C-22, An Act respecting lawful access - Legislative Summary (Library of Parliament)","url":"https://lop.parl.ca/staticfiles/PublicWebsite/Home/ResearchPublications/LegislativeSummaries/PDF/45-1/PV_45-1-C22-E.pdf","type":"official"},{"title":"CCLA and Coalition to MPs: Scrap Unprecedented Surveillance Measures in Bill C-22","url":"https://ccla.org/privacy/coalition-to-mps-scrap-unprecedented-surveillance-measures/","type":"advocacy"},{"title":"The Lawful Access Two-Headed Surveillance Monster: How Bill C-22 Went Off the Rails - Michael Geist","url":"https://www.michaelgeist.ca/2026/05/the-lawful-access-two-headed-surveillance-monster-how-bill-c-22-went-off-the-rails/","type":"academic"},{"title":"(Un)forced Errors: Analysis of Proposed Surveillance Law Expansion under Bill C-22 - The Citizen Lab","url":"https://citizenlab.ca/research/analysis-of-proposed-surveillance-law-expansion-under-bill-c-22/","type":"academic"},{"title":"US Congress warns Ottawa's lawful-access bill could weaken defences against hackers - Globe and Mail","url":"https://www.theglobeandmail.com/politics/article-us-congress-lawful-access-bill-c-22-hackers/","type":"news"}],"commentary":[{"source":"Canadian Civil Liberties Association (and coalition of 25+ groups)","stance":"oppose","quote":"If passed into law, the legislative proposal would represent the broadest expansion of government surveillance powers in recent Canadian history.","url":"https://ccla.org/privacy/coalition-to-mps-scrap-unprecedented-surveillance-measures/"},{"source":"Michael Geist (University of Ottawa law professor)","stance":"oppose","quote":"Apple has stated the bill allows the government to force companies to break encryption by inserting backdoors into their products, and the metadata-retention regime would create a surveillance map of virtually every Canadian.","url":"https://www.michaelgeist.ca/2026/05/apple-on-bill-c-22-this-bill-allows-the-government-of-canada-to-force-companies-to-break-encryption-by-inserting-backdoors-into-their-products/"},{"source":"Canadian Bar Association","stance":"mixed","quote":"The new lawful access bill is better than its predecessor in Bill C-2, but C-22 still needs work, particularly on thresholds and oversight.","url":"https://cba.org/our-impact/submissions/bill-c-22-lawful-access-act-2026/bill-c-22-lawful-access-act-2026"}]},"c-2":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-2","factCheck":"Verified: Bill C-2 (Strong Borders Act), sponsored by Public Safety Minister Gary Anandasangaree, has been stalled at second reading in the House of Commons since debate on September 17, 2025. Common misinformation overstates its current contents: the controversial lawful-access/warrantless-data provisions (Parts 14 and 15) were REMOVED in October 2025 and re-tabled separately as Bill C-22 (lawful access) and Bill C-12 (border/immigration measures, now law), so the surveillance powers people still attribute to 'C-2' are no longer being advanced under this bill number.","sources":[{"title":"C-2 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-2","type":"official"},{"title":"Government Reverses on Bill C-2: Removes Lawful Access Warrantless Demand Powers - Michael Geist","url":"https://www.michaelgeist.ca/2025/10/government-reverses-on-bill-c-2-removes-lawful-access-warrantless-demand-powers-in-new-border-bill/","type":"academic"},{"title":"Bill C-2: Strong Borders Act Introduces Lawful Access and Data Disclosure Regime - Fasken","url":"https://www.fasken.com/en/knowledge/2025/06/bill-c2-strong-borders-act-introduces-lawful-access-and-data-disclosure-regime","type":"legal"},{"title":"Bill C-2 information resources outline significant privacy concerns - CCLA","url":"https://ccla.org/privacy/bill-c-2-information-resources/","type":"advocacy"},{"title":"Over 10,000 OpenMedia Members Demand Withdrawal of the 'Strong Borders' Act - OpenMedia","url":"https://openmedia.org/article/item/over-10000-openmedia-members-demand-withdrawal-of-the-strong-borders-act","type":"advocacy"}],"commentary":[{"source":"OpenMedia","stance":"oppose","quote":"More than 10,000 members wrote to their MPs demanding the Strong Borders Act be withdrawn, calling its lawful-access measures a betrayal of Canadian rights driven by US data demands.","url":"https://openmedia.org/article/item/over-10000-openmedia-members-demand-withdrawal-of-the-strong-borders-act"},{"source":"Canadian Civil Liberties Association","stance":"oppose","quote":"CCLA renewed its call for the government to drop its entire Strong Borders package, citing significant privacy concerns and conflict with Charter rights and Supreme Court jurisprudence on subscriber information.","url":"https://ccla.org/privacy/ccla-renews-calls-for-government-to-drop-its-strong-borders-package/"},{"source":"Fasken (law firm analysis)","stance":"mixed","quote":"Bill C-2 introduced a sweeping lawful access and data-disclosure regime; the government subsequently removed those provisions and reintroduced them, in modified form, in Bill C-22.","url":"https://www.fasken.com/en/knowledge/2025/06/bill-c2-strong-borders-act-introduces-lawful-access-and-data-disclosure-regime"}]},"c-12":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-12","factCheck":"Verified: Bill C-12 (Strengthening Canada's Immigration System and Borders Act) received Royal Assent on March 26, 2026 (Statutes of Canada 2026, c. 4) and is now law. It carries forward the border/immigration measures of Bill C-2 but NOT the lawful-access surveillance parts; among other changes it makes asylum claims filed more than one year after first arrival ineligible for referral to the Immigration and Refugee Board.","sources":[{"title":"C-12 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-12","type":"official"},{"title":"Legislation that strengthens the immigration system and border security receives Royal Assent - Canada.ca","url":"https://www.canada.ca/en/public-safety-canada/news/2026/03/legislation-that-strengthens-the-immigration-system-and-border-security-receives-royal-assent.html","type":"official"},{"title":"Passing of Bill C-12 is an Attack on Refugee and Migrant Rights in Canada - CCLA","url":"https://ccla.org/press-release/passing-of-bill-c-12-is-an-attack-on-refugee-and-migrant-rights-in-canada/","type":"advocacy"},{"title":"Criticism of Bill C-12 grows over risks to the health of refugees and migrants - Radio-Canada","url":"https://ici.radio-canada.ca/rci/en/news/2243814/report-criticism-of-bill-c-12-grows-over-risks-to-the-health-of-refugees-and-migrants","type":"news"},{"title":"Key UN Body Issues Stark Assessment of Bill C-12 Immigration Reforms - CCLA","url":"https://ccla.org/equality/key-un-body-issues-stark-assessment-of-human-rights-in-canada/","type":"advocacy"}],"commentary":[{"source":"Canadian Civil Liberties Association","stance":"oppose","quote":"The passing of Bill C-12 is an attack on refugee and migrant rights; it creates fundamental unfairness and will violate the Charter and Canada's international human-rights obligations.","url":"https://ccla.org/press-release/passing-of-bill-c-12-is-an-attack-on-refugee-and-migrant-rights-in-canada/"},{"source":"UN Human Rights Committee","stance":"oppose","quote":"The Committee issued a stark assessment warning that C-12 undermines critical procedural safeguards for refugees as part of a broader erosion of human rights in Canada.","url":"https://ccla.org/equality/key-un-body-issues-stark-assessment-of-human-rights-in-canada/"},{"source":"Government of Canada (Public Safety)","stance":"support","quote":"The Act strengthens Canada's immigration and asylum systems and gives law enforcement more tools to secure borders and combat transnational organized crime, fentanyl, and illicit financing.","url":"https://www.canada.ca/en/public-safety-canada/news/2026/03/legislation-that-strengthens-the-immigration-system-and-border-security-receives-royal-assent.html"}]},"c-8":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-8","factCheck":"Verified: Bill C-8 (Cyber Security Act) received Royal Assent on June 15, 2026 (Statutes of Canada 2026, c. 9); it amends the Telecommunications Act and enacts the Critical Cyber Systems Protection Act for sectors such as telecom, finance, energy and transport. Note for accuracy: a late amendment expressly bars the Minister or Governor in Council from ordering the decryption of an encrypted private communication, so claims that the final Act mandates encryption backdoors are no longer accurate, though civil-liberties groups still flag warrantless data mechanisms and secret orders.","sources":[{"title":"C-8 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-8","type":"official"},{"title":"Government of Canada Strengthens Cyber Security with Royal Assent of Bill C-8","url":"https://www.newswire.ca/news-releases/government-of-canada-strengthens-cyber-security-and-critical-infrastructure-with-royal-assent-of-bill-c-8-874016254.html","type":"official"},{"title":"Government needs to fix dangerous flaws in federal cybersecurity proposal - CCLA","url":"https://ccla.org/privacy/fix-dangerous-flaws-in-federal-cybersecurity-proposal/","type":"advocacy"},{"title":"Bill C-8 Passes House of Commons Following Substantive Amendments - Fasken","url":"https://www.fasken.com/en/knowledge/2026/04/bill-c8","type":"legal"},{"title":"Submission to Senate Committee on Bill C-8 - Office of the Privacy Commissioner of Canada","url":"https://www.priv.gc.ca/en/opc-actions-and-decisions/advice-to-parliament/2026/parl_sub_260522_c8/","type":"official"}],"commentary":[{"source":"Tamir Israel, CCLA (Privacy, Surveillance and Technology Program)","stance":"mixed","quote":"By failing to guarantee critical end-to-end encryption protocols will not be undermined, Bill C-8 risks doing more harm than good to cybersecurity; its warrantless data-access mechanisms and secrecy-by-default approach pose an additional threat to privacy and civil liberties.","url":"https://ccla.org/privacy/fix-dangerous-flaws-in-federal-cybersecurity-proposal/"},{"source":"OpenMedia","stance":"mixed","quote":"OpenMedia urged the SECU committee to close loopholes that weaken cybersecurity and to prevent secret ministerial orders that could compromise encryption.","url":"https://openmedia.org/article/item/openmedia-urges-secu-to-close-loopholes-that-weaken-cybersecurity-in-bill-c-8"},{"source":"Government of Canada","stance":"support","quote":"The Act strengthens Canada's ability to protect essential services and bolsters cyber security across the telecommunications, finance, energy and transportation sectors.","url":"https://www.newswire.ca/news-releases/government-of-canada-strengthens-cyber-security-and-critical-infrastructure-with-royal-assent-of-bill-c-8-874016254.html"}]},"c-9":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-9","factCheck":"Verified: Bill C-9 (Combatting Hate Act), sponsored by Justice Minister Sean Fraser, amends the Criminal Code on hate propaganda, hate crime and access to religious/cultural places. As of June 16, 2026 it is at the stage of the House considering Senate amendments (the Senate passed it with a hate-symbols amendment); it has NOT yet received Royal Assent, so reports that it is 'already law' are premature. Its removal of the good-faith religious-expression defence is the most contested element.","sources":[{"title":"C-9 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-9","type":"official"},{"title":"Bill C-9 has passed. Here's what you need to know - Canadian Constitution Foundation","url":"https://theccf.ca/bill-c-9-has-passed-heres-what-you-need-to-know/","type":"advocacy"},{"title":"Civil liberties group lambasts acceleration of Combatting Hate Act review - Canadian Lawyer","url":"https://www.canadianlawyermag.com/news/general/civil-liberties-group-lambasts-acceleration-of-combatting-hate-act-review/393844","type":"news"},{"title":"B'nai Brith Canada, CIJA, FSWC, ACCA, CWAA Issue Joint Statement on Bill C-9 - B'nai Brith Canada","url":"https://www.bnaibrith.ca/bnai-brith-canada-cija-fswc-acca-cwaa-issue-joint-statement-on-bill-c-9/","type":"advocacy"},{"title":"Protecting Fundamental Rights - Our Concerns with Bill C-9 - Canadian Labour Congress","url":"https://canadianlabour.ca/protecting-fundamental-rights-our-concerns-with-bill-c-9/","type":"advocacy"}],"commentary":[{"source":"Coalition of five Jewish organizations (CIJA, B'nai Brith, FSWC, ACCA, CWAA)","stance":"support","quote":"We believe the incitement to violence against Canadians we have witnessed since October 7 by some radical groups and individuals must be addressed - without undermining religious freedoms.","url":"https://www.cija.ca/bill_c_9_joint_statement_by_five_jewish_organizations"},{"source":"Canadian Constitution Foundation","stance":"oppose","quote":"The bill has raised concerns about its impact on civil liberties and religious speech, removing the good-faith religious-expression defence and adding a redundant intimidation offence and a symbols ban.","url":"https://theccf.ca/bill-c-9-has-passed-heres-what-you-need-to-know/"},{"source":"Canadian Civil Liberties Association","stance":"oppose","quote":"More than 40 civil society organizations raised serious concerns that the bill's vague language could criminalize peaceful protest and chill unpopular expression.","url":"https://www.canadianlawyermag.com/news/general/civil-liberties-group-lambasts-acceleration-of-combatting-hate-act-review/393844"}]},"c-14":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-14","factCheck":"Verified: Bill C-14 (Bail and Sentencing Reform Act), sponsored by Justice Minister Sean Fraser, received Royal Assent on June 15, 2026 (Statutes of Canada 2026, c. 11) and most provisions take effect July 15, 2026. It makes over 80 Criminal Code, Youth Criminal Justice Act and National Defence Act changes, expanding reverse-onus bail and toughening sentencing; it is now law (not merely 'proposed').","sources":[{"title":"C-14 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-14","type":"official"},{"title":"Canada's sweeping bail and sentencing reforms become law - Canada.ca","url":"https://www.canada.ca/en/department-justice/news/2026/06/canadas-sweeping-bail-and-sentencing-reforms-become-law.html","type":"official"},{"title":"Bill C-14: Bail and Sentencing Reform Act - Canadian Bar Association submission","url":"https://cba.org/our-impact/submissions/bill-c-14-bail-and-sentencing-reform-act/bill-c-14-bail-and-sentencing-reform-act","type":"legal"},{"title":"CCLA Urges MPs to Adopt Senate Amendments to Bill C-14 on Bail Reform - CCLA","url":"https://ccla.org/criminal-justice/ccla-urges-mps-to-adopt-senate-amendments-to-bill-c-14-on-bail-reform/","type":"advocacy"},{"title":"Canada's police leaders endorse the introduction of Bill C-14 - Canadian Association of Chiefs of Police","url":"https://www.cacp.ca/cgi/page.cgi/_zine.html/news/Canada_s_police_leaders_endorse_the_introduction_of_Bill_C-14_the_Bail_and_Sentencing_Reform_Act_","type":"official"}],"commentary":[{"source":"Canadian Association of Chiefs of Police (and all provincial/territorial premiers)","stance":"support","quote":"Canada's police leaders endorsed Bill C-14 and called for its swift passage; every provincial and territorial premier backed the reforms.","url":"https://www.cacp.ca/cgi/page.cgi/_zine.html/news/Canada_s_police_leaders_endorse_the_introduction_of_Bill_C-14_the_Bail_and_Sentencing_Reform_Act_"},{"source":"Canadian Civil Liberties Association","stance":"oppose","quote":"Expanded reverse-onus provisions raise constitutional and policy concerns; they could detain legally innocent people and worsen the disproportionate imprisonment of Indigenous, Black and other racialized communities.","url":"https://ccla.org/criminal-justice/ccla-urges-mps-to-adopt-senate-amendments-to-bill-c-14-on-bail-reform/"},{"source":"Canadian Bar Association","stance":"mixed","quote":"Reverse-onus provisions and changes to the ladder principle are unlikely to produce the intended deterrent effect, raise Charter-compliance concerns, and without court-resource investment risk worsening delays.","url":"https://cba.org/our-impact/submissions/bill-c-14-bail-and-sentencing-reform-act/bill-c-14-bail-and-sentencing-reform-act"}]},"c-34":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-34","factCheck":"Verified: Bill C-34 (Safe Social Media Act), introduced June 10, 2026, is only at second reading in the House of Commons; it is NOT yet law. It would enact the Digital Safety Act and Digital Safety Commission of Canada Act, including a proposed under-16 social-media restriction, mandatory age verification, AI-chatbot rules and platform duties - so reports that an under-16 ban is already 'here' or in force are inaccurate.","sources":[{"title":"C-34 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-34","type":"official"},{"title":"Bill C-34, the Safe Social Media Act - Canada.ca","url":"https://www.canada.ca/en/canadian-heritage/services/safe-social-media-act.html","type":"official"},{"title":"Bill C-34 at a glance: Canada's new Digital Safety Act - Osler","url":"https://www.osler.com/en/insights/updates/bill-c-34-at-a-glance-canadas-new-digital-safety-act/","type":"legal"},{"title":"CCLA warns against risks to freedom of expression and privacy posed by Bill C-34","url":"https://ccla.org/press-release/ccla-warns-against-risks-to-freedom-of-expression-and-privacy-posed-by-bill-c-34-the-safe-social-media-act/","type":"advocacy"},{"title":"Everything All At Once: Bill C-34 Combines Platform Duties, a Kids' Social Media Ban, AI Chatbot Regulation... - Michael Geist","url":"https://www.michaelgeist.ca/2026/06/everything-all-at-once-bill-c-34-combines-platform-duties-a-kids-social-media-ban-ai-chatbot-regulation-and-a-powerful-digital-safety-commission-into-a-risky-trust-us-bet/","type":"academic"}],"commentary":[{"source":"Canadian Civil Liberties Association","stance":"oppose","quote":"The bill raises significant civil-liberties concerns, including risks to freedom of expression and privacy through mandatory age verification and the limitless powers it grants the government and a new digital-safety regulator.","url":"https://ccla.org/press-release/ccla-warns-against-risks-to-freedom-of-expression-and-privacy-posed-by-bill-c-34-the-safe-social-media-act/"},{"source":"Michael Geist (University of Ottawa)","stance":"oppose","quote":"Bundling platform duties, a kids' social-media ban, AI-chatbot regulation and a powerful Digital Safety Commission into one bill amounts to a risky 'trust us' bet with too much discretionary power.","url":"https://www.michaelgeist.ca/2026/06/everything-all-at-once-bill-c-34-combines-platform-duties-a-kids-social-media-ban-ai-chatbot-regulation-and-a-powerful-digital-safety-commission-into-a-risky-trust-us-bet/"},{"source":"Government of Canada (Canadian Heritage)","stance":"support","quote":"The legislation will make social media services and AI chatbots safer for children and create a Digital Safety Commission to enforce the rules and support victims of online harms.","url":"https://www.canada.ca/en/canadian-heritage/news/2026/06/government-of-canada-introduces-legislation-to-make-social-media-services-and-ai-chatbots-safer-for-children.html"}]},"c-36":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-36","factCheck":"Verified: Bill C-36 (Protecting Privacy and Consumer Data Act), tabled June 15, 2026 by the Minister of Artificial Intelligence and Digital Innovation, is at second reading and is NOT yet law. It enacts a new private-sector privacy statute, repeals the privacy provisions of PIPEDA (renaming it the Electronic Documents Act), recognizes privacy as a fundamental right, and shifts private-sector enforcement away from the Privacy Commissioner to a new data-protection commission - the most debated structural change.","sources":[{"title":"C-36 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-36","type":"official"},{"title":"Statement by the Privacy Commissioner of Canada on Bill C-36","url":"https://www.priv.gc.ca/en/opc-news/speeches-and-statements/2026/s-d_260615/","type":"official"},{"title":"Ottawa tables long-awaited privacy reform legislation - Gowling WLG","url":"https://gowlingwlg.com/en-ca/insights-resources/articles/2026/ottawa-tables-long-awaited-federal-privacy-reform-legislation","type":"legal"},{"title":"Canada's Digital Super-Regulator: Bill C-36 Pushes Out the Privacy Commissioner - Michael Geist","url":"https://www.michaelgeist.ca/2026/06/canadas-digital-super-regulator-bill-c-36-pushes-out-the-privacy-commissioner-and-hands-private-sector-privacy-to-an-overloaded-commission/","type":"academic"},{"title":"With update to Canada's privacy laws, feds are building a 'super-regulator' - BetaKit","url":"https://betakit.com/with-update-to-canadas-privacy-laws-feds-are-building-a-super-regulator/","type":"news"}],"commentary":[{"source":"Philippe Dufresne, Privacy Commissioner of Canada","stance":"support","quote":"The bill would significantly enhance Canadians' privacy when navigating the digital world and protect children's privacy.","url":"https://www.priv.gc.ca/en/opc-news/speeches-and-statements/2026/s-d_260615/"},{"source":"Michael Geist (University of Ottawa)","stance":"oppose","quote":"There is no precedent in Canada for this kind of digital super-regulator; the bill marks the end of the globally respected Privacy Commissioner on private-sector privacy and hands the role to an overloaded content-focused commission.","url":"https://www.michaelgeist.ca/2026/06/canadas-digital-super-regulator-bill-c-36-pushes-out-the-privacy-commissioner-and-hands-private-sector-privacy-to-an-overloaded-commission/"},{"source":"Minister Evan Solomon (AI and Digital Innovation)","stance":"support","quote":"The moment is here for reform, positioning privacy protection as foundational to responsible AI innovation and public trust under the 'AI for All' strategy.","url":"https://www.canada.ca/en/innovation-science-economic-development/news/2026/06/government-of-canada-introduces-legislation-to-protect-canadians-privacy-in-the-digital-age.html"}]},"c-25":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-25","factCheck":"Verified: Bill C-25 (Strong and Free Elections Act), sponsored by Government House Leader Steven MacKinnon, amends the Canada Elections Act and renames certain electoral districts; as of June 16, 2026 it has passed the House and is at committee study in the Senate (not yet law). It responds to the Foreign Interference inquiry, banning foreign/anonymous and crypto/prepaid-card donations, adding party privacy obligations, and criminalizing election deepfakes and false voting-process information.","sources":[{"title":"C-25 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-25","type":"official"},{"title":"Government of Canada introduces measures to further protect Canada's electoral processes - Canada.ca","url":"https://www.canada.ca/en/democratic-institutions/news/2026/03/government-of-canada-introduces-measures-to-further-protect-canadas-electoral-processes-and-strengthen-democracy.html","type":"official"},{"title":"Bill C-25: Strong and Free Elections Act - Canadian Bar Association submission","url":"https://www.cba.org/our-impact/submissions/bill-c-25-strong-and-free-elections-act/","type":"legal"},{"title":"Charter Statement - Bill C-25 (Department of Justice)","url":"https://www.justice.gc.ca/eng/csj-sjc/pl/charter-charte/c25_2.html","type":"official"}],"commentary":[{"source":"Canadian Bar Association (Privacy and Access Law Section)","stance":"mixed","quote":"We support strengthening electoral integrity and welcome the privacy-related amendments, but they do not resolve structural deficiencies: the regime still fails to treat political-opinion data as sensitive, lacks independent oversight, and denies Canadians access and correction rights.","url":"https://www.cba.org/our-impact/submissions/bill-c-25-strong-and-free-elections-act/"},{"source":"Government of Canada (Democratic Institutions)","stance":"support","quote":"The bill introduces measures to further protect Canada's electoral processes and strengthen democracy, implementing recommendations from the foreign-interference inquiry and the Chief Electoral Officer.","url":"https://www.canada.ca/en/democratic-institutions/news/2026/03/government-of-canada-introduces-measures-to-further-protect-canadas-electoral-processes-and-strengthen-democracy.html"}]},"c-29":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-29","factCheck":"Verified: Bill C-29 (Financial Crimes Agency Act), sponsored by Finance Minister Francois-Philippe Champagne, was introduced and given first reading on April 27, 2026 and is at second reading in the House - an early stage, not yet law. It would create a new standalone federal law-enforcement body to investigate complex financial crimes (money laundering, sanctions evasion, fraud), described as the first new federal police agency since the RCMP.","sources":[{"title":"C-29 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-29","type":"official"},{"title":"Canada's proposed Financial Crimes Agency: A new era of financial crime enforcement - BLG","url":"https://www.blg.com/en/insights/2026/05/canadas-proposed-financial-crimes-agency-a-new-era-of-financial-crime-enforcement","type":"legal"},{"title":"Legislative framework introduced to establish the Financial Crimes Agency - Norton Rose Fulbright","url":"https://www.nortonrosefulbright.com/en-ca/knowledge/publications/e09bd647/legislative-framework-introduced-to-establish-the-financial-crimes-agency","type":"legal"},{"title":"Canada takes aim at financial crime: an overview of Bill C-29 - Osler","url":"https://www.osler.com/en/insights/blogs/risk/canada-takes-aim-financial-crime-bill-c-29-financial-crimes-agency/","type":"legal"}],"commentary":[{"source":"Borden Ladner Gervais (BLG, law firm analysis)","stance":"mixed","quote":"The Financial Crimes Agency would usher in a new era of financial-crime enforcement with broad investigative powers, though its design and coordination with existing bodies will determine its effectiveness.","url":"https://www.blg.com/en/insights/2026/05/canadas-proposed-financial-crimes-agency-a-new-era-of-financial-crime-enforcement"},{"source":"Norton Rose Fulbright (law firm analysis)","stance":"mixed","quote":"The bill responds to longstanding criticism of Canada's fragmented approach to complex financial crime; if passed it would be the first new federal police agency since the RCMP.","url":"https://www.nortonrosefulbright.com/en-ca/knowledge/publications/e09bd647/legislative-framework-introduced-to-establish-the-financial-crimes-agency"}]},"c-5":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-5","factCheck":"Verified: Bill C-5 (One Canadian Economy Act), sponsored by Dominic LeBlanc, received Royal Assent on June 26, 2025 (Statutes of Canada 2025, c. 2). It enacts the Free Trade and Labour Mobility in Canada Act and the Building Canada Act, the latter letting Cabinet designate 'national interest' projects for an accelerated review and even exempt them from certain federal laws. Common misinformation frames it as automatically approving specific pipelines; it sets up a designation/fast-track process rather than pre-approving named projects.","sources":[{"title":"C-5 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-5","type":"official"},{"title":"Liberals' major projects bill passes House of Commons with Conservative support - CBC News","url":"https://www.cbc.ca/news/politics/bill-c-5-passes-1.7566780","type":"news"},{"title":"Bill C-5 becomes law, setting a dangerous precedent - Ecojustice","url":"https://ecojustice.ca/news/environmental-and-civil-society-groups-react-bill-c-5-becomes-law-setting-a-dangerous-precedent/","type":"advocacy"},{"title":"First Nations urge Governor General to delay - or even reject - Bill C-5 - CBC News","url":"https://www.cbc.ca/news/politics/first-nations-urge-governor-general-intervention-bill-c5-1.7564839","type":"news"},{"title":"First Nations Leadership United in Opposition to Bill C-5 - Chiefs of Ontario","url":"https://chiefs-of-ontario.org/first-nations-leadership-united-in-opposition-to-liberal-governments-unprecedented-bill-c-5/","type":"advocacy"}],"commentary":[{"source":"Ecojustice","stance":"oppose","quote":"Bill C-5 gives the government extraordinary powers once a project is designated in the 'national interest,' including the ability to fully exempt it from any federal law - a threat to democracy and the environment.","url":"https://ecojustice.ca/news/ecojustice-slams-bill-c-5-as-a-threat-to-democracy-and-the-environment/"},{"source":"Chiefs of Ontario / Assembly of First Nations leaders","stance":"oppose","quote":"First Nations were not properly consulted before the bill was tabled; it was rammed through Parliament and could override existing laws and Indigenous rights, prompting calls for the Governor General to intervene.","url":"https://www.cbc.ca/news/politics/first-nations-urge-governor-general-intervention-bill-c5-1.7564839"},{"source":"Government of Canada (Carney government) and Conservative Party","stance":"support","quote":"The legislation is needed to build one Canadian economy and get major projects built faster to strengthen Canada's autonomy and resilience amid US trade pressure; it passed the House with Conservative support.","url":"https://www.cbc.ca/news/politics/bill-c-5-passes-1.7566780"}]},"c-4":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-4","factCheck":"Verified: Bill C-4 (Making Life More Affordable for Canadians Act), sponsored by Finance Minister Francois-Philippe Champagne, received Royal Assent on March 12, 2026 (Statutes of Canada 2026, c. 2). It cuts the lowest federal personal income-tax rate, provides GST relief for first-time buyers on new homes up to $1.5 million, and removes the consumer carbon price from federal law. No notable misinformation found.","sources":[{"title":"C-4 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-4","type":"official"},{"title":"Government Bill (House of Commons) C-4 (45-1) - Royal Assent - Parliament of Canada","url":"https://www.parl.ca/DocumentViewer/en/45-1/bill/C-4/royal-assent","type":"official"}],"commentary":[{"source":"Government of Canada (Department of Finance)","stance":"support","quote":"The Act delivers a middle-class tax cut, GST relief for first-time home buyers, and removes the consumer carbon price to make life more affordable for Canadians.","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-4"}]},"c-3":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-3","factCheck":"Verified: Bill C-3 (An Act to amend the Citizenship Act, 2025), sponsored by Immigration Minister Lena Metlege Diab, received Royal Assent on November 20, 2025 (Statutes of Canada 2025, c. 5); IRCC began applying the amended Act from December 15, 2025. It ends the first-generation limit on citizenship by descent - restoring status to many 'Lost Canadians' - and lets citizens born abroad pass on citizenship if they show a 'substantial connection' (1,095 days physical presence). The royal-assent date is sometimes reported as Nov. 21; the official record shows Nov. 20, 2025.","sources":[{"title":"C-3 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-3","type":"official"},{"title":"Government Bill (House of Commons) C-3 (45-1) - Royal Assent - Parliament of Canada","url":"https://www.parl.ca/DocumentViewer/en/45-1/bill/C-3/royal-assent","type":"official"},{"title":"SOCI - Bill C-3, An Act to Amend The Citizenship Act - Canada.ca","url":"https://www.canada.ca/en/immigration-refugees-citizenship/corporate/transparency/committees/soci-nov-17-2025/bill-c-3-act-amend-citizenship-act.html","type":"official"},{"title":"Royal Assent for Bill C-3 ends 'Lost Canadian' era and rewrites rules on citizenship by descent","url":"https://www.visahq.com/news/2025-11-22/ca/royal-assent-for-bill-c-3-ends-lost-canadian-era-and-rewrites-rules-on-citizenship-by-descent/","type":"news"}],"commentary":[{"source":"Government of Canada (IRCC)","stance":"support","quote":"The amendments restore citizenship to 'Lost Canadians' affected by the first-generation limit and modernize citizenship-by-descent rules for families born or adopted abroad.","url":"https://www.canada.ca/en/immigration-refugees-citizenship/corporate/transparency/committees/soci-nov-17-2025/bill-c-3-act-amend-citizenship-act.html"},{"source":"Immigration legal analysts (Harvey Law Group)","stance":"support","quote":"Bill C-3 ends the long-criticized first-generation limit and offers a clear path for Lost Canadians to reclaim citizenship, reflecting the realities of global families.","url":"https://harveylawcorporation.com/lost-canadians-citizenship/"}]},"c-19":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-19","factCheck":"Verified: Bill C-19 (Canada Groceries and Essentials Benefit Act, amending the Income Tax Act), sponsored by Finance Minister Francois-Philippe Champagne, received Royal Assent on February 12, 2026 (Statutes of Canada 2026, c. 1). It enhances the GST/HST credit - a one-time payment of 50% of the 2025-26 credit plus a 25% annual increase for five years from July 2026 - and rebrands it as the Canada Groceries and Essentials Benefit. No notable misinformation found.","sources":[{"title":"C-19 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-19","type":"official"},{"title":"Canada Groceries and Essentials Benefit (CGEB) - Canada.ca","url":"https://www.canada.ca/en/revenue-agency/services/child-family-benefits/canada-groceries-essentials-benefit.html","type":"official"},{"title":"Canada Groceries and Essentials Benefit - Parliamentary Budget Officer","url":"https://www.pbo-dpb.ca/en/publications/LEG-2526-010-S--canada-groceries-essentials-benefit--allocation-canadienne-epicerie-besoins-essentiels","type":"official"},{"title":"One-time GST top-up lands this week as part of new grocery benefit - Global News","url":"https://globalnews.ca/news/11886729/gst-top-up-payment-canada-groceries-essentials-benefit/","type":"news"}],"commentary":[{"source":"Government of Canada (Department of Finance)","stance":"support","quote":"The benefit provides up to an additional $402 for a single individual, $527 for a couple, and $805 for a couple with two children to help with the cost of groceries and essentials.","url":"https://www.canada.ca/en/department-finance/news/2026/02/legislation-passes-to-deliver-new-canada-groceries-and-essentials-benefit.html"},{"source":"Parliamentary Budget Officer","stance":"mixed","quote":"The PBO estimates the measure will cost approximately $12.4 billion over 2025-26 to 2030-31.","url":"https://www.pbo-dpb.ca/en/publications/LEG-2526-010-S--canada-groceries-essentials-benefit--allocation-canadienne-epicerie-besoins-essentiels"}]},"c-16":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-16","factCheck":"Verified: Bill C-16 (Protecting Victims Act), sponsored by Justice Minister Sean Fraser, has passed the House and is at committee study in the Senate (referred June 15, 2026) - not yet law. It amends the Criminal Code on child protection (restoring some mandatory minimums with a constitutional 'safety valve,' expanding luring/sextortion offences), creates a coercive-control offence for intimate partners, and strengthens the Canadian Victims Bill of Rights.","sources":[{"title":"C-16 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-16","type":"official"},{"title":"Bill C-16: updates to Canada's federal child sexual abuse and exploitation material reporting regime - Osler","url":"https://www.osler.com/en/insights/updates/bill-c-16-federal-child-sexual-abuse-exploitation-material-reporting-regime/","type":"legal"},{"title":"Bill C-16 - Protecting Victims Act - Canadian Bar Association submission","url":"https://cba.org/our-impact/submissions/bill-c-16-protecting-victims-act/bill-c-16-protecting-victims-act","type":"legal"},{"title":"Government Bill (House of Commons) C-16 (45-1) - First Reading - Parliament of Canada","url":"https://www.parl.ca/DocumentViewer/en/45-1/bill/C-16/first-reading","type":"official"}],"commentary":[{"source":"Government of Canada (Department of Justice)","stance":"support","quote":"The bill is designed to protect victims and keep kids safe from predators, strengthening responses to child sexual exploitation and intimate-partner coercive control while reinforcing victims' rights.","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-16"},{"source":"Canadian Bar Association","stance":"mixed","quote":"The CBA supports the Supreme Court's established approach excluding conditional sentences for serious child sexual offences but urges a clear framework preserving judicial discretion in truly exceptional cases.","url":"https://cba.org/our-impact/submissions/bill-c-16-protecting-victims-act/bill-c-16-protecting-victims-act"},{"source":"Osler (law firm analysis)","stance":"mixed","quote":"Bill C-16 significantly updates the federal child sexual abuse and exploitation material reporting regime, expanding obligations and offences while raising implementation questions for service providers.","url":"https://www.osler.com/en/insights/updates/bill-c-16-federal-child-sexual-abuse-exploitation-material-reporting-regime/"}]},"c-20":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-20","factCheck":"Verified: Bill C-20 (Build Canada Homes Act), sponsored by Housing Minister Gregor Robertson, has passed the House and is at committee study in the Senate (referred June 16, 2026) - not yet law. It establishes Build Canada Homes, a federal Crown corporation to finance and build affordable housing (notably on federal land) using low-interest loans, equity and factory-built methods. Critics note it does not explicitly commit to social housing or fully address municipal cost drivers.","sources":[{"title":"C-20 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-20","type":"official"},{"title":"Build Canada Homes - Bill C-20 - Assembly of First Nations","url":"https://afn.ca/build-canada-homes-bill-c-20/","type":"advocacy"},{"title":"Make the right to housing central to Build Canada Homes - Maytree","url":"https://maytree.com/publications/make-the-right-to-housing-central-to-build-canada-homes/","type":"advocacy"},{"title":"Build Canada Homes Submission, April 2026 - Social Housing and Human Rights Coalition","url":"https://www.moresocialhousing.ca/bchsubmission/","type":"advocacy"}],"commentary":[{"source":"Social Housing and Human Rights Coalition","stance":"mixed","quote":"Bill C-20 risks continuing a failed trajectory because it does not commit to social housing; it should be amended to include accessible social housing as an essential component of national housing policy.","url":"https://www.moresocialhousing.ca/bchsubmission/"},{"source":"Assembly of First Nations","stance":"mixed","quote":"First Nations agree urgent housing action is needed, but Bill C-20 needs changes to ensure a powerful new federal Crown corporation does not deepen the crisis for First Nations.","url":"https://afn.ca/build-canada-homes-bill-c-20/"},{"source":"Maytree","stance":"mixed","quote":"The right to housing should be made central to Build Canada Homes so the new corporation prioritizes those in greatest need.","url":"https://maytree.com/publications/make-the-right-to-housing-central-to-build-canada-homes/"}]},"c-37":{"officialUrl":"https://www.parl.ca/legisinfo/en/bill/45-1/c-37","factCheck":"Verified: Bill C-37 (First Nations Clean Water Act), sponsored by the Minister of Indigenous Services (Mandy Gull-Masty), was introduced June 16, 2026 and is at second reading - an early stage, not yet law. It is a reintroduction (after the prior Parliament's bill died) creating a legislative framework for safe drinking water and wastewater on First Nation lands, paired with a $4.6 billion funding commitment; a notable change reworded the section 3 rights clause to 'progressive realization' of the human right to safe drinking water, which some First Nations leaders criticize.","sources":[{"title":"C-37 (45-1) - LEGISinfo - Parliament of Canada","url":"https://www.parl.ca/legisinfo/en/bill/45-1/c-37","type":"official"},{"title":"Minister Gull-Masty introduces legislation to support access to clean drinking water in First Nations communities - Canada.ca","url":"https://www.canada.ca/en/indigenous-services-canada/news/2026/06/minister-gull-masty-introduces-legislation-to-support-access-to-clean-drinking-water-in-first-nations-communities-and-announces-historic-funding-co.html","type":"official"},{"title":"Feds reintroduce First Nations water bill after long delay with changes to rights clause - APTN News","url":"https://www.aptnnews.ca/national-news/feds-reintroduces-first-nations-water-bill-after-long-delay-with-changes-to-rights-clause/","type":"news"},{"title":"First Nations leaders frustrated as Ottawa rewrites clean water bill - APTN News","url":"https://www.aptnnews.ca/national-news/clean-water-bill-leaves-first-nations-leaders-frustrated-but-not-ready-to-walk-away/","type":"news"}],"commentary":[{"source":"First Nations leaders (via APTN News)","stance":"mixed","quote":"Leaders are frustrated that the rights clause was rewritten from 'upholding the rights of First Nations peoples' to a weaker 'progressive realization' standard, and they cite a lack of adequate, predictable funding - but are not ready to walk away.","url":"https://www.aptnnews.ca/national-news/clean-water-bill-leaves-first-nations-leaders-frustrated-but-not-ready-to-walk-away/"},{"source":"Indigenous Services Canada (Minister Mandy Gull-Masty)","stance":"support","quote":"The Act would, for the first time, establish a legislative framework for safe drinking water and recognize First Nations jurisdiction over water on their lands, backed by the largest-ever $4.6 billion water and wastewater infrastructure investment.","url":"https://www.canada.ca/en/indigenous-services-canada/news/2026/06/minister-gull-masty-introduces-legislation-to-support-access-to-clean-drinking-water-in-first-nations-communities-and-announces-historic-funding-co.html"}]},"ns-bill-150":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-150","factCheck":"Verified: Bill 150 (a complete rewrite of the Freedom of Information and Protection of Privacy Act) received Royal Assent Oct. 3, 2025 (2025 c.13) and comes into force April 1, 2027; it makes the Information and Privacy Commissioner an independent officer of the House of Assembly and modernizes privacy/breach rules. Correcting a common misconception: despite the overhaul, the Commissioner still issues only recommendations, NOT binding orders, so the law did not deliver the order-making power Premier Houston promised in opposition; it also adds a new power to refuse 'trivial, frivolous or vexatious' requests.","sources":[{"title":"Bill 150 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-150","type":"official"},{"title":"Bill 150 text as introduced (Nova Scotia Legislature)","url":"https://nslegislature.ca/legc/bills/65th_1st/1st_read/b150.htm","type":"official"},{"title":"Access-to-information overhaul increases commissioner's independence, but not power (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/freedom-of-information-protection-of-privacy-tim-houston-1.7645179","type":"news"},{"title":"N.S. wants to deny 'vexatious' information requests; critics concerned (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/nova-scotia-freedom-information-privacy-commissioner-legislation-vexatious-1.7466187","type":"news"},{"title":"Nova Scotia's new Freedom of Information and Protection of Privacy Act (David Fraser, Canadian Privacy Law Blog)","url":"https://blog.privacylawyer.ca/2025/11/nova-scotias-new-freedom-of-information.html","type":"legal"},{"title":"Office of the Information and Privacy Commissioner for Nova Scotia","url":"https://oipc.novascotia.ca/","type":"official"}],"commentary":[{"source":"David Fraser, privacy lawyer (Canadian Privacy Law Blog)","stance":"mixed","quote":"Calls the new framework 'significant' with welcome improvements (a more independent Commissioner, municipalities covered, electronic re-usable records) but says 'a big miss... is that the Commissioner does not have the ability to issue binding orders on public bodies,' and calls removing the original transparency/accountability purpose clause 'a real step backward.'","url":"https://blog.privacylawyer.ca/2025/11/nova-scotias-new-freedom-of-information.html"},{"source":"Centre for Law and Democracy (Toby Mendel, Executive Director)","stance":"oppose","quote":"On the government's access-to-information changes: 'It is extremely disappointing that a government which originally came into office promising positive reforms to the local access law is in fact seeking to obstruct access.'","url":"https://www.law-democracy.org/nova-scotia-amendments-would-undermine-access-to-information-act/"},{"source":"CBC News (reporting access experts)","stance":"mixed","quote":"Reports the reform makes the former 'review officer' a more independent Information and Privacy Commissioner and updates 'personal information' (IP addresses, biometric, genetic data), but critics warn the new power to reject 'trivial, frivolous or vexatious' requests could be misused to deny access.","url":"https://www.cbc.ca/news/canada/nova-scotia/nova-scotia-freedom-information-privacy-commissioner-legislation-vexatious-1.7466187"}]},"ns-bill-1":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-1","factCheck":"Verified: Bill 1, the omnibus Government Organization and Administration Act, received Royal Assent March 26, 2025 (2025 c.8); it repealed Nova Scotia's fixed-election-date law, raised the base MLA salary (to roughly $115,000, opt-out allowed), changed the Auditor General Act (a minimum delay before public release of reports and a process for dismissal), and tightened access-to-information rules. Correcting two common conflations: the $50,000 Crown-lands/forest-road anti-protest provisions are in Bill 127 (fall 2025), NOT Bill 1; and the 2026 electoral-modernization changes are Bill 205, NOT Bill 1.","sources":[{"title":"Bill 1 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-1","type":"official"},{"title":"Bill 1 text as introduced (Nova Scotia Legislature)","url":"https://nslegislature.ca/legc/bills/65th_1st/1st_read/b001.htm","type":"official"},{"title":"Nova Scotia: Amendments Would Undermine Access to Information Act (Centre for Law and Democracy)","url":"https://www.law-democracy.org/nova-scotia-amendments-would-undermine-access-to-information-act/","type":"advocacy"},{"title":"OIPC letter to Law Amendments Committee re Bill 1 (Information and Privacy Commissioner for N.S.)","url":"https://oipc.novascotia.ca/sites/default/files/2025%2002%2025%20Letter%20to%20LAC%20-%20Bill%201.pdf","type":"official"},{"title":"Nova Scotia bill would repeal fixed election date, increase politicians' pay (The Canadian Press)","url":"https://www.thecanadianpressnews.ca/atlantic/nova-scotia-bill-would-repeal-fixed-election-date-increase-politicians-pay/article_f257e244-4d73-5fa6-a88e-f0de4136b1a6.html","type":"news"},{"title":"Winter session at N.S. Legislature nears close as bills clear third reading (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/legislation-trade-auditor-general-access-to-information-1.7492370","type":"news"}],"commentary":[{"source":"Centre for Law and Democracy (Toby Mendel, Executive Director)","stance":"oppose","quote":"Says the access provisions in Bill 1 would let officials reject requests via broad 'specificity' and discretionary-disregard powers and let the AG conclusively claim solicitor-client privilege: 'It is extremely disappointing that a government which originally came into office promising positive reforms to the local access law is in fact seeking to obstruct access.'","url":"https://www.law-democracy.org/nova-scotia-amendments-would-undermine-access-to-information-act/"},{"source":"Information and Privacy Commissioner for Nova Scotia","stance":"oppose","quote":"Raised formal concerns to the Law Amendments Committee that the bill's access-to-information amendments would weaken the right of access and the oversight regime.","url":"https://oipc.novascotia.ca/sites/default/files/2025%2002%2025%20Letter%20to%20LAC%20-%20Bill%201.pdf"},{"source":"The Canadian Press","stance":"mixed","quote":"Reports the omnibus repeals the fixed-election-date law (previously third Tuesday in July every four years) and raises the MLA base salary to about $115,000 from $89,234, while also delaying public release of Auditor General reports and allowing the AG's dismissal by two-thirds of the House.","url":"https://www.thecanadianpressnews.ca/atlantic/nova-scotia-bill-would-repeal-fixed-election-date-increase-politicians-pay/article_f257e244-4d73-5fa6-a88e-f0de4136b1a6.html"}]},"ns-bill-6":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-6","factCheck":"Verified: Bill 6, An Act Respecting Agriculture, Energy and Natural Resources, received Royal Assent March 26, 2025 (2025 c.4); it repealed the Uranium Exploration and Mining Prohibition Act and amended the Petroleum Resources Act to enable (with authorization) onshore drilling and hydraulic fracturing, effectively ending the long-standing uranium ban and the 2014 fracking moratorium, and also created agrologist regulation and a noxious-weed framework. Correcting misinformation: the fracking provisions concern ONSHORE petroleum (not offshore), and the bill does not 'ban' fracking — it requires ministerial/regulatory authorization for it; Mi'kmaw chiefs say they were not consulted.","sources":[{"title":"Bill 6 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-6","type":"official"},{"title":"Bill 6 text as introduced (Nova Scotia Legislature)","url":"https://nslegislature.ca/legc/bills/65th_1st/1st_read/b006.htm","type":"official"},{"title":"Nova Scotia government bill would lift ban on fracking, uranium exploration (CBC News)","url":"https://www.cbc.ca/lite/story/1.7462119","type":"news"},{"title":"N.S. Mi'kmaw chiefs say they should have been consulted on natural resources legislation (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/mi-kmaw-chiefs-natural-resources-fracking-uranium-1.7474738","type":"news"},{"title":"Health and climate risks rise as Nova Scotia pushes to overturn bans on fracking and uranium mining (Canada's National Observer)","url":"https://www.nationalobserver.com/2025/02/20/news/health-climate-nova-scotia-fracking-uranium-mining","type":"news"},{"title":"Nova Scotia lifts uranium ban, issues request for proposals (World Nuclear News)","url":"https://www.world-nuclear-news.org/articles/nova-scotia-lifts-uranium-ban-issues-request-for-proposals","type":"news"}],"commentary":[{"source":"Assembly of Nova Scotia Mi'kmaw Chiefs","stance":"oppose","quote":"Wrote to Premier Houston criticizing the government for tabling legislation enabling onshore fracking and repealing the uranium ban 'without advance notice to, or discussion with, the Mi'kmaq,' calling it an infringement on their rights.","url":"https://www.cbc.ca/news/canada/nova-scotia/mi-kmaw-chiefs-natural-resources-fracking-uranium-1.7474738"},{"source":"Canada's National Observer","stance":"oppose","quote":"Reports physicians and environmental advocates warning that lifting the bans on fracking and uranium mining raises health and climate risks, reviving concerns that prompted the original 2009 uranium moratorium and 2014 fracking moratorium.","url":"https://www.nationalobserver.com/2025/02/20/news/health-climate-nova-scotia-fracking-uranium-mining"},{"source":"Government of Nova Scotia (Premier Tim Houston / Minister Tory Rushton)","stance":"support","quote":"Framed the bill as pursuing resource development and economic opportunity, repealing 'outdated' prohibitions so the province can responsibly explore critical minerals and energy, including uranium, subject to regulatory approval.","url":"https://news.novascotia.ca/en/2025/02/18/province-pursues-resource-development-legislation"}]},"ns-bill-130":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-130","factCheck":"Verified: Bill 130, the Traffic Safety Act, received Royal Assent Oct. 3, 2025 (2025 c.20) and will replace the century-old Motor Vehicle Act when proclaimed (the government targeted 2026); for the first time it authorizes automated enforcement (photo radar, red-light and intersection cameras) and lets municipalities set lower speed limits and regulate bikes/scooters. Correcting a common misconception: passage does not by itself put cameras on the road — the enabling provisions require regulations/proclamation before any automated enforcement begins; it is a fresh Act after the 2018 Traffic Safety Act proved too difficult to proclaim.","sources":[{"title":"Bill 130 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-130","type":"official"},{"title":"Traffic Safety Act, SNS 2025, c 20 (CanLII)","url":"https://www.canlii.org/en/ns/laws/astat/sns-2025-c-20/latest/sns-2025-c-20.html","type":"legal"},{"title":"N.S. government abandons 2018 bill, tables fresh Traffic Safety Act (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/new-traffic-safety-act-tabled-province-house-1.7641191","type":"news"},{"title":"Nova Scotia says long-awaited traffic safety changes to come next year (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/nova-scotia-consulting-municipalities-on-long-awaited-traffic-safety-changes-1.7505989","type":"news"},{"title":"Traffic Safety Act: legislative changes (Government of Nova Scotia)","url":"https://novascotia.ca/traffic-safety-act-legislative-changes/","type":"official"}],"commentary":[{"source":"Hon. Fred Tilley, Minister of Public Works (Government of Nova Scotia)","stance":"support","quote":"Said the 2018 Traffic Safety Act 'proved to be too difficult to proclaim,' so the department started anew with a modernized Act giving government flexibility to respond to evolving transportation needs and enable automated enforcement.","url":"https://www.cbc.ca/news/canada/nova-scotia/new-traffic-safety-act-tabled-province-house-1.7641191"},{"source":"CBC News","stance":"mixed","quote":"Reports the Act enables photo radar, red-light and intersection cameras and opens the door to sharing licence-plate data with private companies (e.g. for paid-parking enforcement), while giving municipalities power to set speed limits under 80 km/h and regulate bikes and scooters.","url":"https://www.cbc.ca/news/canada/nova-scotia/new-traffic-safety-act-tabled-province-house-1.7641191"},{"source":"Government of Nova Scotia (consultation record)","stance":"support","quote":"Notes the modernization follows extensive consultation (about 1,800 pieces of feedback on the earlier draft regulations 2021-2022) and is intended to improve road safety for all users.","url":"https://novascotia.ca/traffic-safety-act-legislative-changes/"}]},"ns-bill-205":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-205","factCheck":"Verified: Bill 205, amending the Elections Act and the House of Assembly Act, received Royal Assent April 9, 2026 (2026 c.9); most changes implement modernization recommendations from Nova Scotia's Chief Electoral Officer following the 2021 and 2024 elections (some sections take effect on the next dissolution of the House). Correcting a common conflation: the repeal of the fixed-election-date law and the MLA pay raise were enacted in 2025 via Bill 1, NOT Bill 205 — Nova Scotia had already abolished fixed election dates before Bill 205 was introduced.","sources":[{"title":"Bill 205 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-205","type":"official"},{"title":"Bill 205 text as introduced (Nova Scotia Legislature)","url":"https://nslegislature.ca/legc/bills/65th_1st/1st_read/b205.htm","type":"official"},{"title":"Amendments Modernize Electoral Process (Government of Nova Scotia news release)","url":"https://news.novascotia.ca/en/2026/02/26/amendments-modernize-electoral-process","type":"official"},{"title":"Elections Act, SNS 2011, c 5 (CanLII)","url":"https://www.canlii.org/t/8pcs","type":"legal"},{"title":"Nova Scotia Poised to Repeal Its Fixed-Date Elections Law (James Bowden, Parliamentum blog)","url":"https://parliamentum.org/2025/02/19/nova-scotia-poised-to-repeal-its-fixed-date-elections-law/","type":"academic"}],"commentary":[{"source":"Government of Nova Scotia (Attorney General / Office of the Attorney General)","stance":"support","quote":"Says the amendments 'modernize the electoral process,' implementing changes recommended by the Chief Electoral Officer after the 2021 and 2024 provincial general elections.","url":"https://news.novascotia.ca/en/2026/02/26/amendments-modernize-electoral-process"},{"source":"James Bowden, parliamentary procedure analyst (Parliamentum)","stance":"mixed","quote":"On Nova Scotia's earlier 2025 move to repeal fixed election dates, argues fixed-date laws in Westminster systems are largely symbolic given the Crown's prerogative to dissolve, providing context for understanding the province's electoral-law changes.","url":"https://parliamentum.org/2025/02/19/nova-scotia-poised-to-repeal-its-fixed-date-elections-law/"}]},"ns-bill-127":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-127","factCheck":"Verified: Bill 127, the omnibus Protecting Nova Scotians Act, received Royal Assent Oct. 3, 2025 (2025 c.19); it amends seven statutes plus creates one new Act, and notably amends the Crown Lands Act to make it an offence (fines up to $50,000 and/or up to six months in jail) to block or impede forest-access roads or build obstructing structures, while also restricting collection of Social Insurance Numbers and letting gender-based-violence survivors keep their lease terms. Correcting misinformation: critics call the Crown-lands measures an attack on Mi'kmaw land protectors; the government says they target unlawful road blockades, not lawful protest — but the constitutional consultation concerns are real and contested.","sources":[{"title":"Bill 127 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-127","type":"official"},{"title":"Bill 127 third-reading text (Nova Scotia Legislature)","url":"https://nslegislature.ca/legc/bills/65th_1st/3rd_read/b127.htm","type":"official"},{"title":"Crown lands bill would criminalize peaceful protests, critics say (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/crown-lands-bill-would-criminalize-peaceful-protests-critics-say-1.7646661","type":"news"},{"title":"Statement from Sipekne'katik First Nation on Bill 127 (Sipekne'katik First Nation)","url":"https://www.sipeknekatik.ca/community-notices/statement-from-sipeknekatik-first-nation-on-nova-scotia-omnibus-legislation-bill-127-protecting-nova-scotia-act","type":"advocacy"},{"title":"The 'Protecting Nova Scotians Act' does no such thing (Dalhousie Gazette, opinion)","url":"https://dalgazette.com/opinions/the-protecting-nova-scotians-act-does-no-such-thing/","type":"news"},{"title":"Legislation to Protect Nova Scotians (Government of Nova Scotia news release)","url":"https://news.novascotia.ca/en/2025/09/23/legislation-protect-nova-scotians","type":"official"}],"commentary":[{"source":"Sipekne'katik First Nation","stance":"oppose","quote":"'The lands referred to as \"Crown lands\" are, in fact, unceded Mi'kmaq territory within Mi'kma'ki, a sovereign nation,' arguing the Province failed its duty to consult and is criminalizing land protectors in violation of treaty rights.","url":"https://www.sipeknekatik.ca/community-notices/statement-from-sipeknekatik-first-nation-on-nova-scotia-omnibus-legislation-bill-127-protecting-nova-scotia-act"},{"source":"Dalhousie Gazette (opinion)","stance":"oppose","quote":"Argues the 'Protecting Nova Scotians Act' does the opposite of protect, bundling unrelated changes and using Crown-lands amendments to target Mi'kmaw land defenders with steep fines and jail.","url":"https://dalgazette.com/opinions/the-protecting-nova-scotians-act-does-no-such-thing/"},{"source":"CBC News (reporting opposition MLAs and critics)","stance":"oppose","quote":"Reports critics calling the Crown-lands provisions 'heavy-handed' and an attempt to criminalize peaceful protest, and opposition MLAs decrying the omnibus approach of combining unrelated bills as limiting debate.","url":"https://www.cbc.ca/news/canada/nova-scotia/crown-lands-bill-would-criminalize-peaceful-protests-critics-say-1.7646661"},{"source":"Government of Nova Scotia (Hon. Jill Balser / Service Nova Scotia)","stance":"support","quote":"Frames the bill as protecting Nova Scotians — limiting SIN collection, supporting gender-based-violence survivors' tenancy rights, and keeping forest-access roads open for lawful Crown-land use.","url":"https://news.novascotia.ca/en/2025/09/23/legislation-protect-nova-scotians"}]},"ns-bill-198":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-198","factCheck":"Verified: Bill 198, the Financial Measures (2026) Act implementing the 2026 budget, received Royal Assent April 9, 2026 (2026 c.3) and amends roughly 20 statutes; key measures include new biennial road-use levies on electric ($500) and hybrid ($250) vehicles (from Oct. 1, 2026), raising the financial-institutions capital tax from 4% to 6%, harmonizing the vaping tax with the federal regime, and narrowing preferential forest-property tax rates to active forestry. Correcting a misconception: the budget did NOT change personal or corporate income-tax rates, and the EV charge is a flat registration-style levy, not a per-kilometre road tax.","sources":[{"title":"Bill 198 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-198","type":"official"},{"title":"N.S. government's budget-related bill includes changes to 20 pieces of legislation (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/john-lohr-financial-measures-act-budget-claudia-chender-iain-rankin-9.7105862","type":"news"},{"title":"Electric vehicle users, advocates say new levy feels 'punitive' (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/electric-vehicle-users-advocates-say-new-levy-feels-punitive-9.7103892","type":"news"},{"title":"Nova Scotia Budget 2026 tax summary (Doane Grant Thornton)","url":"https://www.doanegrantthornton.ca/insights/budgets/nova-scotia-budget-2026/","type":"legal"},{"title":"Financial Measures (2026) Act Introduced (Government of Nova Scotia news release)","url":"https://news.novascotia.ca/en/2026/02/25/financial-measures-2026-act-introduced","type":"official"}],"commentary":[{"source":"Claudia Chender, NDP Leader of the Official Opposition","stance":"oppose","quote":"Called the EV/hybrid levy 'absolutely ridiculous,' saying it 'represents the only significant tax in our budget, which is going to be on people who are just trying to do the right thing.'","url":"https://www.claudiachender.ca/media/2026/2/24/ottawa-incentivizes-electric-vehicle-purchases-nova-scotia-makes-them-more-expensive"},{"source":"Electric Vehicle Association of Atlantic Canada","stance":"oppose","quote":"Called the new EV levy 'short-sighted and irresponsible,' warning it will slow the province's clean-transportation progress.","url":"https://www.cbc.ca/news/canada/nova-scotia/electric-vehicle-users-advocates-say-new-levy-feels-punitive-9.7103892"},{"source":"Hon. John Lohr / Premier Tim Houston (Government of Nova Scotia)","stance":"support","quote":"Defends the levy because heavier EVs cause road 'wear and tear,' so their owners 'should pay something towards that,' and frames the FMA as responsible budget implementation.","url":"https://www.cbc.ca/news/canada/nova-scotia/electric-vehicle-users-advocates-say-new-levy-feels-punitive-9.7103892"}]},"ns-bill-193":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-193","factCheck":"Verified: Bill 193, the Powering the Economy Act, received Royal Assent April 9, 2026 (2026 c.5); it creates the Offshore Renewable Energy Revenue Act (a royalty/levy regime for offshore wind, about $7,000/MW of installed turbine capacity for the first 10 years), a new Subsurface Energy Resource Extraction Act (geothermal, natural hydrogen, helium, carbon storage and onshore oil and gas), and accelerates the transfer of grid operations from Nova Scotia Power to the Independent Energy System Operator. Correcting expectations: although the bill lets the Minister require utilities to buy offshore-wind power for local use, the government itself expects most offshore wind energy to be exported.","sources":[{"title":"Bill 193 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-193","type":"official"},{"title":"Province Introduces Legislation to Power the Economy (Government of Nova Scotia news release)","url":"https://news.novascotia.ca/en/2026/02/24/province-introduces-legislation-power-economy","type":"official"},{"title":"From Seabed to Grid: How Bill 193 Is Rewiring Nova Scotia's Energy Future (Cox & Palmer)","url":"https://coxandpalmerlaw.com/publication/from-seabed-to-grid-how-bill-193-is-rewiring-nova-scotias-energy-future/","type":"legal"},{"title":"Bill allows local use of offshore energy, but N.S. expects most will be exported (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/offshore-wind-energy-legislation-1.7644830","type":"news"},{"title":"Legislative Sitting Concludes with Budget, Powering the Economy Act Passed (Government of Nova Scotia)","url":"https://news.novascotia.ca/en/2026/04/09/legislative-sitting-concludes-budget-powering-economy-act-passed","type":"official"}],"commentary":[{"source":"Cox & Palmer (law firm energy analysis)","stance":"mixed","quote":"Describes Bill 193 as 'rewiring Nova Scotia's energy future' by creating the Offshore Renewable Energy Revenue Act and the Subsurface Energy Resource Extraction Act and accelerating the IESO transition, establishing a clearer fiscal and regulatory framework for offshore wind and emerging subsurface resources.","url":"https://coxandpalmerlaw.com/publication/from-seabed-to-grid-how-bill-193-is-rewiring-nova-scotias-energy-future/"},{"source":"Government of Nova Scotia (Premier/Minister of Energy Tim Houston)","stance":"support","quote":"Frames the Act as positioning Nova Scotia to capitalize on offshore wind and subsurface energy, set a royalty regime, and finish moving grid control to the IESO to 'power the economy.'","url":"https://news.novascotia.ca/en/2026/02/24/province-introduces-legislation-power-economy"},{"source":"Claudia Chender, NDP Leader of the Official Opposition","stance":"mixed","quote":"On the broader offshore-wind/grid agenda, argues transmission 'infrastructure barriers' must not limit new wind energy and that the government 'has to be at the front of fixing it,' while criticizing rising Nova Scotia Power rates.","url":"https://www.nsndp.ca/government-action-needed-help-nova-scotians-afford-power-bill-increase-ndp"}]},"ns-bill-11":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-11","factCheck":"Verified: Bill 11, the Administrative Efficiency and Accountability in Healthcare Act, received Royal Assent March 26, 2025 (2025 c.2); it repeals outdated statutes (including the 19th-century Anatomy Act and the Emergency Department Accountability Act) and amends the Health Services and Insurance Act and Human Organ and Tissue Donation Act to cut administrative burden. Correcting the spin in the title: opposition critics note that despite 'Accountability' in the name, the bill eliminates the legally required annual emergency-department accountability report — the government argues equivalent data is now available in real time via online dashboards.","sources":[{"title":"Bill 11 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-11","type":"official"},{"title":"Bill 11 text as introduced (Nova Scotia Legislature)","url":"https://nslegislature.ca/legc/bills/65th_1st/1st_read/b011.htm","type":"official"},{"title":"Legislative Changes to Create Administrative Efficiency, Modernize Healthcare System (Government of Nova Scotia)","url":"https://news.novascotia.ca/en/2025/02/19/legislative-changes-create-administrative-efficiency-modernize-healthcare-system","type":"official"},{"title":"Here's why it's hard to know what's going on in Nova Scotia health care (The Signal, University of King's College)","url":"https://signalhfx.ca/heres-why-its-hard-to-know-whats-going-on-in-nova-scotia-health-care/","type":"news"},{"title":"Winter session at N.S. Legislature nears close as bills clear third reading (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/legislation-trade-auditor-general-access-to-information-1.7492370","type":"news"}],"commentary":[{"source":"Derek Mombourquette, interim Nova Scotia Liberal Leader","stance":"oppose","quote":"'Repealing this Act only makes it easier for the government to control the narrative and harder for Nova Scotians to see the true state of our health-care system,' on the removal of the Emergency Department Accountability Act.","url":"https://signalhfx.ca/heres-why-its-hard-to-know-whats-going-on-in-nova-scotia-health-care/"},{"source":"Hon. Michelle Thompson, Minister of Health and Wellness (Government of Nova Scotia)","stance":"support","quote":"'We have legislation that is outdated, redundant and no longer reflects the realities of our health-care system,' saying repealed reporting is replaced by real-time public dashboards (YourHealthNS, Action for Health).","url":"https://news.novascotia.ca/en/2025/02/19/legislative-changes-create-administrative-efficiency-modernize-healthcare-system"},{"source":"The Signal (University of King's College journalism)","stance":"mixed","quote":"Reports that the repealed annual report included metrics not on the dashboards — year-over-year comparisons, walkout rates, age brackets and public consultations — narrowing the scope of public accountability.","url":"https://signalhfx.ca/heres-why-its-hard-to-know-whats-going-on-in-nova-scotia-health-care/"}]},"ns-bill-249":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-249","factCheck":"Verified: Bill 249 is a Private Member's Bill from Suzy Hansen (NDP, Halifax Needham) that would amend the Intimate Images and Cyber-protection Act to cover 'artificially generated' (AI/deepfake) intimate images; it had First Reading March 26, 2026 and, as a private member's bill, has not advanced further (it is not law). It defines a 'fake intimate image' as a reasonably convincing AI/software-created depiction and would let courts act even when the person is not identifiable. Correcting a likely confusion: this is a provincial civil/cyber-protection measure and is distinct from the federal Criminal Code deepfake bill (Bill C-16); both were spurred by a 2026 Nova Scotia case where a man was acquitted because the existing law did not cover AI-generated images.","sources":[{"title":"Bill 249 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-249","type":"official"},{"title":"Bill 249 text as introduced (Nova Scotia Legislature)","url":"https://nslegislature.ca/legc/bills/65th_1st/1st_read/b249.htm","type":"official"},{"title":"N.S. man acquitted of intimate images charges (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/man-acquitted-of-intimate-images-charges-9.7122591","type":"news"},{"title":"Federal justice minister calls deepfake nudes 'heinous' after N.S. man acquitted (CBC News)","url":"https://www.cbc.ca/news/canada/nova-scotia/sean-fraser-deepfake-nudes-heinous-9.7130804","type":"news"},{"title":"Intimate Images and Cyber-protection Act, SNS 2017, c 7 (Nova Scotia statute)","url":"https://nslegislature.ca/sites/default/files/legc/statutes%20HTML/intimate%20images%20and%20cyber-protection.htm","type":"legal"}],"commentary":[{"source":"Suzy Hansen, MLA (NDP, Halifax Needham), bill sponsor","stance":"support","quote":"Sponsors the bill to close the gap exposed by recent cases, defining a 'fake intimate image' as a reasonably convincing AI/software-generated depiction so victims of deepfakes can seek cyber-protection orders even if they are not identifiable.","url":"https://nslegislature.ca/legc/bills/65th_1st/1st_read/b249.htm"},{"source":"Sean Fraser, federal Minister of Justice (Nova Scotia MP)","stance":"support","quote":"Called non-consensual deepfake nude images 'heinous' after a Nova Scotia man was acquitted because existing law did not capture AI-generated images, underscoring the legal gap these reforms aim to fill.","url":"https://www.cbc.ca/news/canada/nova-scotia/sean-fraser-deepfake-nudes-heinous-9.7130804"},{"source":"CBC News (reporting the N.S. acquittal)","stance":"mixed","quote":"Reports a judge acquitting a man who used AI to create nude images of classmates, noting 'the law does not reflect the technology that exists today,' which prompted calls for legislative change at both provincial and federal levels.","url":"https://www.cbc.ca/news/canada/nova-scotia/man-acquitted-of-intimate-images-charges-9.7122591"}]},"ns-bill-131":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-131","factCheck":"Verified: Bill 131, the Privacy and Credit Protection Act, is a Private Member's Bill from Susan Leblanc (NDP, Dartmouth North); it had First Reading Sept. 23, 2025 and reached Second Reading debate (Oct. 1, 2025) but, as an opposition private member's bill, it has not been passed and is not law. It would require organizations to safeguard and securely destroy personal data and add credit-protection measures. It was tabled amid the major Nova Scotia Power data breach; no notable misinformation found beyond the common error of treating private member's bills as enacted.","sources":[{"title":"Bill 131 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-131","type":"official"},{"title":"Bill 131 text as introduced (Nova Scotia Legislature)","url":"https://nslegislature.ca/legc/bills/65th_1st/1st_read/b131.htm","type":"official"},{"title":"Susan Leblanc - sponsored bills (Nova Scotia Legislature member profile)","url":"https://nslegislature.ca/members/profiles/susan-leblanc/bills","type":"official"},{"title":"N.S. wants to limit access to SIN numbers, prohibit protests on logging roads (Global News)","url":"https://globalnews.ca/news/11446002/nova-scotia-legislature-opens/","type":"news"}],"commentary":[{"source":"Susan Leblanc, MLA (NDP, Dartmouth North), bill sponsor","stance":"support","quote":"Introduces the Privacy and Credit Protection Act to require organizations to protect personal data against breaches and securely destroy it, and to give Nova Scotians stronger credit-protection tools after major data breaches.","url":"https://nslegislature.ca/members/profiles/susan-leblanc/bills"},{"source":"Nova Scotia NDP","stance":"support","quote":"Part of the Official Opposition's privacy push following the Nova Scotia Power cyberattack, arguing residents need legal safeguards and credit protections when their personal data is compromised.","url":"https://nslegislature.ca/members/profiles/susan-leblanc/bills"}]},"ns-bill-140":{"officialUrl":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-140","factCheck":"Verified: Bill 140, the Private Data Protection Act, is a Private Member's Bill from Derek Mombourquette (Liberal, Sydney-Membertou); it had First Reading Sept. 24, 2025 and has not advanced beyond that, so it is not law. It would create a statutory tort — actionable without proof of damage — for willfully violating another person's privacy (e.g., surveillance or data misuse), and was tabled as part of a Liberal package responding to the Nova Scotia Power data breach. No notable misinformation found, other than the common error of assuming a private member's bill at first reading is in force.","sources":[{"title":"Bill 140 official status page (Nova Scotia Legislature)","url":"https://nslegislature.ca/legislative-business/bills-statutes/bills/assembly-65-session-1/bill-140","type":"official"},{"title":"Bill 140 text as introduced (Nova Scotia Legislature)","url":"https://nslegislature.ca/legc/bills/65th_1st/1st_read/b140.htm","type":"official"},{"title":"Liberal bill demands transparency after Nova Scotia Power security failures (The Laker News)","url":"https://thelaker.ca/liberal-bill-demands-transparency-after-nova-scotia-power-security-failures/","type":"news"},{"title":"Information access and privacy legislation and policies: overview (Government of Nova Scotia)","url":"https://www.novascotia.ca/information-access-and-privacy-legislation-and-policies-overview","type":"official"}],"commentary":[{"source":"Derek Mombourquette, MLA (Liberal, Sydney-Membertou), bill sponsor","stance":"support","quote":"Introduces the Private Data Protection Act to give Nova Scotians the ability to sue when their privacy is willfully violated — a tort actionable without proof of damage — as part of a package to hold Nova Scotia Power accountable after one of the province's largest data breaches.","url":"https://thelaker.ca/liberal-bill-demands-transparency-after-nova-scotia-power-security-failures/"},{"source":"The Laker News","stance":"mixed","quote":"Reports the Liberal bill as demanding greater transparency and accountability following Nova Scotia Power's security failures, giving residents better legal tools to protect their information.","url":"https://thelaker.ca/liberal-bill-demands-transparency-after-nova-scotia-power-security-failures/"}]},"on-bill-5":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-5","factCheck":"Verified: Bill 5 received Royal Assent on June 6, 2025 (S.O. 2025, c. 4) and is in force; it enacts the Special Economic Zones Act, 2025 (letting Cabinet exempt designated 'trusted proponents'/projects from provincial laws and municipal by-laws) and the Species Conservation Act, 2025, which replaces the Endangered Species Act, 2007. A common misconception is that the law is unchallengeable or already used to override all rules in the Ring of Fire; in fact no special economic zone had been formally designated as of mid-2026, and the Act faces an active Charter/constitutional challenge by First Nations and environmental groups.","sources":[{"title":"Bill 5, Protect Ontario by Unleashing our Economy Act, 2025 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-5","type":"official"},{"title":"Bill 5, Protect Ontario by Unleashing our Economy Act, 2025: now in force - McCarthy Tetrault","url":"https://www.mccarthy.ca/en/insights/blogs/canadian-era-perspectives/bill-5-protect-ontario-by-unleashing-our-economy-act-2025-now-in-force","type":"legal"},{"title":"Ford government's 'special economic zones' law facing constitutional challenge - CBC News","url":"https://www.cbc.ca/news/canada/toronto/ford-government-bill-5-legal-challenge-9.7156329","type":"news"},{"title":"9 Ontario First Nations ask for injunction against Bill 5, say law represents 'clear and present danger' - CBC News","url":"https://www.cbc.ca/news/canada/toronto/first-nations-legal-challenge-against-ontario-bill-five-1.7585361","type":"news"},{"title":"Bill 5 campaign - Ontario Nature","url":"https://ontarionature.org/campaigns/bill-5/","type":"advocacy"}],"commentary":[{"source":"Nine Ontario First Nations (legal challenge)","stance":"oppose","quote":"The First Nations argue Bill 5 and the federal Bill C-5 are a 'clear and present danger' to their self-determination and Treaty rights, and have sought a Superior Court injunction against the Special Economic Zones Act.","url":"https://www.cbc.ca/news/canada/toronto/first-nations-legal-challenge-against-ontario-bill-five-1.7585361"},{"source":"Wildlands League, Environmental Defence, Friends of the Earth & Democracy Watch","stance":"oppose","quote":"Allege the special economic zone law unconstitutionally delegates powers reserved for the legislature to Cabinet, allowing projects to be exempted from all provincial laws and municipal bylaws with no guardrails.","url":"https://www.theglobeandmail.com/canada/article-constitutional-challenge-ontario-special-economic-zones-act-bill-5/"},{"source":"Government of Ontario (Premier Doug Ford / Ministry)","stance":"support","quote":"Frames the Act as protecting Ontario's economy from tariffs by accelerating critical mineral and energy projects and cutting red tape to speed approvals.","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-5"},{"source":"Norton Rose Fulbright (legal analysis)","stance":"mixed","quote":"Notes the Act materially streamlines infrastructure and mining approvals but creates significant uncertainty for proponents and stakeholders given broad, discretionary Cabinet exemption powers.","url":"https://www.nortonrosefulbright.com/en/knowledge/publications/9bd176cd/bill-5-protect-ontario-by-unleashing-our-economy-act-2025-receives-royal-assent"}]},"on-bill-6":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-6","factCheck":"Verified: Bill 6 received Royal Assent in June 2025 (S.O. 2025, c. 5) and is in force; it enacts the Restricting Public Consumption of Illegal Substances Act, 2025 (banning illegal-drug use in public places, including tents/encampments, with fines up to $10,000 and/or up to six months' jail) and amends the Trespass to Property Act to add aggravating sentencing factors. A frequent overstatement is that the law itself 'bans encampments' or lets police demolish them at will; it does not directly authorize encampment removal but expands drug-consumption and trespass enforcement, and municipalities/police have discretion over whether to use the new powers.","sources":[{"title":"Bill 6, Safer Municipalities Act, 2025 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-6","type":"official"},{"title":"Understanding Ontario's Safer Municipalities Act, 2025 - Gowling WLG","url":"https://gowlingwlg.com/en/insights-resources/articles/2025/understanding-ontarios-safer-municipalities-act-2025","type":"legal"},{"title":"CCLA Reacts to Ontario Passing the Safer Municipalities Act - Canadian Civil Liberties Association","url":"https://ccla.org/equality/ccla-reacts-to-ontario-passing-the-safer-municipalities-act/","type":"advocacy"},{"title":"Ontario anti-encampment law punishes the homeless, avoids long-term solutions: critics - CBC News","url":"https://www.cbc.ca/news/canada/toronto/ontario-encampment-law-1.7555659","type":"news"},{"title":"Ontario's 'Safer Municipalities Act' (Bill 6) and the Criminalization of Indigenous People in the City - Yellowhead Institute","url":"https://yellowheadinstitute.org/2025/ontarios-safer-municipalities-act-bill-6-and-the-criminalization-of-indigenous-people-in-the-city/","type":"academic"}],"commentary":[{"source":"Canadian Civil Liberties Association (CCLA)","stance":"oppose","quote":"As part of the Encampment Justice Coalition, the CCLA opposes the 'punitive and harmful measures,' warning the Act lets police remove and arrest people from encampments without a warrant on mere suspicion of drug use and only 'serves to further criminalize vulnerable individuals.'","url":"https://ccla.org/equality/ccla-reacts-to-ontario-passing-the-safer-municipalities-act/"},{"source":"Encampment Justice Coalition (85 Ontario organizations)","stance":"oppose","quote":"Open letter urging the government to rescind Bill 6 and instead pursue 'human rights-compliant, evidence-based' solutions, above all safe, affordable housing.","url":"https://ccla.org/press-release/67-organizations-across-ontario-stand-against-punishing-encampments/"},{"source":"Government of Ontario (Solicitor General)","stance":"support","quote":"Says the Act gives police and municipalities tools to restore safe public spaces by addressing public drug use and repeat trespassing.","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-6"},{"source":"Northeastern Ontario police services (CBC reporting)","stance":"mixed","quote":"Several police leaders said they were in no rush to use the new powers, with the message that 'you definitely can't arrest your way out of this' homelessness and addiction crisis.","url":"https://www.cbc.ca/news/canada/sudbury/bill-6-encampment-enforcement-police-1.7557410"}]},"on-bill-97":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-97","factCheck":"Verified: Bill 97 (the 2026 budget bill) received Royal Assent in 2026 (S.O. 2026, c. 2) and amends FIPPA and MFIPPA; the most controversial provisions exclude records held by the Premier, ministers, MPPs and their political staff from access-to-information laws, with the FIPPA changes deemed in force July 1, 2026 (some provisions Sept. 15, 2026). It is accurate that critics call this the most restrictive change to FIPPA in roughly 40 years and that there are retroactivity concerns affecting existing FOI requests/orders; the bill does not abolish FOI generally but narrows access to political-office records.","sources":[{"title":"Bill 97, Plan to Protect Ontario Act (Budget Measures), 2026 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-97","type":"official"},{"title":"Ontario's Bill 97 threatens government accountability and privacy - CCLA","url":"https://ccla.org/fundamental-freedoms/freedoms-expression/access-to-information/ontarios-bill-97-threatens-government-accountability-and-privacy/","type":"advocacy"},{"title":"Ontario passes law shielding provincial ministers' records from information requests - JURIST","url":"https://www.jurist.org/news/2026/04/ontario-passes-law-shielding-provincial-ministers-records-from-information-requests/","type":"news"},{"title":"PCs advance their proposed records-secrecy law changes - The Trillium","url":"https://www.thetrillium.ca/news/politics/pcs-advance-their-proposed-records-secrecy-law-changes-12096019","type":"news"},{"title":"Bill 97 would reshape Ontario's access and privacy regime - BLG","url":"https://www.blg.com/en/insights/2026/04/major-access-to-information-and-privacy-reform-comes-to-ontario","type":"legal"}],"commentary":[{"source":"Patricia Kosseim, Information and Privacy Commissioner of Ontario","stance":"oppose","quote":"'If records about government business can be shielded from scrutiny simply because they sit in a minister's office, on a staffer's device, or within a political account, public accountability is eviscerated.'","url":"https://www.jurist.org/news/2026/04/ontario-passes-law-shielding-provincial-ministers-records-from-information-requests/"},{"source":"Canadian Civil Liberties Association (CCLA)","stance":"oppose","quote":"Warns the bill represents the most restrictive changes to FIPPA since its creation and that retroactively excluding ministerial records would invalidate existing FOI requests, disclosure orders and court decisions.","url":"https://ccla.org/fundamental-freedoms/freedoms-expression/access-to-information/ontarios-bill-97-threatens-government-accountability-and-privacy/"},{"source":"The Trillium (Queen's Park reporting)","stance":"mixed","quote":"Reports the PCs advanced the changes over objections that they amount to a 'records-secrecy' law, while the government framed them as modernizing and streamlining the FOI system.","url":"https://www.thetrillium.ca/news/politics/pcs-advance-their-proposed-records-secrecy-law-changes-12096019"},{"source":"Government of Ontario (Ministry of Finance)","stance":"support","quote":"Presents the FIPPA/MFIPPA amendments as improving operational efficiency in responding to access requests and modernizing the privacy framework.","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-97"}]},"on-bill-119":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-119","factCheck":"Verified: Bill 119, sponsored by Solicitor General Michael Kerzner, had first reading May 25, 2026 and, per the Legislative Assembly, is currently at 'Second Reading - Ordered referred to a Standing Committee'; it is an omnibus public-safety bill (roughly 16 schedules) covering high-risk/sex-offender public notification, human-trafficking debt relief, towing-industry oversight, transit safety and restraining-order enforcement. Misinformation to correct: some early reports claimed its second reading was 'lost on division' and the bill defeated - that is not what the official record shows; as of mid-June 2026 the bill remains alive and in committee, not defeated.","sources":[{"title":"Bill 119, Protecting Ontario's Streets and Communities Act, 2026 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-119","type":"official"},{"title":"House of Bills: May 25-28, 2026 - Know How (Great Library / LSO)","url":"https://greatlibrary.blog/2026/06/01/house-of-bills-may-25-28-2026/","type":"legal"},{"title":"Ontario Introduces Legislation to Protect Communities and Keep Streets Safe - Indigenous Lands & Resources Today","url":"https://ilrtoday.ca/ontario-introduces-legislation-to-protect-communities-and-keep-streets-safe/","type":"news"},{"title":"Bill 119 Proposes Changes to the Planning Act - Barriston Law","url":"https://www.barristonlaw.com/municipal-law/bill-119-proposes-changes-to-the-planning-act","type":"legal"}],"commentary":[{"source":"Government of Ontario (Solicitor General Michael Kerzner)","stance":"support","quote":"Describes the bill as 'bold new measures' to support human-trafficking victims (including up to $50,000 in debt relief), crack down on illegal drugs, strengthen towing-industry oversight and make restraining orders easier to enforce.","url":"https://ilrtoday.ca/ontario-introduces-legislation-to-protect-communities-and-keep-streets-safe/"},{"source":"Dawn Gallagher Murphy, MPP (government)","stance":"support","quote":"Promotes the legislation as protecting communities and keeping streets safe, highlighting public notification on high-risk offenders and crackdowns on illegal drugs and trafficking.","url":"https://dawngallaghermurphympp.ca/ontario-introduces-legislation-to-protect-communities-and-keep-streets-safe/"},{"source":"Barriston Law (municipal-law analysis)","stance":"mixed","quote":"Notes the omnibus bill reaches beyond policing into Planning Act and procurement (e.g., government drone procurement) changes, flagging breadth that municipal and development stakeholders should monitor.","url":"https://www.barristonlaw.com/municipal-law/bill-119-proposes-changes-to-the-planning-act"}]},"on-bill-75":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-75","factCheck":"Verified: Bill 75 received Royal Assent in 2026 (S.O. 2026, c. 7); its centrepiece Bail Act (Schedule 2) requires accused persons or sureties to pay a cash security deposit up front in certain cases, and it also enacts the Constable Joe MacDonald scholarship fund and amends the Highway Traffic Act (90-day suspensions/impoundment for dangerous driving) and other Acts. Important caveats: bail is primarily federal criminal law, so legal experts warn key provisions may be challenged as ultra vires and as contrary to the s. 11(e) Charter right not to be denied reasonable bail; the 'cash up front in every case' framing is contested, and any province-wide cash-bail regime would still operate within the federal Criminal Code framework.","sources":[{"title":"Bill 75, Keeping Criminals Behind Bars Act, 2026 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-75","type":"official"},{"title":"Bill 75 - Schedule 2 Bail Act (submission) - Ontario Bar Association","url":"https://oba.org/Our-Impact/Submissions/Bill-75-Schedule-2-Bail-Act","type":"legal"},{"title":"Ontario's 'atrocious' plan for cash bail may be unconstitutional - CBA National Magazine","url":"https://nationalmagazine.ca/en-ca/articles/law/in-depth/2025/ontario-s-%E2%80%98atrocious-plan-for-cash-bail-may-be-unconstitutional","type":"legal"},{"title":"Ontario plans to require bail cash up front as part of new justice bill - CBC News","url":"https://www.cbc.ca/news/canada/toronto/ontario-to-table-bail-cash-up-front-bill-9.6990304","type":"news"},{"title":"Ontario Government Introduces Keeping Criminals Behind Bars Act - Ontario Association of Chiefs of Police","url":"https://www.oacp.ca/en/news/ontario-government-introduces-keeping-criminals-behind-bars-act-2025.aspx","type":"advocacy"}],"commentary":[{"source":"Ontario Bar Association","stance":"oppose","quote":"'Respectfully, the proposed reform should not be pursued,' warning mandatory cash deposits create a 'wealth-based system of pre-trial detention' that harms low-income accused regardless of public-safety risk.","url":"https://oba.org/Our-Impact/Submissions/Bill-75-Schedule-2-Bail-Act"},{"source":"Senator Kim Pate","stance":"oppose","quote":"Calls the cash-bail plan 'atrocious,' saying it signals 'a very clear move to a type of approach where, if you have cash or resources, there's a better chance that you will be released' - something 'nowhere articulated in our Charter.'","url":"https://nationalmagazine.ca/en-ca/articles/law/in-depth/2025/ontario-s-%E2%80%98atrocious-plan-for-cash-bail-may-be-unconstitutional"},{"source":"Howard Sapers, Canadian Civil Liberties Association","stance":"oppose","quote":"Warns the plan will sharply increase the number of people sent to overcrowded provincial jails with inhumane conditions.","url":"https://www.cbc.ca/news/canada/toronto/ontario-to-table-bail-cash-up-front-bill-9.6990304"},{"source":"Ontario Association of Chiefs of Police","stance":"support","quote":"Welcomes the legislation as strengthening accountability for repeat and violent offenders and supporting public safety.","url":"https://www.oacp.ca/en/news/ontario-government-introduces-keeping-criminals-behind-bars-act-2025.aspx"}]},"on-bill-101":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-101","factCheck":"Verified: Bill 101 received Royal Assent in 2026 (S.O. 2026, c. 4); it restructures school-board governance - splitting the director's role into a Chief Executive Officer and a Chief Education Officer, expanding the Minister's powers over board communications and educational materials, and changing the central collective-bargaining framework. A clarification: the law does not 'abolish' elected trustees outright, but critics say it strips trustees of core authority (budgets, bargaining leadership) and centralizes power with the Minister; reports that it was merely 'proposed' are out of date, as it has passed.","sources":[{"title":"Bill 101, Putting Student Achievement First Act, 2026 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-101","type":"official"},{"title":"OPSBA Statement on Bill 101, Putting Student Achievement First Act, 2026","url":"https://educationnewscanada.com/article/education/level/k12/3/1194888/opsba-statement-on-bill-101-putting-student-achievement-first-act-2026.html","type":"advocacy"},{"title":"School boards and universities will both be affected by Ontario's Bill 101 sweeping changes - The Conversation","url":"https://theconversation.com/school-boards-and-universities-will-both-be-affected-by-ontarios-bill-101-sweeping-changes-281412","type":"academic"},{"title":"Ontario Proposes Substantive Changes to School Board Governance and Collective Bargaining - Hicks Morley","url":"https://hicksmorley.com/2026/04/27/ontario-is-proposing-changes-to-governance-and-collective-bargaining-in-school-boards/","type":"legal"}],"commentary":[{"source":"Ontario Public School Boards' Association (OPSBA)","stance":"oppose","quote":"Expressed deep concern that removing core responsibilities such as budgets and bargaining leadership from elected trustees 'means removing decisions from people directly accountable to the community.'","url":"https://educationnewscanada.com/article/education/level/k12/3/1194888/opsba-statement-on-bill-101-putting-student-achievement-first-act-2026.html"},{"source":"OSSTF/FEESO (teachers' union)","stance":"oppose","quote":"Said that even with Bill 101 passed, 'the real issues in Ontario schools remain unresolved' - violence, larger class sizes, staffing shortages and fewer student supports.","url":"https://www.facebook.com/osstfnews/posts/bill-101-has-passed-but-the-real-issues-in-ontario-schools-remain-unresolvedviol/1399081378918361/"},{"source":"Government of Ontario (Ministry of Education)","stance":"support","quote":"States the objective is to strengthen school-board oversight and accountability and ensure more consistent learning experiences for students.","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-101"},{"source":"The Conversation (academic analysis)","stance":"mixed","quote":"Analyzes the bill as a sweeping centralization affecting both school boards and universities, raising concerns about democratic accountability while noting the government's efficiency rationale.","url":"https://theconversation.com/school-boards-and-universities-will-both-be-affected-by-ontarios-bill-101-sweeping-changes-281412"}]},"on-bill-100":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-100","factCheck":"Verified: Bill 100 received Royal Assent in 2026 (S.O. 2026, c. 3), amending the Municipal Act, 2001 and Municipal Elections Act, 1996; it lets the Minister appoint heads of council ('Strong Chair' powers) for eight upper-tier municipalities (Durham, Halton, Muskoka, Niagara, Peel, Simcoe, Waterloo, York) and restructures Niagara Regional Council (reducing it to mayors plus the appointed chair). A correction: the bill is not an amalgamation law - earlier Niagara amalgamation proposals were shelved - so claims that it 'merges' municipalities are inaccurate; the core change is appointed regional chairs and reduced/restructured councils.","sources":[{"title":"Bill 100, Better Regional Governance Act, 2026 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-100","type":"official"},{"title":"Better Regional Governance Act, 2026, passes through Ontario Legislature - Niagara Independent","url":"https://niagaraindependent.ca/better-regional-governance-act-2026-passes-through-ontario-legislature/","type":"news"},{"title":"'Consolidation of Power' the Overarching Theme for Changes to Regional Governance in Ontario, Local Mayor Says - PressProgress","url":"https://pressprogress.ca/consolidation-of-power-the-overarching-theme-for-changes-to-regional-governance-in-ontario-local-mayor-says/","type":"news"},{"title":"Bill 100 Regional Governance Changes - Association of Municipalities of Ontario (AMO)","url":"https://www.amo.on.ca/policy/finance-infrastructure-and-economy/bill-100-regional-governance-changes-canada-ontario","type":"advocacy"},{"title":"Ontario announces plan to slash Niagara Region, Simcoe County councils and add 'strong chair' powers - CBC News","url":"https://www.cbc.ca/news/canada/hamilton/ontario-governance-structure-announcement-9.7151746","type":"news"}],"commentary":[{"source":"Wayne Redekop, Mayor of Fort Erie","stance":"oppose","quote":"'The result is, with the appointment of the eight regional chairs, a consolidation of power. And that seems to be an overriding theme,' warning it could let an unelected chair and the two largest municipalities decide major Niagara issues and 'jeopardizes the smaller communities.'","url":"https://pressprogress.ca/consolidation-of-power-the-overarching-theme-for-changes-to-regional-governance-in-ontario-local-mayor-says/"},{"source":"Association of Municipalities of Ontario (AMO)","stance":"mixed","quote":"Engages on the regional governance changes, seeking clarity for affected municipalities while flagging concerns about local representation and the appointment of upper-tier heads of council.","url":"https://www.amo.on.ca/policy/finance-infrastructure-and-economy/bill-100-regional-governance-changes-canada-ontario"},{"source":"Government of Ontario (Ministry of Municipal Affairs and Housing)","stance":"support","quote":"Presents the Act as streamlining regional decision-making and supporting housing and infrastructure delivery through stronger, more accountable regional leadership.","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-100"}]},"on-bill-33":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-33","factCheck":"Verified: Bill 33 received Royal Assent on November 28, 2025 (S.O. 2025, c. 12), amending the Child, Youth and Family Services Act, 2017, the Education Act, the Ministry of Training, Colleges and Universities Act, and the Ombudsman Act; it expands the Minister's power to investigate and take control of school boards, requires boards to work with police on school-access and school resource officer programs 'in the prescribed circumstances,' and gives the government power to regulate fees charged by colleges and universities. A nuance: the police-in-schools provision does not unilaterally mandate officers in every school - it requires boards to implement SRO programs 'where such programs are available' and as prescribed by regulation.","sources":[{"title":"Bill 33, Supporting Children and Students Act, 2025 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-33","type":"official"},{"title":"Ontario's Bill 33: Key changes to education, child welfare and postsecondary oversight - BLG","url":"https://www.blg.com/en/insights/2025/06/ontarios-bill-33-key-changes-to-education-child-welfare-and-postsecondary-oversight","type":"legal"},{"title":"OHRC Submission on Bill 33, Supporting Children and Students Act, 2025 - Ontario Human Rights Commission","url":"https://www3.ohrc.on.ca/en/ohrc-submission-bill-33-supporting-children-and-students-act-2025","type":"advocacy"},{"title":"Ontario passes Bill 33 - The Varsity","url":"https://thevarsity.ca/2025/11/23/ontario-passes-bill-33/","type":"news"}],"commentary":[{"source":"Ontario Human Rights Commission (OHRC)","stance":"mixed","quote":"Raised human-rights concerns about provisions such as reintroducing police/SRO programs in schools, urging the government to ensure measures do not disproportionately harm Indigenous, Black and other marginalized students.","url":"https://www3.ohrc.on.ca/en/ohrc-submission-bill-33-supporting-children-and-students-act-2025"},{"source":"Ontario Public School Boards' Association (OPSBA)","stance":"mixed","quote":"Submitted recommended amendments expressing concern about expanded ministerial control over boards and the implications of mandated police-in-schools and fee-regulation provisions.","url":"https://www.opsba.org/wp-content/uploads/2025/01/OPSBA-Submission-and-Recommended-Amendments-for-Bill-33-FINAL.pdf"},{"source":"Student groups / The Varsity (postsecondary reporting)","stance":"oppose","quote":"Report that students and campus groups opposed the new provincial power to regulate university and college student fees, fearing it could undercut student-union and ancillary-fee autonomy.","url":"https://thevarsity.ca/2025/11/23/ontario-passes-bill-33/"},{"source":"Government of Ontario (Ministry of Education)","stance":"support","quote":"Frames the Act as supporting children and students by strengthening school-board accountability, reintroducing police partnerships, and protecting students through fee oversight.","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-33"}]},"on-bill-105":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-105","factCheck":"Verified: Bill 105 (the 'POWER Act') was introduced April 20, 2026 and, per the Legislative Assembly, is at the third-reading stage ('Ordered for Third Reading') and had NOT yet received Royal Assent as of mid-June 2026; it is an omnibus bill amending about eight statutes (including the ESA, LRA, OHSA and WSIA) and enacting the new Strengthening Talent Agency Regulation Act, 2026. Anyone describing it as already 'in force' or 'law' is mistaken - key provisions are tied to a future Royal Assent date. Notable measures include barring employers from charging workers for uniforms, a worker Occupational Exposure Registry, and shortening construction-sector union displacement/termination ('open period') windows from two months to one.","sources":[{"title":"Bill 105, Protecting Ontario's Workers and Economic Resilience Act, 2026 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-105","type":"official"},{"title":"Employment and labour law changes in Ontario's POWER Act - Norton Rose Fulbright","url":"https://www.nortonrosefulbright.com/en-ca/knowledge/publications/83870796/employment-and-labour-law-changes-in-ontario-s-power-act","type":"legal"},{"title":"New Protections for Ontario Workers under Bill 105 - Koskie Minsky LLP","url":"https://kmlaw.ca/new-protections-for-ontario-workers-under-bill-105-proposed-changes-to-the-employment-standards-act-2000-and-the-proposed-strengthening-talent-agency-regulation-act-2006/","type":"legal"},{"title":"What Contractors Should Know About the POWER Act - Council of Ontario Construction Associations","url":"https://coca.on.ca/what-contractors-should-know-about-the-power-act/","type":"advocacy"}],"commentary":[{"source":"Koskie Minsky LLP (union-side / employee-side firm)","stance":"support","quote":"Highlights the bill's 'new protections for Ontario workers,' including prohibiting employers from charging employees for uniforms and creating the new talent-agency regulation regime to protect entertainment workers.","url":"https://kmlaw.ca/new-protections-for-ontario-workers-under-bill-105-proposed-changes-to-the-employment-standards-act-2000-and-the-proposed-strengthening-talent-agency-regulation-act-2006/"},{"source":"Council of Ontario Construction Associations (COCA)","stance":"mixed","quote":"Flags for contractors that shortening construction displacement/termination application windows from two months to one month, plus OHSA and WSIA changes, will materially affect the sector and labour relations.","url":"https://coca.on.ca/what-contractors-should-know-about-the-power-act/"},{"source":"Norton Rose Fulbright (employer-side analysis)","stance":"mixed","quote":"Describes the POWER Act as a broad omnibus reform balancing new worker protections with significant compliance changes for employers across the ESA, LRA, OHSA and WSIA.","url":"https://www.nortonrosefulbright.com/en-ca/knowledge/publications/83870796/employment-and-labour-law-changes-in-ontario-s-power-act"},{"source":"Government of Ontario (Ministry of Labour)","stance":"support","quote":"Presents the bill as protecting workers and bolstering economic resilience amid tariff pressures, strengthening health and safety and cracking down on exploitation of vulnerable workers.","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-105"}]},"on-bill-40":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-40","factCheck":"Verified: Bill 40 received Royal Assent on December 12, 2025 (S.O. 2025, c. 22) and is in force; it amends the Electricity Act, 1998, the Ontario Energy Board Act, 1998 and the Municipal Franchises Act to expedite energy approvals, add 'economic growth' as an OEB/Electricity Act objective, set connection requirements for large 'specified load facilities' such as data centres (new s. 28.1), and remove the requirement for a municipal elector vote before granting public-utility/franchise rights (replacing it with council approval). The law also restricts foreign participation in Ontario's energy sector via regulation; characterizing it purely as a 'data-centre bill' understates its broader procurement and franchise changes.","sources":[{"title":"Bill 40, Protect Ontario by Securing Affordable Energy for Generations Act, 2025 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-40","type":"official"},{"title":"Bill 40 Receives Royal Assent - Major Changes to Ontario Energy Policy Now in Effect - McCarthy Tetrault","url":"https://www.mccarthy.ca/en/insights/blogs/canadian-energy-perspectives/bill-40-protect-ontario-by-securing-affordable-energy-for-generations-act-2025-receives-royal-assent-major-changes-to-ontario-energy-policy-now-in-effect","type":"legal"},{"title":"Bill 40: key changes that will affect Ontario's energy sector and data centre industry - Torys LLP","url":"https://www.torys.com/our-latest-thinking/publications/2025/06/bill-40","type":"legal"},{"title":"Ontario's Bill 40: Expediting Regulatory Approvals for Energy Infrastructure Projects - Blakes","url":"https://www.blakes.com/insights/ontario-proposes-expediting-regulatory-approvals-for-energy-infrastructure-projects-with-bill-40/","type":"legal"}],"commentary":[{"source":"Government of Ontario (Ministry of Energy)","stance":"support","quote":"Says the Act will help build an affordable, secure, reliable and clean energy system and boost domestic investment in local energy infrastructure.","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-40"},{"source":"Torys LLP (energy-law analysis)","stance":"mixed","quote":"Notes the bill significantly reshapes Ontario energy policy and the data-centre connection regime, creating opportunities but also new compliance and approval considerations for the sector.","url":"https://www.torys.com/our-latest-thinking/publications/2025/06/bill-40"},{"source":"McCarthy Tetrault (energy-law analysis)","stance":"mixed","quote":"Highlights that removing municipal elector approval for franchise rights and adding 'economic growth' as a regulatory objective are major changes 'now in effect' that shift the balance of energy decision-making.","url":"https://www.mccarthy.ca/en/insights/blogs/canadian-energy-perspectives/bill-40-protect-ontario-by-securing-affordable-energy-for-generations-act-2025-receives-royal-assent-major-changes-to-ontario-energy-policy-now-in-effect"}]},"on-bill-114":{"officialUrl":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-114","factCheck":"Verified: Bill 114 received Royal Assent in May 2026 (S.O. 2026, c. 5); it amends the Retail Sales Tax Act to let the Minister, by regulation, provide credits/payments for the federal (5%) component of HST on residential property, complementing the federal new-home rebate so eligible buyers can receive up to roughly $130,000 in combined HST relief on qualifying new homes (agreements after March 31, 2026 and before April 1, 2027). Important caveat: although the enabling law has passed, the relief is not automatically payable yet - the CRA and Ontario have said further regulations and administrative steps are needed before rebates can actually be paid or credited, so buyers expecting an immediate cheque may be misinformed.","sources":[{"title":"Bill 114, HST Relief Implementation Act (Residential Property Rebates), 2026 - Legislative Assembly of Ontario","url":"https://www.ola.org/en/legislative-business/bills/parliament-44/session-1/bill-114","type":"official"},{"title":"Tax Insights: Enhanced Harmonized Sales Tax relief on the sale of new homes in Ontario - PwC Canada","url":"https://www.pwc.com/ca/en/services/tax/publications/tax-insights/enhanced-hst-relief-sale-new-homes-ontario-2026.html","type":"legal"},{"title":"Recent Sales Tax Changes in Ontario and British Columbia: HST Relief and PST Expansion - Richter","url":"https://www.richter.ca/our-insights/ontario-and-british-columbia-hst-relief-and-pst-expansion/","type":"legal"},{"title":"Ontario's new-home HST relief awaits final rules as builders explore workarounds - Canadian Mortgage Trends","url":"https://www.canadianmortgagetrends.com/2026/06/ontarios-new-home-hst-relief-awaits-final-rules-as-builders-explore-workarounds/","type":"news"}],"commentary":[{"source":"Government of Ontario (Ministry of Finance)","stance":"support","quote":"Promotes the measure as eliminating HST on qualifying new homes up to $1 million (with partial relief to higher values), projecting a roughly $2.7 billion boost to housing affordability and construction.","url":"https://ontarioconstructionnews.com/ontario-introduces-legislation-to-implement-hst-relief-on-new-homes-projecting-2-7-billion-boost"},{"source":"PwC Canada (tax analysis)","stance":"mixed","quote":"Explains the enhanced rebate mechanics and eligibility but notes the relief depends on the interaction of federal and provincial measures and on regulations still to be finalized.","url":"https://www.pwc.com/ca/en/services/tax/publications/tax-insights/enhanced-hst-relief-sale-new-homes-ontario-2026.html"},{"source":"Canadian Mortgage Trends (industry reporting)","stance":"mixed","quote":"Reports the relief 'awaits final rules,' with builders exploring workarounds and buyers facing uncertainty because rebates cannot yet be paid pending further CRA/Ontario administrative steps.","url":"https://www.canadianmortgagetrends.com/2026/06/ontarios-new-home-hst-relief-awaits-final-rules-as-builders-explore-workarounds/"}]},"qc-bill-2":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-2-43-3.html","factCheck":"Verified: Bill 2 (An Act respecting the renewal of the override/notwithstanding provisions protecting the Charter of the French Language and the Act respecting French, the official and common language of Quebec) was introduced May 6, 2026 by French Language Minister Jean-Francois Roberge and adopted in the June 2026 pre-recess blitz; it extends the Section 33 override shielding Bill 101/Bill 96 for a further five years (to roughly 2031). Common misconception to correct: the bill does NOT itself change the substance of Bill 101 or Bill 96 and it is not 'new' use of the clause - it pre-emptively renews an existing override (originally enacted with Bill 96 in 2022 and otherwise valid until 2027), one year ahead of the deadline.","sources":[{"title":"Bill 2 - Renewal of notwithstanding provisions for the Charter of the French Language (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-2-43-3.html","type":"official"},{"title":"Quebec Premier Frechette to renew notwithstanding clause on province's language law (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/quebec-notwithstanding-clause-9.7188161","type":"news"},{"title":"Frechette to renew Charter override clause for language law as legislature resumes (CTV News)","url":"https://www.ctvnews.ca/montreal/politics/article/frechette-to-renew-charter-override-clause-for-language-law-as-legislature-resumes/","type":"news"},{"title":"2026 - Projet de loi 2 (Bibliotheque de l'Assemblee nationale du Quebec - thematic guide on the Charter of the French Language)","url":"https://www.bibliotheque.assnat.qc.ca/guides/fr/charte-de-la-langue-francaise/reglements/19333-2026-projet-de-loi-2","type":"official"},{"title":"Renouvellement de la clause derogatoire pour la loi 101: CAQ, PLQ et QS s'affrontent en commission (APDQ)","url":"https://actualitepolitiqueduquebec.com/p/la-caq-renouvelle-la-clause-derogatoire","type":"news"}],"commentary":[{"source":"Coalition Avenir Quebec / Jean-Francois Roberge (French Language Minister)","stance":"support","quote":"The government presents the renewal as an essential shield to protect Bill 101 and the Bill 96 reforms from challenges under the Canadian Charter of Rights and Freedoms, renewing it early because of the tight pre-election calendar.","url":"https://www.ctvnews.ca/montreal/politics/article/frechette-to-renew-charter-override-clause-for-language-law-as-legislature-resumes/"},{"source":"Quebec Liberal Party (PLQ)","stance":"oppose","quote":"The PLQ voted against Bill 2, arguing that certain provisions of Bill 96 are themselves problematic and should not be pre-emptively immunized from court review.","url":"https://actualitepolitiqueduquebec.com/p/la-caq-renouvelle-la-clause-derogatoire"},{"source":"Quebec solidaire (QS)","stance":"mixed","quote":"QS supported protecting French but proposed amendments to remove the derogation from the Quebec Charter of Human Rights and Freedoms; the amendments were rejected.","url":"https://actualitepolitiqueduquebec.com/p/la-caq-renouvelle-la-clause-derogatoire"}]},"qc-bill-4":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-4-43-3.html","factCheck":"Verified: Bill 4 (An Act respecting the communication of information for the purpose of protecting against intimate partner violence), nicknamed the 'Gabie Renaud Law' and modelled on the UK's 'Clare's Law,' was introduced by the CAQ government and passed in the June 2026 session (adopted Thursday June 11, 2026). It lets a person who fears for their safety or their children's request, online or at a police station, a file on a current/former partner's history of conjugal violence; the Surete du Quebec compiles the file and a support organization discloses it. Correction: it is broader than a standard criminal-record check and is named for Gabie Renaud, allegedly killed by her partner in Saint-Jerome in 2025; similar 'Clare's Law' regimes already exist in Saskatchewan, Manitoba and Alberta.","sources":[{"title":"Bill 4 - Communication of information to protect against intimate partner violence (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-4-43-3.html","type":"official"},{"title":"Quebec proposes law allowing people to obtain conjugal violence history of partners (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/quebec-intimate-partner-violence-bill-9.7198271","type":"news"},{"title":"Quebec tables bill allowing people to obtain domestic violence history of partners (The Globe and Mail)","url":"https://www.theglobeandmail.com/canada/article-quebec-bill-partner-domestic-violence-history-gabie-renaud/","type":"news"},{"title":"Violence against women: 'Gabie Renaud' bill introduced in Quebec (CTV News)","url":"https://www.ctvnews.ca/montreal/article/gabie-renaud-bill-introduced-in-quebec-to-combat-violence-against-women/","type":"news"},{"title":"It's raining laws: Quebec passes slew of bills in blitz before summer break (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/bills-passing-in-quebec-legislation-9.7232094","type":"news"}],"commentary":[{"source":"Coalition Avenir Quebec (government)","stance":"support","quote":"The CAQ framed Bill 4 as a tool to prevent femicide by letting at-risk people learn a partner's violent past before harm occurs, citing Gabie Renaud's case in which her partner had numerous prior convictions and probation breaches.","url":"https://www.ctvnews.ca/montreal/article/gabie-renaud-bill-introduced-in-quebec-to-combat-violence-against-women/"},{"source":"Indigenous / First Nations organizations (as reported)","stance":"mixed","quote":"Some Indigenous groups welcomed the intent but called for further consultation on how the regime would apply in their communities before implementation.","url":"https://easterndoor.com/article/bill-aims-to-curb-domestic-violence"},{"source":"The Globe and Mail (reporting on advocates)","stance":"mixed","quote":"Advocates broadly welcomed the measure while cautioning that disclosure must be paired with safety planning and support so that requests do not inadvertently escalate danger to victims.","url":"https://www.theglobeandmail.com/canada/article-quebec-bill-partner-domestic-violence-history-gabie-renaud/"}]},"qc-bill-23":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-23-43-3.html","factCheck":"Verified: Bill 23 (An Act to, in particular, better support persons whose mental state could present a risk to their own safety or that of others), reforming the 1998 'P-38' involuntary-hospitalization law, was tabled March 24, 2026 by Health and Seniors Minister Sonia Belanger and passed Friday June 12, 2026 after being significantly amended in committee. It relaxes the threshold from a 'grave and immediate' danger to a broader 'situation where there is a danger'; police would need authorization from a crisis worker before acting, an initial hold runs about seven days, and holds beyond a week require an application to the Administrative Tribunal of Quebec. Correction: it loosens (does not abolish) the danger criterion and adds procedural safeguards; it was prompted partly by high-profile killings (a downtown Montreal store clerk; the 2023 death of officer Maureen Breau).","sources":[{"title":"Bill 23 - Better supporting persons whose mental state could present a risk (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-23-43-3.html","type":"official"},{"title":"Bill 23: Quebec passes law on involuntary hospitalizations (CTV News)","url":"https://www.ctvnews.ca/montreal/article/bill-23-quebec-passes-law-on-involuntary-hospitalizations/","type":"news"},{"title":"Quebec tables bill on involuntary hospitalization (The Canadian Press)","url":"https://www.thecanadianpressnews.ca/health/quebec-tables-bill-on-involuntary-hospitalization/article_a1145902-dc2f-5009-9efa-4d2ee2487187.html","type":"news"},{"title":"Quebec psychiatrists group supports bill on forced hospitalizations for mentally ill (CTV News)","url":"https://www.ctvnews.ca/montreal/health/article/quebec-psychiatrists-group-supports-bill-on-forced-hospitalizations-for-mentally-ill/","type":"news"}],"commentary":[{"source":"Association des medecins psychiatres du Quebec (Quebec psychiatrists)","stance":"support","quote":"The province's psychiatrists' association publicly backed the reform, saying the old 'grave and immediate danger' test was too restrictive and prevented timely care for deteriorating patients.","url":"https://www.ctvnews.ca/montreal/health/article/quebec-psychiatrists-group-supports-bill-on-forced-hospitalizations-for-mentally-ill/"},{"source":"Quebec Institute for Law and Justice Reform (commissioned report)","stance":"mixed","quote":"A government-commissioned report found the existing P-38 regime already represented a 'serious infringement of people's fundamental rights and freedoms,' underscoring the need for stronger procedural safeguards alongside any expansion.","url":"https://www.thecanadianpressnews.ca/health/quebec-tables-bill-on-involuntary-hospitalization/article_a1145902-dc2f-5009-9efa-4d2ee2487187.html"},{"source":"Civil-liberties / patient-rights advocates (as reported)","stance":"oppose","quote":"Rights advocates warned that broadening the danger threshold risks more coercive detentions of people with mental illness and could erode autonomy if safeguards are weak.","url":"https://www.ctvnews.ca/montreal/article/bill-23-quebec-passes-law-on-involuntary-hospitalizations/"}]},"qc-bill-24":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-24-43-3.html","factCheck":"Verified: Bill 24 (An Act to protect consumers against the deceptive or fraudulent use of a person's identity or image), aimed at deepfake/AI-driven scam ads, was adopted June 13, 2026 (sponsored by Justice Minister Simon Jolin-Barrette, who is also responsible for consumer protection). It prohibits using a person's identity/image without consent to make commercial representations to consumers and gives the heads of the Office de la protection du consommateur and the Autorite des marches financiers new power to order takedowns/destruction of material without first going to court, with non-compliance enforceable as contempt. Correction: this is a consumer-protection statute targeting fraudulent advertising and identity usurpation - it is distinct from Quebec's separate regime on non-consensual intimate images and from the federal/privacy-commissioner deepfake actions.","sources":[{"title":"Bill 24 - Protecting consumers against deceptive or fraudulent use of a person's identity or image (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-24-43-3.html","type":"official"},{"title":"Adoption du projet de loi no 24 - Un nouvel outil pour contrer l'usurpation d'image et les fausses publicites (Gouvernement du Quebec)","url":"https://www.quebec.ca/nouvelles/actualites/details/adoption-du-projet-de-loi-n-24-un-nouvel-outil-pour-contrer-lusurpation-dimage-et-les-fausses-publicites-71112","type":"official"},{"title":"Projet de loi no 24: Loi protegeant le consommateur contre l'utilisation trompeuse ou frauduleuse de l'identite ou de l'image (Office de la protection du consommateur)","url":"https://www.opc.gouv.qc.ca/a-propos/projet/usurpation","type":"official"},{"title":"Quebec depose un projet de loi visant a punir les voleurs d'identite en ligne (Radio-Canada)","url":"https://ici.radio-canada.ca/nouvelle/2241950/projet-loi-24-vol-identite-quebec","type":"news"},{"title":"PL24 au Quebec: l'hypertrucage par IA devant les parlementaires (APDQ analysis)","url":"https://actualitepolitiqueduquebec.com/p/pl24-lhypertrucage-rattrape-quebec","type":"news"}],"commentary":[{"source":"Office de la protection du consommateur / Gouvernement du Quebec","stance":"support","quote":"With deepfakes proliferating, fraudsters use public figures' images without consent to sell counterfeit products; the new powers let regulators act faster and more effectively against identity usurpation and false advertising.","url":"https://www.quebec.ca/nouvelles/actualites/details/adoption-du-projet-de-loi-n-24-un-nouvel-outil-pour-contrer-lusurpation-dimage-et-les-fausses-publicites-71112"},{"source":"Simon Jolin-Barrette (Minister of Justice)","stance":"support","quote":"The government cast the bill as a needed modernization giving the OPC and AMF teeth to order the cessation and destruction of fraudulent identity/image uses without lengthy court proceedings.","url":"https://ici.radio-canada.ca/nouvelle/2241950/projet-loi-24-vol-identite-quebec"},{"source":"Actualite politique du Quebec (APDQ analysis)","stance":"mixed","quote":"Commentators welcomed Quebec acting on AI deepfakes but questioned enforcement reach and whether consumer-protection tools alone can keep pace with rapidly evolving generative-AI fraud.","url":"https://actualitepolitiqueduquebec.com/p/pl24-lhypertrucage-rattrape-quebec"}]},"qc-bill-5":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-5-43-3.html","factCheck":"Verified: Bill 5 (An Act to accelerate the granting of the authorizations required to carry out priority national-scale projects), the 'Q-5' megaproject fast-track, was introduced December 9, 2025 by Finance Minister Eric Girard and reinstated in the third session on May 6, 2026. It lets the government designate projects as 'priority and of national scope' for five years and issue a single government authorization replacing permits otherwise required under laws listed in Schedule I (with conditions; an authorization lapses if a project has not begun within two years). Correction/caveat: explicitly modelled on federal Bill C-5 and Ontario's Bill 5, but as of mid-June 2026 it had reached committee study and was among the major bills the CAQ was trying to push before the session closed June 12 - it is NOT confirmed to have received final adoption, so it should not be described as already law.","sources":[{"title":"Bill 5 - Accelerating authorizations for priority national-scale projects (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-5-43-3.html","type":"official"},{"title":"Quebec's Bill 5: Fast-Tracking Priority National-Scale Projects (Blakes / Blake, Cassels & Graydon LLP)","url":"https://www.blakes.com/insights/quebec-s-bill-5-fast-tracking-priority-national-scale-projects/","type":"legal"},{"title":"Quebec's Bill 5: Fast track for priority and national projects (Dentons)","url":"https://www.dentons.com/en/insights/alerts/2025/december/16/quebecs-bill-5","type":"legal"},{"title":"Bill 5: Like Ottawa, Quebec is concentrating its power and opening the door to setbacks for health and the environment (CQDE - Quebec Environmental Law Centre)","url":"https://cqde.org/en/news/bill-c5-like-ottawa-quebec-is-concentrating-power/","type":"advocacy"},{"title":"Brief on Quebec's Bill 5 aimed at fast-tracking priority projects (MiningWatch Canada)","url":"https://miningwatch.ca/2026/2/11/brief-quebecs-bill-5-aimed-fast-tracking-priority-projects-and-projects-national","type":"advocacy"}],"commentary":[{"source":"Genevieve Paul, Executive Director, Centre quebecois du droit de l'environnement (CQDE)","stance":"oppose","quote":"'It's no longer projects that must comply with the law, but the law that adjusts to projects' - CQDE warns the bill lets megaprojects bypass dozens of environmental, agricultural and heritage protections and guts public consultation via the BAPE.","url":"https://cqde.org/en/news/bill-c5-like-ottawa-quebec-is-concentrating-power/"},{"source":"Heritage Montreal","stance":"oppose","quote":"'We deserve better than rule by arbitrariness' - the group argues the discretionary single-authorization power undermines transparency and the rule of law.","url":"https://www.heritagemontreal.org/en/bill-5-on-priority-national-projects-we-deserve-better-than-rule-by-arbitrariness/"},{"source":"Blakes (Blake, Cassels & Graydon LLP)","stance":"mixed","quote":"Business-side counsel note the bill could meaningfully speed strategic energy and critical-minerals projects, while flagging legal uncertainty around the breadth of discretion and conditions attached to authorizations.","url":"https://www.blakes.com/insights/quebec-s-bill-5-fast-tracking-priority-national-scale-projects/"}]},"qc-bill-1":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-1-43-2.html","factCheck":"Verified: Bill 1 (Quebec Constitution Act, 2025), a written provincial constitution declaring Quebec an autonomous national state and asserting primacy over inconsistent rules of law (entrenching French, state secularism, gender equality and abortion access), was tabled October 2025 under then-Premier Francois Legault. IMPORTANT correction to common misinformation: although the bill was adopted in principle on April 1, 2026 (vote 68-31), it was NEVER passed into law - Justice Minister Simon Jolin-Barrette abandoned it and it died on the order paper on June 11, 2026 when Premier Christine Frechette declined to use closure to force it through before the session ended. So it is incorrect to say Quebec 'adopted' or 'enacted' a constitution; the bill failed.","sources":[{"title":"Bill 1, Quebec Constitution Act, 2025 (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-1-43-2.html","type":"official"},{"title":"CAQ's controversial Quebec constitution bill dies as parliamentary session ends (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/caq-quebec-constitution-bill-9.7231688","type":"news"},{"title":"Quebec constitution bill dies ahead of provincial election (The Globe and Mail)","url":"https://www.theglobeandmail.com/canada/article-quebec-constitution-bill-dies-ahead-of-provincial-election/","type":"news"},{"title":"Why Quebec's proposed constitution has legal experts, civil rights groups sounding the alarm (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/quebec-legault-constitution-controversy-9.6988103","type":"news"},{"title":"Quebec's Bill 1: An Illegitimate Bill with Authoritarian Overtones (Canadian Civil Liberties Association)","url":"https://ccla.org/fundamental-freedoms/quebecs-bill-1-an-illegitimate-bill-with-authoritarian-overtones/","type":"advocacy"}],"commentary":[{"source":"Canadian Civil Liberties Association (CCLA)","stance":"oppose","quote":"The CCLA called Bill 1 'an illegitimate bill with authoritarian overtones,' saying it was drafted behind closed doors, undermines the rule of law, muzzles checks and balances, and erodes rights protections in Quebec.","url":"https://ccla.org/fundamental-freedoms/quebecs-bill-1-an-illegitimate-bill-with-authoritarian-overtones/"},{"source":"Coalition of 300+ civil-society organizations (incl. CCLA and Ligue des droits et libertes)","stance":"oppose","quote":"More than 300 organizations endorsed a joint statement calling for the complete withdrawal of Bill 1.","url":"https://ccla.org/press-release/more-than-300-organizations-call-for-the-withdrawal-of-quebecs-bill-1/"},{"source":"Simon Jolin-Barrette (Minister of Justice, sponsor)","stance":"support","quote":"Abandoning the bill, Jolin-Barrette said he was 'very proud to have taken a bill to establish a Quebec constitution as far as it has ever gone,' suggesting the idea may return in the election campaign.","url":"https://www.theglobeandmail.com/canada/article-quebec-constitution-bill-dies-ahead-of-provincial-election/"},{"source":"Parti Quebecois","stance":"oppose","quote":"The sovereigntist PQ denounced the bill as a 'fantasy,' arguing a real Quebec constitution must follow independence achieved through a referendum, not be created within Canada.","url":"https://www.cbc.ca/news/canada/montreal/caq-quebec-constitution-bill-9.7231688"}]},"qc-bill-3":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-3-43-3.html","factCheck":"Verified: Bill 3 (An Act to ensure effective representation of electors) was tabled in early May 2026 by Democratic Institutions Minister Jean-Francois Roberge and adopted Friday June 12, 2026; it increases Quebec's provincial ridings from 125 to 127. It was a response to the independent electoral boundaries commission's map (which would have eliminated one Gaspe and one east-Montreal riding to create two in the Laurentides and Centre-du-Quebec) and to a Supreme Court of Canada ruling against the government's attempt to block that redraw; the bill preserves the two threatened ridings while adding two new ones. Correction: it was co-authored with the Liberals, Parti Quebecois and Quebec solidaire (a rare all-party measure), not a unilateral CAQ gerrymander.","sources":[{"title":"Bill 3 - Ensuring effective representation of electors (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-3-43-3.html","type":"official"},{"title":"Quebec tables bill to increase number of ridings to 127 after Supreme Court decision (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/quebec-bill-ridings-supreme-court-decision-9.7191513","type":"news"},{"title":"Review of Quebec's electoral map (Elections Quebec)","url":"https://www.electionsquebec.qc.ca/en/electoral-maps/review-of-quebecs-electoral-map/","type":"official"},{"title":"It's raining laws: Quebec passes slew of bills in blitz before summer break (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/bills-passing-in-quebec-legislation-9.7232094","type":"news"}],"commentary":[{"source":"Jean-Francois Roberge (Minister responsible for Democratic Institutions)","stance":"support","quote":"Roberge said the bill delivers 'a map that truly respects effective representation,' balancing voter parity with respect for natural communities such as the Gaspe and east Montreal.","url":"https://www.cbc.ca/news/canada/montreal/quebec-bill-ridings-supreme-court-decision-9.7191513"},{"source":"Liberals, Parti Quebecois and Quebec solidaire (co-authors)","stance":"support","quote":"All three opposition parties co-authored Bill 3, backing the move to 127 seats to preserve regional ridings that the commission's map would have cut.","url":"https://www.cbc.ca/news/canada/montreal/bills-passing-in-quebec-legislation-9.7232094"},{"source":"Independent electoral boundaries commission (as reported)","stance":"oppose","quote":"The commission viewed the legislative override of its redrawn map as politically motivated interference with the independent delimitation process.","url":"https://ca.news.yahoo.com/constitution-energy-drinks-electoral-map-080000111.html"}]},"qc-bill-8":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-8-43-3.html","factCheck":"Verified: Bill 8 (An Act to regulate the language of instruction in vocational training and in adult general education) would extend Charter of the French Language (Bill 101) rules to adult education and trade programs, barring students without an English-eligibility certificate from enrolling in English-language adult/vocational courses (with a roughly two-year grace period; current students unaffected). IMPORTANT correction: the bill was tabled in early June 2026 but did NOT pass - it died on the order paper when the session ended (around June 12-13, 2026), so it is not law. English school boards estimated up to ~27,000 students could eventually be affected, and the Liberals opposed it.","sources":[{"title":"Bill 8 - Language of instruction in vocational training and adult general education (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-8-43-3.html","type":"official"},{"title":"Quebec tables expansion of Bill 101 to English adult education (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/quebec-to-table-bill-101-expansion-9.7222320","type":"news"},{"title":"Quebec tables bill to extend French language rules to adult education, drawing backlash (Global News)","url":"https://globalnews.ca/news/11891440/quebec-bill-french-adult-education/","type":"news"},{"title":"Protect our Adult Education and Vocational Training Centres (English Montreal School Board)","url":"https://www.emsb.qc.ca/emsb/articles/protect-our-adult-education-and-vocational-training-centres","type":"advocacy"},{"title":"It's raining laws: Quebec passes slew of bills in blitz before summer break (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/bills-passing-in-quebec-legislation-9.7232094","type":"news"}],"commentary":[{"source":"English Montreal School Board (EMSB)","stance":"oppose","quote":"The EMSB urged Quebecers to 'protect our adult education and vocational training centres,' warning the bill would block access to English-language adult and trade programs and threaten enrolment at anglophone centres.","url":"https://www.emsb.qc.ca/emsb/articles/protect-our-adult-education-and-vocational-training-centres"},{"source":"Quebec Provincial Association of Teachers (QPAT)","stance":"oppose","quote":"QPAT denounced Bill 8 as 'a threat to access to education, workforce qualification, and adult success.'","url":"https://digitalmedianet.com/bill-8-qpat-denounces-a-threat-to-access-to-education-workforce-qualification-and-adult-success/"},{"source":"Coalition Avenir Quebec (government)","stance":"support","quote":"The CAQ defended Bill 8 as a logical extension of Bill 101 to close a remaining gap in adult and vocational education and reinforce French as the common language of instruction.","url":"https://globalnews.ca/news/11891440/quebec-bill-french-adult-education/"}]},"qc-bill-20":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-20-43-2.html","factCheck":"Verified: Bill 20 (An Act to enact the Act to facilitate access to housing and amending various provisions with respect to housing) aimed to prioritize low-cost/affordable housing for lower-income tenants by tightening eligibility, creating a single centralized access window/portal, and penalizing housing co-op members whose income rises past a threshold. Correction to its status: the bill did NOT proceed - facing strong opposition from the cooperative-housing sector (which feared losing autonomy to select members), the CAQ shelved it and the new housing minister decided not to recall it for debate; it was effectively dropped/abandoned rather than passed.","sources":[{"title":"Bill 20 - Act to facilitate access to housing (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-20-43-2.html","type":"official"},{"title":"Proposed housing law threatens long-term stability of Quebec co-ops, advocates say (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/co-ops-quebec-bill-20-9.7150818","type":"news"},{"title":"CAQ's Bill 20 aims to regulate access to affordable housing, but critics say it's missing the real issue (The Concordian)","url":"https://theconcordian.com/2026/03/bill-20-regulation-access-affordable-housing/","type":"news"},{"title":"How Quebec's Bill 20 could impact access to affordable housing, including co-ops (CBC / Yahoo News Canada)","url":"https://ca.news.yahoo.com/quebec-bill-20-could-impact-080000060.html","type":"news"}],"commentary":[{"source":"Quebec housing cooperative sector / co-op advocates","stance":"oppose","quote":"Co-op advocates warned the single access portal would 'strip them of their independence' to screen and select residents, threatening the long-term stability and self-governance of cooperatives.","url":"https://www.cbc.ca/news/canada/montreal/co-ops-quebec-bill-20-9.7150818"},{"source":"Tenant / housing-rights critics (The Concordian)","stance":"mixed","quote":"Critics said that while better-targeting affordable units is reasonable, Bill 20 'misses the real issue' - the overall shortage and affordability crisis - and could penalize tenants whose incomes modestly rise.","url":"https://theconcordian.com/2026/03/bill-20-regulation-access-affordable-housing/"},{"source":"Quebec government / Minister responsible for Housing","stance":"support","quote":"The government argued a unified single-window system would cut administrative burden and direct scarce low-cost housing to those most in need, before agreeing to shelve the bill to address co-op concerns.","url":"https://ca.news.yahoo.com/quebec-bill-20-could-impact-080000060.html"}]},"qc-bill-10":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-10-43-3.html","factCheck":"Verified: Bill 10 (An Act to protect consumers against abusive practices in ticket reselling and online subscription renewal) was tabled December 2, 2025 and was passed in the June 2026 session ('it ultimately managed to cross the finish line'). It amends the Consumer Protection Act to require an easy, clearly labelled cancellation button for subscriptions, advance written notice (about 2-10 days) before a free trial or promo price ends, restrictions on reselling tickets above face value without the producer's authorization, protection of consumers' right to post reviews, and stronger restitution remedies. No notable misinformation found; note some provisions are expected to be phased in and the in-force dates set by regulation.","sources":[{"title":"Bill 10 - Protecting consumers against abusive practices in ticket reselling and online subscription renewal (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-10-43-3.html","type":"official"},{"title":"Quebec's Bill 10: Protecting Consumers Against Abusive Practices in Ticket Resales and Online Subscriptions (Stikeman Elliott)","url":"https://stikeman.com/en-ca/kh/corporations-commercial-law/quebecs-bill-10-protecting-consumers-against-abusive-practices-in-ticket-resales","type":"legal"},{"title":"Quebec's Bill 10: new rules for subscriptions and ticket resale practices (Osler, Hoskin & Harcourt LLP)","url":"https://www.osler.com/en/insights/updates/quebec-bill-10-new-rules-subscriptions-ticket-resale-practices/","type":"legal"},{"title":"Bill 10: Ticket reselling and online subscriptions (and cancel button and restitution obligation) (Langlois Lawyers)","url":"https://langlois.ca/en/insights/bill-10-ticket-reselling-and-online-subscriptions-and-cancel-button-and-restitution-obligation/","type":"legal"}],"commentary":[{"source":"Quebec government (Office de la protection du consommateur)","stance":"support","quote":"The government presented Bill 10 as a response to rising consumer complaints, targeting 'hard-to-cancel' subscription dark patterns, surprise renewals, and inflated unauthorized ticket resales.","url":"https://stikeman.com/en-ca/kh/corporations-commercial-law/quebecs-bill-10-protecting-consumers-against-abusive-practices-in-ticket-resales"},{"source":"Osler, Hoskin & Harcourt LLP","stance":"mixed","quote":"Business-side counsel advised that the cancel-button, pre-renewal notice and resale rules will require operational changes for merchants and ticket platforms, with phased-in compliance timelines.","url":"https://www.osler.com/en/insights/updates/quebec-bill-10-new-rules-subscriptions-ticket-resale-practices/"},{"source":"Langlois Lawyers","stance":"support","quote":"Analysts highlighted the strengthened restitution obligation and the mandatory, easily accessible cancellation mechanism as meaningful consumer-protection gains.","url":"https://langlois.ca/en/insights/bill-10-ticket-reselling-and-online-subscriptions-and-cancel-button-and-restitution-obligation/"}]},"qc-bill-9":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-9-43-3.html","factCheck":"Verified: Bill 9 (An Act to prevent the harmful effects of energy drinks on the health of young people) was adopted June 10-11, 2026 (passed 103-1, assent June 11), making Quebec the first jurisdiction in North America to restrict caffeinated energy drinks to people under 16. It bans sale to minors under 16 (including online sales and vending machines), imposes in-person sales requirements, and creates an inspection/penalty regime; an 'energy drink' is defined as a beverage with at least 150 mg caffeine per litre plus ingredients like taurine/vitamins, expressly excluding coffee, tea and certain natural health products. It takes effect about six months after assent. Correction: it restricts sales to youth and does not ban energy drinks outright; it was spurred partly by the 2024 death of 15-year-old Zachary Miron.","sources":[{"title":"Bill 9 - Preventing harmful effects of energy drinks on the health of young people (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-9-43-3.html","type":"official"},{"title":"Quebec becomes 1st Canadian province to ban energy drinks for youth (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/quebec-legislature-new-bills-9.7231667","type":"news"},{"title":"Quebec's Bill 9 Prohibits the Sale of Energy Drinks to Minors Under 16 (Fasken)","url":"https://www.fasken.com/en/knowledge/2026/06/quebec-loi-9","type":"legal"},{"title":"Health experts back Quebec's proposed ban on energy drinks for teens (CBC News)","url":"https://www.cbc.ca/news/canada/montreal/quebec-energy-drinks-ban-consultation-9.7229009","type":"news"},{"title":"CBA Statement: Adoption of Quebec's Bill 9 Ignores Science-Based Health Canada Regulation of Energy Drinks (Canadian Beverage Association)","url":"https://www.newswire.ca/news-releases/cba-statement-adoption-of-quebec-s-bill-9-ignores-science-based-health-canada-regulation-of-energy-drinks-and-will-not-serve-public-health-837889840.html","type":"advocacy"}],"commentary":[{"source":"Public-health experts (consulted at hearings)","stance":"support","quote":"Health experts backed the under-16 restriction, citing cardiac and other risks of high caffeine intake for adolescents, especially combined with medication.","url":"https://www.cbc.ca/news/canada/montreal/quebec-energy-drinks-ban-consultation-9.7229009"},{"source":"Canadian Beverage Association (CBA)","stance":"oppose","quote":"The CBA said the adoption of Bill 9 'ignores science-based Health Canada regulation of energy drinks and will not serve public health,' arguing federal rules already govern caffeine content.","url":"https://www.newswire.ca/news-releases/cba-statement-adoption-of-quebec-s-bill-9-ignores-science-based-health-canada-regulation-of-energy-drinks-and-will-not-serve-public-health-837889840.html"},{"source":"Family of Zachary Miron / Coroner (as reported)","stance":"support","quote":"The push followed the 2024 death of 15-year-old Zachary Miron; a coroner's report found the combination of his ADHD medication and caffeine likely caused a fatal arrhythmia.","url":"https://www.cbc.ca/news/canada/montreal/quebec-energy-drinks-teens-9.7224511"}]},"qc-bill-25":{"officialUrl":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-25-43-3.html","factCheck":"Verified: Bill 25 (An Act to increase public confidence in the justice system by modernizing judicial ethics and to implement certain recommendations of the committee on the remuneration of judges and justices of the peace for the 2023-2027 period) was tabled March 18, 2026 by Justice Minister Simon Jolin-Barrette and reinstated in the third session on May 6, 2026. It strengthens the Conseil de la magistrature with intermediate sanctions (suspension up to six months without pay, mandatory training/therapy), allows pursuing judges up to three years after retirement, requires faster public disclosure of decisions, adds non-lawyer/public members, and enacts judges' remuneration measures. Caveat against overstatement: as of mid-June 2026 it had been introduced and was under study but I could NOT confirm it received final adoption before the session ended June 12; like the related Jolin-Barrette constitution bill, several measures were at risk of dying on the order paper, so it should not be stated as enacted without confirmation.","sources":[{"title":"Bill 25 - Modernizing judicial ethics and judges'/JPs' remuneration 2023-2027 (National Assembly of Quebec)","url":"https://www.assnat.qc.ca/en/travaux-parlementaires/projets-loi/projet-loi-25-43-3.html","type":"official"},{"title":"Pour un traitement plus efficace et plus transparent des plaintes en matiere de deontologie judiciaire (Quebec government news release, Newswire)","url":"https://www.newswire.ca/fr/news-releases/pour-un-traitement-plus-efficace-et-plus-transparent-des-plaintes-en-matiere-de-deontologie-judiciaire-892714985.html","type":"official"},{"title":"Jolin-Barrette veut davantage de sanctions contre les juges (Radio-Canada)","url":"https://ici.radio-canada.ca/nouvelle/2240042/jolin-barrette-conseil-magistrature-juges-sanctions","type":"news"},{"title":"Le Barreau du Quebec salue le depot du projet de loi 25 (Barreau du Quebec)","url":"https://www.barreau.qc.ca/en/new/press-releases/barreau-salue-depot-projet-loi-25/","type":"legal"},{"title":"Projet de loi no 25 (Conseil de la magistrature du Quebec)","url":"https://conseildelamagistrature.qc.ca/article/projet-de-loi-no-25-loi-visant-a-accroitre-la-confiance-du-public-envers-le-systeme-de-justice-en-modernisant-la-deontologie-judiciaire-et-mettant-en-oeuvre-certaines-recommandations-du-comite-de-la-remuneration-des-juges-pour-la-periode-2023-2027","type":"official"}],"commentary":[{"source":"Simon Jolin-Barrette (Minister of Justice)","stance":"support","quote":"Jolin-Barrette argued judges need to face real consequences for misconduct, proposing suspensions without pay and replacing a judge's seat on the Conseil de la magistrature with an additional public representative to boost transparency.","url":"https://ici.radio-canada.ca/nouvelle/2240042/jolin-barrette-conseil-magistrature-juges-sanctions"},{"source":"Barreau du Quebec (Quebec Bar)","stance":"mixed","quote":"The Barreau welcomed the tabling of Bill 25 and its goal of more efficient, transparent handling of judicial-ethics complaints, while signalling it would scrutinize the details of the new sanctions and process.","url":"https://www.barreau.qc.ca/en/new/press-releases/barreau-salue-depot-projet-loi-25/"},{"source":"La Presse (opinion: 'Le projet de loi 25? D'accord, mais...')","stance":"mixed","quote":"Commentators agreed reform of judicial discipline was overdue - after years in which very few complaints against judges were upheld - but cautioned about preserving judicial independence and ensuring sanctions are meaningfully applied.","url":"https://www.lapresse.ca/dialogue/opinions/2026-03-24/deontologie-judiciaire/le-projet-de-loi-25-d-accord-mais.php"}]},"bc-bill-9":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov09-1","factCheck":"Verified: Bill 9 (Freedom of Information and Protection of Privacy Amendment Act, 2026), introduced Feb. 26, 2026 by Citizens' Services Minister Diana Gibson, received Royal Assent on May 28, 2026 (S.B.C. 2026, c. 19) after the Speaker broke a tie on the final session day; it changes the duty to respond from 'without delay' to 'without unreasonable delay,' adds grounds to disregard abusive/repetitive requests, permits applicant-consented timeline extensions, enables a 'connected services' data-sharing gateway (Connected Services BC), and creates new 'snooping' offences. Common misinformation to correct: the government clarified the bill does NOT introduce new FOI fees and does NOT shorten or remove statutory response timelines; the broad 'data sovereignty'/storing-information-outside-Canada change critics sometimes cite actually originated in the separate 2021 Bill 22, not this 2026 bill.","sources":[{"title":"Bill 9 – 2026: Freedom of Information and Protection of Privacy Amendment Act, 2026 (official text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov09-1","type":"official"},{"title":"Improving digital service delivery with FOIPPA amendments (BC Gov News)","url":"https://news.gov.bc.ca/releases/2026CITZ0001-000196","type":"official"},{"title":"Minister's statement about amendments to Bill 9 (BC Gov News)","url":"https://news.gov.bc.ca/releases/2026CITZ0004-000496","type":"official"},{"title":"2026 Bill 9 Weakens Access in BC (BC Freedom of Information and Privacy Association)","url":"https://fipa.bc.ca/2026-bill-9-weakens-access-in-bc","type":"advocacy"},{"title":"BC Privacy Law Updates: Bill 9 and FOIPPA Amendments 2026 (Lawson Lundell LLP)","url":"https://www.lawsonlundell.com/publication/changes-are-coming-to-bc-privacy-laws","type":"legal"},{"title":"Bill 9 (2026): Recalibrating Access, Discretion, and Delay Under FIPPA (Ng Ariss Fong)","url":"https://www.ngariss.com/our-professional-conduct-posts/bill-9-2026-recalibrating-access-discretion-and-delay-under-fippa/","type":"legal"}],"commentary":[{"source":"BC Freedom of Information and Privacy Association (Jason Woywada, Executive Director)","stance":"oppose","quote":"Access delays are often a symptom of recordkeeping failures. You cannot fix systemic information management problems by weakening public access rights.","url":"https://fipa.bc.ca/2026-bill-9-weakens-access-in-bc"},{"source":"BC Green Party (MLA Rob Botterell)","stance":"oppose","quote":"Criticized the bill for lacking 'guardrails' on how officials could refuse information requests, warning the new discretion to disregard 'abusive' requests is too broad.","url":"https://vicnews.com/2026/05/28/controversial-treaty-and-foi-bills-pass-on-last-day-of-b-c-legislative-session/"},{"source":"Government of B.C. (Diana Gibson, Minister of Citizens' Services)","stance":"support","quote":"We are happy to make these adjustments that provide more precision on the intent of the provisions outlined in the legislation; the bill does not change FOI response timelines, allow refusal of legitimate requests, or introduce new fees.","url":"https://news.gov.bc.ca/releases/2026CITZ0004-000496"},{"source":"Lawson Lundell LLP","stance":"mixed","quote":"The amendments recognize that public bodies are struggling under the weight of increasingly complex FOI requests, while raising questions about the breadth of new discretion to disregard requests.","url":"https://www.lawsonlundell.com/publication/changes-are-coming-to-bc-privacy-laws"}]},"bc-bill-16":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov16-1","factCheck":"Verified: Bill 16 (Miscellaneous Statutes Amendment Act, 2026), introduced April 1, 2026, received Royal Assent on May 21, 2026 (S.B.C. 2026, c. 15); it is an omnibus bill amending multiple statutes, including a 60-day deadline to apply for judicial review under the Judicial Review Procedure Act and, most controversially, an amendment to the Correction Act expressly authorizing correctional officers to use force to assist health-care providers administering involuntary treatment under the Mental Health Act. No notable misinformation found; the central dispute is about the substance and placement of the use-of-force provision in an omnibus bill rather than factual inaccuracy.","sources":[{"title":"Bill 16 – 2026: Miscellaneous Statutes Amendment Act, 2026 (official text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov16-1","type":"official"},{"title":"Modernizing enforcement, housing, justice tools (BC Gov News)","url":"https://news.gov.bc.ca/releases/2026AG0016-000360","type":"official"},{"title":"Bill 16: 2026 Miscellaneous Statutes Amendment Act — Expanding use of force in the Correction Act (Health Justice)","url":"https://www.healthjustice.ca/blog/bill16","type":"advocacy"},{"title":"Legislative Update Report No. 2026-11 (Osler, Hoskin & Harcourt LLP)","url":"https://www.osler.com/en/insights/updates/legislative-update-report-no-2026-11-le-bulletin-dactualites-legislatives/","type":"legal"}],"commentary":[{"source":"Health Justice (BC legal/health policy organization)","stance":"oppose","quote":"A shift of this magnitude requires deep transparency and accountability in a democratic society; expanding corrections officers' authority to use force to assist involuntary psychiatric treatment should not be buried in an omnibus bill and deserves standalone scrutiny.","url":"https://www.healthjustice.ca/blog/bill16"},{"source":"Government of B.C. (Ministry of Attorney General)","stance":"support","quote":"The amendments modernize justice and enforcement tools, including keeping judicial reviews fair, timely and affordable with a 60-day application deadline.","url":"https://news.gov.bc.ca/releases/2026AG0016-000360"},{"source":"Osler, Hoskin & Harcourt LLP","stance":"mixed","quote":"Notes Bill 16 received Royal Assent May 21, 2026 as Chapter 15 and spans amendments across numerous statutes, flagging the Correction Act use-of-force change as significant.","url":"https://www.osler.com/en/insights/updates/legislative-update-report-no-2026-11-le-bulletin-dactualites-legislatives/"}]},"bc-bill-15":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/gov15-3_43rd2nd","factCheck":"Verified: The 2026 Bill 15 is the Environmental Assessment Amendment Act, 2026, which passed Third Reading on April 16, 2026; it adds an 'issues resolution protocol' (technical/leadership tables) co-developed with First Nations, limits dispute resolution to earlier assessment stages, and—reflecting the Supreme Court of Canada's Desautel decision—provides that U.S.-based tribes are not 'participating Indigenous nations' for the protocol. Important correction: this 2026 Environmental Assessment Amendment Act must NOT be confused with the 2025 'Bill 15 – Infrastructure Projects Act' (a separate, earlier bill that received Royal Assent May 29, 2025 and gave Cabinet power to designate 'provincially significant' projects); much of the 'Bill 15 fast-tracking/regulatory-override' controversy circulating online refers to that 2025 infrastructure law, not the 2026 EA amendment.","sources":[{"title":"Bill 15 – 2026: Environmental Assessment Amendment Act, 2026 (official third-reading text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/gov15-3_43rd2nd","type":"official"},{"title":"Environmental Assessment Act (BC Gov News)","url":"https://news.gov.bc.ca/releases/2026ENV0016-000346","type":"official"},{"title":"B.C. Amends Environmental Assessment Act: New Dispute Resolution Processes and Limits to U.S. Tribes (Blake, Cassels & Graydon LLP)","url":"https://www.jdsupra.com/legalnews/b-c-amends-environmental-assessment-act-6188329/","type":"legal"},{"title":"B.C.'s controversial Bill 15, explained (The Narwhal)","url":"https://thenarwhal.ca/bc-bill-15-controversy-explained/","type":"news"},{"title":"Bill 14 and Bill 15: Does BC's Drive to Expedite Projects Put People and Planet at Risk? (West Coast Environmental Law)","url":"https://www.wcel.org/blog/bill-14-and-bill-15-does-bcs-drive-expedite-projects-put-people-and-planet-risk","type":"advocacy"}],"commentary":[{"source":"West Coast Environmental Law","stance":"oppose","quote":"Questions whether B.C.'s drive to expedite projects (Bills 14 and 15) puts people and planet at risk, warning that narrowing assessment scope and timelines can sideline climate, health and species effects and Indigenous consultation.","url":"https://www.wcel.org/blog/bill-14-and-bill-15-does-bcs-drive-expedite-projects-put-people-and-planet-risk"},{"source":"First Nations Leadership Council (Robert Phillips)","stance":"oppose","quote":"Reconciliation and economic growth are not incompatible, they go hand in hand. If the province chooses to neglect the former in a misguided attempt to advance the latter, it will quickly find itself mired in legal proceedings.","url":"https://thenarwhal.ca/bc-bill-15-controversy-explained/"},{"source":"Blake, Cassels & Graydon LLP","stance":"mixed","quote":"Notes the 2026 amendments add structured issue-resolution mechanisms and, consistent with the Desautel test, prevent U.S. tribes from being treated as participating Indigenous nations in the EA process.","url":"https://www.jdsupra.com/legalnews/b-c-amends-environmental-assessment-act-6188329/"}]},"bc-bill-8":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov08-3","factCheck":"Verified: Bill 8 (Civil Forfeiture Amendment Act, 2026), introduced Feb. 23, 2026 by Public Safety and Solicitor General Minister Nina Krieger, passed Third Reading on April 1, 2026; it expands the Civil Forfeiture Office's powers, allows default forfeiture orders where respondents fail to file, extends certain director decision timelines from 30 to 60 days, adds a rebuttable presumption of vehicle depreciation, and broadens information-sharing, aligning with Cullen Commission recommendations and a Budget 2026 commitment. No notable misinformation found; B.C. civil forfeiture is civil (not criminal), so—accurately—property can be pursued without a criminal charge or conviction, a point critics emphasize.","sources":[{"title":"Bill 8 – 2026: Civil Forfeiture Amendment Act, 2026 (official third-reading text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov08-3","type":"official"},{"title":"Streamlining government's response to organized crime (BC Gov News)","url":"https://news.gov.bc.ca/33391","type":"official"},{"title":"British Columbia's New Civil Forfeiture Rules [2026] (Mickelson, Whysall & Moore Law Group)","url":"https://www.criminallawyervancouver.com/blog/british-columbias-new-civil-forfeiture-rules/","type":"legal"}],"commentary":[{"source":"Government of B.C. (Nina Krieger, Minister of Public Safety and Solicitor General)","stance":"support","quote":"These changes will give law enforcement stronger tools to target criminal proceeds, disrupt organized crime and reinvest recovered funds into initiatives that support victims.","url":"https://news.gov.bc.ca/33391"},{"source":"Mickelson, Whysall & Moore Law Group (criminal defence firm)","stance":"oppose","quote":"While the government frames these changes as tools to combat organized crime and money laundering, the practical reality is a system that is now faster, broader, and more difficult to challenge — the balance has shifted further in favour of the state.","url":"https://www.criminallawyervancouver.com/blog/british-columbias-new-civil-forfeiture-rules/"}]},"bc-bill-11":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov11-1","factCheck":"Verified: Bill 11 (Residential Tenancy Amendment Act, 2026), sponsored by Housing and Municipal Affairs Minister Christine Boyle, amends the Residential Tenancy Act to more explicitly define supportive housing and create faster grounds for supportive-housing operators to end a tenancy (e.g., where a tenant or their guest possesses or is observed with a weapon) and to temporarily remove disruptive residents. As of mid-June 2026 it had advanced through second reading/committee but has not been confirmed to have received Royal Assent. No notable factual misinformation found; the dispute is over policy trade-offs—safety versus due-process and eviction protections for vulnerable tenants.","sources":[{"title":"Bill 11 – 2026: Residential Tenancy Amendment Act, 2026 (official text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov11-1","type":"official"},{"title":"Strengthening health and safety in supportive housing (BC Gov News)","url":"https://news.gov.bc.ca/releases/2026HMA0019-000214","type":"official"},{"title":"B.C.'s Bill 11 improves housing safety, but raises risks for tenants (Policy Options / IRPP)","url":"https://policyoptions.irpp.org/2026/03/bc-housing-risks/","type":"academic"},{"title":"Advocates urge Province to halt Bill 11, citing threats to tenant safety and rights (Surrey Now-Leader)","url":"https://surreynowleader.com/2026/03/27/advocates-urge-province-to-halt-bill-11-citing-threats-to-tenant-safety-and-rights/","type":"news"},{"title":"Inside the BC NDP's proposal to weaken tenant rights in supportive housing (The Mainlander)","url":"https://themainlander.com/2026/04/13/interviewpaulandmattsupportivehousing/","type":"advocacy"}],"commentary":[{"source":"Tenant advocates (Matt Tarasoff, The Mainlander interview)","stance":"oppose","quote":"This Bill takes away the normal process of getting a fair hearing and no more review, you're just kicked straight to the curb — vulnerable residents could be evicted over undefined 'weapons' or the actions of guests.","url":"https://themainlander.com/2026/04/13/interviewpaulandmattsupportivehousing/"},{"source":"Government of B.C. (Ministry of Housing and Municipal Affairs)","stance":"support","quote":"The amendments strengthen health and safety in supportive housing so operators can respond to weapons and serious safety risks while keeping buildings safe for residents and staff.","url":"https://news.gov.bc.ca/releases/2026HMA0019-000214"},{"source":"Policy Options (Institute for Research on Public Policy)","stance":"mixed","quote":"Bill 11 improves housing safety but raises risks for tenants; proportionality tools are needed so providers and adjudicators can navigate these issues with fairness and humanity.","url":"https://policyoptions.irpp.org/2026/03/bc-housing-risks/"}]},"bc-bill-13":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov13-1","factCheck":"Verified: Bill 13 (Safe Access to Places of Public Worship Act), introduced March 9, 2026 by Attorney General Niki Sharma, would create 20-metre 'access zones' around places of worship (mosques, synagogues, temples, gurdwaras, churches) where conduct that impedes access, disrupts activities, or threatens safety is prohibited, with police enforcement; it includes a sunset clause requiring reassessment in 2030 and is modelled on B.C.'s earlier hospital/school access-zone laws. No notable misinformation found; the bill restricts specified disruptive conduct within the zones rather than banning all expression, and civil-liberties critics dispute its breadth and effect on protest rights.","sources":[{"title":"Bill 13 – 2026: Safe Access to Places of Public Worship Act (official text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov13-1","type":"official"},{"title":"Protecting access to places of worship, schools (BC Gov News)","url":"https://news.gov.bc.ca/releases/2026PREM0013-000238","type":"official"},{"title":"Safe Access to Places of Public Worship Act (Province of British Columbia)","url":"https://www2.gov.bc.ca/gov/content/justice/about-bcs-justice-system/legislation-policy/resources/safe-access-places-public-worship-act","type":"official"},{"title":"B.C. tables legislation to expand protest restrictions near schools and places of worship (AM 1150 / Vista Radio)","url":"https://www.am1150.ca/82637/news/politics/b-c-tables-legislation-to-expand-protest-restrictions-near-schools-and-places-of-worship/","type":"news"}],"commentary":[{"source":"Premier David Eby","stance":"support","quote":"The ability for kids to learn and the ability for everyone to pray without harassment or intimidation is fundamental to who we are as Canadians and British Columbians.","url":"https://news.gov.bc.ca/releases/2026PREM0013-000238"},{"source":"Congregation Schara Tzedeck (Rabbi Andrew Rosenblatt) and other faith leaders","stance":"support","quote":"We thank the B.C. government for introducing this legislation; clear access measures provide a steady, predictable environment for those who gather to worship.","url":"https://news.gov.bc.ca/releases/2026PREM0013-000238"},{"source":"B.C. Civil Liberties Association","stance":"oppose","quote":"Places of worship, schools, or childcare centres are unfortunately not immune from engaging in behaviour that may spark legitimate political protest — restricting demonstrations in access zones raises serious Charter expression concerns.","url":"https://www.am1150.ca/82637/news/politics/b-c-tables-legislation-to-expand-protest-restrictions-near-schools-and-places-of-worship/"}]},"bc-bill-7":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov07-1","factCheck":"Verified: Bill 7 (Post-Secondary International Education (Designated Institutions) Act), introduced Feb. 19, 2026 by Post-Secondary Education and Future Skills Minister Jessie Sunner, puts B.C.'s Education Quality Assurance (EQA) designation into statute, makes designation a legal requirement to host international students on federal study permits, prohibits non-designated institutions from advertising/enrolling/delivering such programs, and creates inspection and enforcement powers. No notable misinformation found; the act regulates which institutions may host study-permit international students and does not, by itself, set provincial study-permit caps (those are set federally by IRCC).","sources":[{"title":"Bill 7 – 2026: Post-Secondary International Education (Designated Institutions) Act (official text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov07-1","type":"official"},{"title":"New legislation will strengthen oversight of international education (BC Gov News)","url":"https://news.gov.bc.ca/releases/2026PSFS0001-000173","type":"official"},{"title":"B.C. proposes legislation to strengthen oversight of designated international education institutions (Law360 Canada)","url":"https://www.law360.ca/ca/business/articles/2444313","type":"news"},{"title":"BC takes next steps in bid to stamp out exploitation in education (The PIE News)","url":"https://thepienews.com/bc-next-steps/","type":"news"}],"commentary":[{"source":"Government of B.C. (Jessie Sunner, Minister of Post-Secondary Education and Future Skills)","stance":"support","quote":"International students deserve the quality education they were promised; the act gives government tools to inspect designated institutions and hold bad actors accountable.","url":"https://news.gov.bc.ca/releases/2026PSFS0001-000173"},{"source":"Vancouver Island University (Carolyn Russell, VP Students)","stance":"support","quote":"It ensures there's a consistent experience for international students across the B.C. post-secondary education sector.","url":"https://thepienews.com/bc-next-steps/"},{"source":"The PIE News (international education sector outlet)","stance":"mixed","quote":"Reports broad sector support for putting EQA into law while noting compliance burdens and the need for clear standards on which institutions can apply and what they must demonstrate.","url":"https://thepienews.com/bc-next-steps/"}]},"bc-bill-5":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov05-1","factCheck":"Verified: Bill 5 (Trade Recognition Act), introduced February 2026 by Jobs and Economic Growth Minister Ravi Kahlon, makes permanent B.C.'s mutual-recognition framework (first rolled out temporarily under the Economic Stabilization (Tariff Response) Act / ESTRA Part 1), so that goods and services lawfully sold or supplied in another Canadian province can generally be sold or supplied in B.C., subject to exceptions, while preserving B.C.'s health, safety, environmental and consumer-protection standards. No notable misinformation found; the act addresses interprovincial trade and labour-mobility barriers and is distinct from the separate International Credentials Recognition Act (2024) for internationally trained professionals.","sources":[{"title":"Bill 5 – 2026: Trade Recognition Act (official text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov05-1","type":"official"},{"title":"Reinforcing B.C.'s leadership in interprovincial trade (BC Gov News)","url":"https://news.gov.bc.ca/releases/2026JEG0014-000166","type":"official"},{"title":"B.C. rolls out law to tackle interprovincial trade barriers (The Globe and Mail)","url":"https://www.theglobeandmail.com/canada/article-bc-introduces-law-interprovincial-trade-barriers/","type":"news"},{"title":"BC's Trade Recognition Act (Bill 5): permanent interprovincial recognition framework (Island Social Trends)","url":"https://islandsocialtrends.ca/bcs-trade-recognition-act-bill-5-permanent-interprovincial-recognition-framework/","type":"news"}],"commentary":[{"source":"Government of B.C. (Ravi Kahlon, Minister of Jobs and Economic Growth)","stance":"support","quote":"By moving to make mutual recognition permanent, we're helping businesses save time and money, while increasing choice and affordability for people throughout the province.","url":"https://news.gov.bc.ca/releases/2026JEG0014-000166"},{"source":"The Globe and Mail","stance":"mixed","quote":"Reports B.C.'s move to tackle interprovincial trade barriers through permanent mutual recognition, situating it within a national push to ease internal trade while noting carve-outs remain.","url":"https://www.theglobeandmail.com/canada/article-bc-introduces-law-interprovincial-trade-barriers/"},{"source":"Island Social Trends","stance":"support","quote":"Frames Bill 5 as a permanent interprovincial recognition framework that keeps the working elements of the temporary tariff-response measures while removing the expiry date.","url":"https://islandsocialtrends.ca/bcs-trade-recognition-act-bill-5-permanent-interprovincial-recognition-framework/"}]},"bc-bill-10":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov10-1","factCheck":"Verified: Bill 10 (Labour Statutes Amendment Act, 2026), introduced March 4, 2026, received Royal Assent on April 16, 2026 (S.B.C. 2026, c. 10), coming into force by regulation; it amends the Employment Standards Act and Temporary Foreign Worker Protection Act to let the Director of Employment Standards dismiss frivolous/settled/out-of-scope complaints, launch broader systemic investigations, and—a notable new requirement—generally require employers to deposit owed amounts before appealing a determination. No notable misinformation found; the changes are procedural reforms to the Employment Standards Branch process and do not repeal core substantive worker protections.","sources":[{"title":"Bill 10 – 2026: Labour Statutes Amendment Act, 2026 (official text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov10-1","type":"official"},{"title":"B.C. introduces Bill 10 to streamline employment standards complaints (DLA Piper)","url":"https://www.dlapiper.com/en-us/insights/publications/2026/03/bc-introduces-bill-10-to-streamline-employment-standards-complaints","type":"legal"},{"title":"Pay-to-Appeal: Proposed Changes to the BC Employment Standards Complaint and Appeal Process (McCarthy Tétrault)","url":"https://www.mccarthy.ca/en/insights/blogs/canadian-employer-advisor/pay-to-appeal-proposed-changes-to-the-bc-employment-standards-complaint-and-appeal-process","type":"legal"},{"title":"BC Bill 10-2026: Amendments Aimed at Improving Efficiency at the BC Employment Standards Branch (Alexander Holburn Beaudin + Lang LLP)","url":"https://www.ahbl.ca/bc-bill-10-2026-amendments-aimed-at-improving-efficiency-at-the-bc-employment-standards-branch/","type":"legal"}],"commentary":[{"source":"DLA Piper","stance":"mixed","quote":"The amendments aim to speed up complaint resolution and deal with current backlogs, bringing BC in line with other Canadian jurisdictions while preserving the substantive protections both Acts provide to workers — though employers must now deposit owed amounts before appealing.","url":"https://www.dlapiper.com/en-us/insights/publications/2026/03/bc-introduces-bill-10-to-streamline-employment-standards-complaints"},{"source":"McCarthy Tétrault","stance":"mixed","quote":"Characterizes the new requirement to pay owed amounts before appealing as a 'pay-to-appeal' change that raises practical and financial considerations for employers contesting determinations.","url":"https://www.mccarthy.ca/en/insights/blogs/canadian-employer-advisor/pay-to-appeal-proposed-changes-to-the-bc-employment-standards-complaint-and-appeal-process"},{"source":"Alexander Holburn Beaudin + Lang LLP","stance":"mixed","quote":"Describes Bill 10 as restructuring the complaint process to resolve straightforward matters faster and help workers recover unpaid wages sooner, while giving the Director greater latitude to refuse or pause investigations.","url":"https://www.ahbl.ca/bc-bill-10-2026-amendments-aimed-at-improving-efficiency-at-the-bc-employment-standards-branch/"}]},"bc-bill-20":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov20-1","factCheck":"Verified: Bill 20 (K'ómoks Treaty Act), introduced April 14, 2026 by Indigenous Relations and Reconciliation Minister Spencer Chandra Herbert, passed Third Reading May 28, 2026 and received Royal Assent on May 28, 2026 (S.B.C. 2026, c. 18), ratifying B.C.'s side of the K'ómoks treaty; treaty provisions come into force later by regulation and the treaty still requires federal ratification. Important correction: its companion, Bill 21 (Kitselas Treaty Act), did NOT pass in the spring session—it was deferred to fall 2026—so reports implying both treaties were finalized together are inaccurate. Several neighbouring First Nations (e.g., Wei Wai Kum) oppose over overlapping-territory claims.","sources":[{"title":"Bill 20 – 2026: K'ómoks Treaty Act (official text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov20-1","type":"official"},{"title":"K'ómoks Treaty Receives Royal Assent in the BC Legislature (BC Treaty Commission, via Newswire)","url":"https://www.newswire.ca/news-releases/k-omoks-treaty-receives-royal-assent-in-the-bc-legislature-890041452.html","type":"official"},{"title":"First Nations opposed to K'ómoks, Kitselas treaty bills prepared for litigation: UBCIC (CBC News)","url":"https://www.cbc.ca/news/canada/british-columbia/wei-wai-kum-first-nation-nine-allied-tribes-lax-kwalaams-band-bill-20-bill-21k-omoks-kitselas-treaties-9.7180145","type":"news"},{"title":"First Nations call on BC to pause treaty bills (UBCIC, via Newswire)","url":"https://www.newswire.ca/news-releases/first-nations-call-on-bc-to-pause-treaty-bills-823139894.html","type":"advocacy"},{"title":"BC Green Caucus statement on the Second Reading of the K'ómoks Treaty Act","url":"https://bcgreencaucus.ca/bc-green-caucus-statement-on-the-second-reading-of-the-komoks-treaty-act/","type":"advocacy"}],"commentary":[{"source":"K'ómoks First Nation (Chief Nicole Rempel)","stance":"support","quote":"This is an historic moment for our Nation and for all those who have worked tirelessly over many years to advance this Treaty.","url":"https://cowichanvalleycitizen.com/2026/05/29/kmoks-first-nation-treaty-passes-third-reading-in-b-c-legislature/"},{"source":"Union of BC Indian Chiefs (Grand Chief Stewart Phillip)","stance":"oppose","quote":"Reconciliation cannot be achieved through incomplete or unilateral processes. Moving forward without resolving shared territory and overlap issues risks undermining relationships between Nations and creating long-term uncertainty.","url":"https://www.newswire.ca/news-releases/first-nations-call-on-bc-to-pause-treaty-bills-823139894.html"},{"source":"Wei Wai Kum First Nation and allied nations (per CBC)","stance":"oppose","quote":"Warn they are prepared to go to court, saying the K'ómoks treaty claims roughly 80 per cent of Wei Wai Kum territory and the bills proceeded without resolving overlapping claims.","url":"https://www.cbc.ca/news/canada/british-columbia/wei-wai-kum-first-nation-nine-allied-tribes-lax-kwalaams-band-bill-20-bill-21k-omoks-kitselas-treaties-9.7180145"}]},"bc-bill-14":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov14-1","factCheck":"Verified: Bill 14 (Forests Statutes Amendment Act, 2026), introduced March 30, 2026, received Royal Assent on May 21, 2026 (S.B.C. 2026, c. 14); it amends the Forest Act and Forest and Range Practices Act to let BC Timber Sales offer new licences for activities such as commercial thinning, salvage of wildfire/windstorm/insect-damaged timber, and wildfire-risk reduction, and to manage licences across the full stewardship cycle. No notable misinformation found; the government projects added fibre supply, while conservation groups warn the changes lack explicit safeguards for at-risk old-growth—an argument about adequacy of protections rather than a factual error.","sources":[{"title":"Bill 14 – 2026: Forests Statutes Amendment Act, 2026 (official text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov14-1","type":"official"},{"title":"Legislative Update Report No. 2026-11 (Osler, Hoskin & Harcourt LLP)","url":"https://www.osler.com/en/insights/updates/legislative-update-report-no-2026-11-le-bulletin-dactualites-legislatives/","type":"legal"},{"title":"Advocates warn proposed legislation changes could put BC's old-growth forests at risk (Ancient Forest Alliance)","url":"https://ancientforestalliance.org/advocates-warn-proposed-legislation-changes-could-put-bcs-old-growth-forests-at-risk/","type":"advocacy"},{"title":"Bill 14 and Bill 15: Does BC's Drive to Expedite Projects Put People and Planet at Risk? (West Coast Environmental Law)","url":"https://www.wcel.org/blog/bill-14-and-bill-15-does-bcs-drive-expedite-projects-put-people-and-planet-risk","type":"advocacy"}],"commentary":[{"source":"Ancient Forest Alliance (TJ Watt, campaigner)","stance":"oppose","quote":"Simply ramping up the rate of logging by BC Timber Sales without also taking proactive steps to ensure at-risk old-growth forests are protected is a recipe for disaster.","url":"https://ancientforestalliance.org/advocates-warn-proposed-legislation-changes-could-put-bcs-old-growth-forests-at-risk/"},{"source":"Government of B.C. (Ministry of Forests)","stance":"support","quote":"The amendments give BC Timber Sales a broader range of fibre-generating and stewardship activities — commercial thinning, salvage of damaged trees and wildfire-risk reduction — to support forestry jobs and a more reliable fibre supply.","url":"https://www.osler.com/en/insights/updates/legislative-update-report-no-2026-11-le-bulletin-dactualites-legislatives/"},{"source":"West Coast Environmental Law","stance":"oppose","quote":"Groups Bills 14 and 15 as part of a push to expedite resource and infrastructure activity that risks weakening environmental and Indigenous-rights safeguards.","url":"https://www.wcel.org/blog/bill-14-and-bill-15-does-bcs-drive-expedite-projects-put-people-and-planet-risk"}]},"bc-bill-12":{"officialUrl":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov12-1","factCheck":"Verified: Bill 12 (Safe Access to Schools Amendment Act, 2026), introduced March 9, 2026 by Attorney General Niki Sharma, amends the 2024 Safe Access to Schools Act to push its sunset/repeal date from July 1, 2026 to July 1, 2028, extending the existing 20-metre school 'access zones' that prohibit specified disruptive conduct. No notable misinformation found; the bill extends and continues an existing law rather than creating new zones, and the government cites 40-plus protest disruptions at K-12 schools since 2023 as justification.","sources":[{"title":"Bill 12 – 2026: Safe Access to Schools Amendment Act, 2026 (official text)","url":"https://www.bclaws.gov.bc.ca/civix/document/id/bills/billscurrent/2nd43rd:gov12-1","type":"official"},{"title":"Protecting access to places of worship, schools (BC Gov News)","url":"https://news.gov.bc.ca/releases/2026PREM0013-000238","type":"official"},{"title":"B.C. introduces bills to restrict protest rights near schools, religious institutions (Black Press / Victoria News)","url":"https://vicnews.com/2026/03/09/b-c-introduces-bills-to-restrict-protest-rights-near-schools-religious-institutions/","type":"news"},{"title":"B.C. tables legislation to expand protest restrictions near schools and places of worship (AM 1150 / Vista Radio)","url":"https://www.am1150.ca/82637/news/politics/b-c-tables-legislation-to-expand-protest-restrictions-near-schools-and-places-of-worship/","type":"news"}],"commentary":[{"source":"Attorney General Niki Sharma","stance":"support","quote":"These laws would help ensure students, educators and faith communities can access these spaces feeling safe, respected and welcome.","url":"https://news.gov.bc.ca/releases/2026PREM0013-000238"},{"source":"B.C. Civil Liberties Association","stance":"oppose","quote":"Has raised concerns that broad access-zone restrictions near schools can capture legitimate political protest and chill Charter-protected expression.","url":"https://www.am1150.ca/82637/news/politics/b-c-tables-legislation-to-expand-protest-restrictions-near-schools-and-places-of-worship/"},{"source":"Premier David Eby","stance":"support","quote":"Pointed to recent 'disturbing incidents' and said the ability for kids to learn without harassment or intimidation is fundamental, defending extension of the school access-zone law.","url":"https://vicnews.com/2026/03/09/b-c-introduces-bills-to-restrict-protest-rights-near-schools-religious-institutions/"}]},"ab-bill-18":{"officialUrl":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-018.pdf","factCheck":"Verified: Bill 18, the Safeguards for Last Resort Termination of Life Act, was introduced March 18, 2026 and passed third reading April 22, 2026; it limits MAID to 'Track 1' cases where natural death is reasonably foreseeable (interpreted as likely within 12 months), prohibits 'Track 2' MAID, and bars MAID for mature minors, mental-illness-as-sole-condition, and advance requests, while designating MAID-free facilities. Common misinformation: the bill does not 'ban MAID' in Alberta outright, and because MAID eligibility is set by the federal Criminal Code, legal commentators note the province's authority to restrict it is contested and the law invites a Charter challenge under Carter/Truchon rather than being settled law.","sources":[{"title":"Bill 18 official text (31st Legislature, 2nd Session)","url":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-018.pdf","type":"official"},{"title":"Protecting vulnerable Albertans seeking MAID (Government of Alberta)","url":"https://www.alberta.ca/protecting-vulnerable-albertans-seeking-maid","type":"official"},{"title":"Alberta bill would limit MAID to patients facing 'reasonably foreseeable' death (CBC News)","url":"https://www.cbc.ca/news/canada/edmonton/alberta-medical-assistance-in-dying-limits-legislation-9.7133788","type":"news"},{"title":"Bill 18: Alberta Pushes Back Against MAID Expansion (LawNow Magazine)","url":"https://www.lawnow.org/bill-18-alberta-pushes-back-against-maid-expansion/","type":"legal"},{"title":"Alberta's Proposed MAID Restrictions Threaten Patient Rights and Autonomy (CCLA)","url":"https://ccla.org/press-release/albertas-proposed-maid-restrictions-threaten-patient-rights-and-autonomy/","type":"advocacy"},{"title":"New Alberta legislation to restrict MAID access (Dying With Dignity Canada)","url":"https://www.dyingwithdignity.ca/advocacy/new-alberta-legislation-to-restrict-maid-access/","type":"advocacy"}],"commentary":[{"source":"Canadian Civil Liberties Association (CCLA)","stance":"oppose","quote":"Urges the government to withdraw Bill 18, warning it 'as currently drafted invites constitutional challenge and will prolong the suffering of those it purports to protect,' undermining the Charter-protected rights affirmed in Carter v. Canada.","url":"https://ccla.org/press-release/albertas-proposed-maid-restrictions-threaten-patient-rights-and-autonomy/"},{"source":"Dying With Dignity Canada","stance":"oppose","quote":"Argues the bill would strip MAID access from many suffering Albertans and that restricting clinicians' ability to discuss MAID could leave patients without full information about their legal options; also notes MAID eligibility is governed by federal law.","url":"https://www.dyingwithdignity.ca/advocacy/new-alberta-legislation-to-restrict-maid-access/"},{"source":"Inclusion Alberta","stance":"support","quote":"CEO Trish Bowman called Bill 18 'an important step,' welcoming the end of Track 2 MAID and arguing it is discriminatory to offer assisted death to people with disabilities while failing to provide them adequate supports.","url":"https://inclusionalberta.org/connections/media-release-inclusion-alberta-welcomes-passage-of-bill-18-as-a-critical-provincial-step-in-protecting-the-rights-and-lives-of-persons-with-disabilities/"},{"source":"Evangelical Fellowship of Canada / CCCC","stance":"support","quote":"Faith-based legal commentators describe Bill 18 as proposing 'important safeguards' to the MAID regime, supporting conscience protections and MAID-free facilities.","url":"https://www.cccc.org/news_blogs/legal/2026/03/30/albertas-bill-18-proposes-important-safeguards-to-maid-regime/"}]},"ab-bill-25":{"officialUrl":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-025.pdf","factCheck":"Verified: Bill 25, An Act to Remove Politics and Ideology from Classrooms and Amend the Education Act, 2026, was introduced March 31, 2026 by Education Minister Demetrios Nicolaides; it requires teachers/boards to be 'neutral' and 'impartial,' restricts which flags may be displayed in schools to the Alberta and Canada flags (with ministerial exemptions), mandates the national anthem at least weekly, and adds ministerial oversight of superintendent contracts, with most provisions to take effect on proclamation (anticipated September 1, 2026). Common misinformation: the statute text does not name 'Pride flags' specifically — the flag rules are framed around government-authorized flags, and critics infer Pride/other identity flags would be excluded absent a ministerial exemption.","sources":[{"title":"Bill 25 official text (31st Legislature, 2nd Session)","url":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-025.pdf","type":"official"},{"title":"Removing politics and ideology from Alberta classrooms (Government of Alberta)","url":"https://www.alberta.ca/removing-politics-and-ideology-from-alberta-classrooms","type":"official"},{"title":"Alberta government says new bill intended to remove politics, ideology from schools (CBC News)","url":"https://www.cbc.ca/news/canada/edmonton/alberta-education-bill-ideology-politics-classroom-9.7148982","type":"news"},{"title":"Proposed political neutrality legislation offensive to Alberta teachers, ATA says (CBC News)","url":"https://www.cbc.ca/news/canada/edmonton/teachers-reaction-alberta-neutrality-bill-9.7150625","type":"news"},{"title":"ATA raises concerns about Bill 25's scope, impacts (Alberta Teachers' Association)","url":"https://teachers.ab.ca/news/ata-raises-concerns-about-bill-25s-scope-impacts","type":"advocacy"},{"title":"Alberta Education Bill Entrenches Censorship in Schools (CCLA)","url":"https://ccla.org/press-release/alberta-education-bill-entrenches-censorship-in-schools/","type":"advocacy"}],"commentary":[{"source":"Alberta Teachers' Association (ATA)","stance":"oppose","quote":"Calls the bill government overreach, warning that 'whether it's a francophone, Metis, Pride or other flag, local schools should be free to reflect their communities without unnecessary political control,' and that teachers are already bound by professional standards and should not be left to interpret vague legislation.","url":"https://teachers.ab.ca/news/ata-raises-concerns-about-bill-25s-scope-impacts"},{"source":"Canadian Civil Liberties Association (CCLA)","stance":"oppose","quote":"'When governments label certain topics, books or symbols as ideological, the result is not neutrality — it is censorship.'","url":"https://ccla.org/press-release/alberta-education-bill-entrenches-censorship-in-schools/"},{"source":"Government of Alberta (Minister Demetrios Nicolaides)","stance":"support","quote":"Says the legislation removes politics and ideology from classrooms, requiring neutrality and impartiality so schools focus on academics, student safety and respect for diverse viewpoints.","url":"https://www.alberta.ca/removing-politics-and-ideology-from-alberta-classrooms"},{"source":"Calgary Board of Education / Alberta School Boards Association","stance":"mixed","quote":"School-board bodies responded with concern about reduced local autonomy and ministerial oversight of superintendent contracts while seeking clarity on implementation.","url":"https://www.asba.ab.ca/asba-statement-bill-25"}]},"ab-bill-28":{"officialUrl":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-028.pdf","factCheck":"Verified: Bill 28, the Municipal Affairs and Housing Statutes Amendment Act, 2026, is an omnibus bill amending the Municipal Government Act, Housing Act and Libraries Act; it passed third reading May 13, 2026 (46-38) and received Royal Assent May 14, 2026. The Libraries Act changes authorize regulations restricting access/borrowing by age (the government's stated aim being to keep sexually explicit visual material away from children 15 and under), expand provincial inspection powers, and let the minister make orders after an inspector's report. Common misinformation: the bill itself does not 'ban books' — it enables age-based access restrictions and physical separation of certain materials via regulation; library/civil-liberties groups characterize this as functional censorship, but outright removal is not what the statute prescribes.","sources":[{"title":"Bill 28 official text (31st Legislature, 2nd Session)","url":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-028.pdf","type":"official"},{"title":"Modernizing municipal legislation across the province (Government of Alberta)","url":"https://www.alberta.ca/modernizing-municipal-legislation-across-the-province","type":"official"},{"title":"Bill 28 Receives Royal Assent (Rural Municipalities of Alberta)","url":"https://rmalberta.com/news/bill-28-receives-royal-assent/","type":"advocacy"},{"title":"Alberta's access restrictions threaten privacy and democratic role of libraries, critics say (CBC News)","url":"https://www.cbc.ca/news/canada/edmonton/alta-libraries-restrictions-privacy-9.7161614","type":"news"},{"title":"Barriers to books is 'censorship' says Library Association of Alberta (Red Deer Advocate)","url":"https://reddeeradvocate.com/2026/04/08/barriers-to-books-is-censorship-says-library-association-of-alberta-about-provinces-plan/","type":"news"},{"title":"Bill 28: ABmunis' analysis now available (Alberta Municipalities)","url":"https://www.abmunis.ca/news/bill-28-abmunis-analysis-now-available","type":"advocacy"}],"commentary":[{"source":"Library Association of Alberta / Coalition of Alberta Public Libraries","stance":"oppose","quote":"Calls restricting access to public library materials censorship 'regardless of whether these materials remain physically in library spaces,' warns of privacy and operational costs, and notes none of the 324 member library services were consulted.","url":"https://reddeeradvocate.com/2026/04/08/barriers-to-books-is-censorship-says-library-association-of-alberta-about-provinces-plan/"},{"source":"CUPE Alberta","stance":"oppose","quote":"Slams the library legislation as 'costly, unworkable and politically motivated,' arguing it downloads unfunded staffing and space requirements onto municipalities.","url":"https://secure.businesswire.com/news/home/20260402717591/en/CUPE-Alberta-slams-new-library-legislation-as-costly-unworkable-and-politically-motivated"},{"source":"Alberta Municipalities (ABmunis)","stance":"mixed","quote":"Its analysis warns Bill 28 reduces municipal autonomy over local planning and governance and adds new implementation costs while constraining limited revenue tools.","url":"https://www.abmunis.ca/news/bill-28-abmunis-analysis-now-available"},{"source":"Government of Alberta (Minister Dan Williams)","stance":"support","quote":"Says the Libraries Act changes ensure children 15 and under cannot independently access visual depictions of sexual acts, with such material controlled by staff or kept in separate areas.","url":"https://www.cbc.ca/news/canada/edmonton/alberta-public-library-changes-9.7151744"}]},"ab-bill-29":{"officialUrl":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-029.pdf","factCheck":"Verified: Bill 29, the Health Statutes Amendment Act, 2026, was introduced April 14, 2026 by Primary and Preventative Health Services Minister Adriana LaGrange and has passed third reading; it amends the Alberta Health Care Insurance Act to lay groundwork for accessing certain privately paid preventative diagnostic tests without a provider referral, and amends the Pharmacy and Drug Act to let authorized prescribers keep a limited supply of certain addiction-treatment medications for urgent use. Common misinformation: the bill does not itself list which tests will be self-referable or privatize the public system — those specifics are deferred to regulations expected in fall 2026; critics frame it as enabling two-tier care, while the government frames it as expanding access.","sources":[{"title":"Bill 29 official text (31st Legislature, 2nd Session)","url":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-029.pdf","type":"official"},{"title":"Expanding health care access for Albertans (Government of Alberta)","url":"https://www.alberta.ca/expanding-health-care-access-for-albertans","type":"official"},{"title":"Alberta moves to allow private diagnostic tests without a doctor's referral (CBC News)","url":"https://www.cbc.ca/news/canada/edmonton/alberta-allow-private-diagnostic-tests-without-doctors-note-9.7162141","type":"news"},{"title":"Greater access to private medical testing in Alberta under proposed legislation (Global News)","url":"https://globalnews.ca/news/11799691/alberta-private-medical-testing-bill-29/","type":"news"},{"title":"Statement from HSAA on Government of Alberta's Bill 29 (Health Sciences Association of Alberta)","url":"https://hsaa.ca/post/statement-hsaa-government-albertas-bill-29","type":"advocacy"},{"title":"The Alberta government legislates two-tier health care, again (Canadian Centre for Policy Alternatives)","url":"https://www.policyalternatives.ca/news-research/the-alberta-government-legislates-two-tier-health-care-again/","type":"academic"}],"commentary":[{"source":"Friends of Medicare (Chris Gallaway)","stance":"oppose","quote":"Calls Bill 29 'legislated queue jumping that further entrenches the government's plan to bring in two-tier American style health care in Alberta,' noting it is the third Health Statutes Amendment Act in under a year.","url":"https://www.policyalternatives.ca/news-research/the-alberta-government-legislates-two-tier-health-care-again/"},{"source":"Health Sciences Association of Alberta (Mike Parker)","stance":"mixed","quote":"Supports improving access to care but says the bill 'leaves significant unanswered questions' about impacts on wait times, which tests will be covered, and who pays.","url":"https://hsaa.ca/post/statement-hsaa-government-albertas-bill-29"},{"source":"Government of Alberta (Minister Adriana LaGrange)","stance":"support","quote":"Frames the bill as expanding health-care access by letting Albertans obtain certain preventative tests without a referral and improving urgent access to addiction-treatment medications.","url":"https://www.alberta.ca/expanding-health-care-access-for-albertans"},{"source":"Canadian Centre for Policy Alternatives (CCPA)","stance":"oppose","quote":"Argues the bill creates a legal framework encouraging for-profit imaging facilities to let wealthier patients pay to be diagnosed ahead of others on the public wait list.","url":"https://www.policyalternatives.ca/news-research/the-alberta-government-legislates-two-tier-health-care-again/"}]},"ab-bill-26":{"officialUrl":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-026.pdf","factCheck":"Verified: Bill 26, the Immigration Oversight Act, was introduced April 1, 2026 and creates a provincial framework requiring employers to register before accessing federal temporary-foreign-worker programs (e.g., before obtaining a Labour Market Impact Assessment), licenses immigration consultants and foreign-worker recruiters, sets prohibited practices, and adds enforcement tools (fines, suspensions, bans). Common misinformation: this is not a provincial 'takeover' of immigration that overrides Ottawa — immigration is a concurrent power under s.95 of the Constitution Act, 1867, so provincial rules operate only insofar as they are not repugnant to federal law; the framework adds provincial registration/licensing on top of the federal system rather than replacing it.","sources":[{"title":"Bill 26 official text (31st Legislature, 2nd Session)","url":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-026.pdf","type":"official"},{"title":"Strengthening immigration oversight (Government of Alberta)","url":"https://www.alberta.ca/strengthening-immigration-oversight","type":"official"},{"title":"Alberta introduces Bill 26: Immigration Oversight Act (EY Tax Alert)","url":"https://www.ey.com/en_gl/technical/tax-alerts/alberta-introduces-bill-26-immigration-oversight-act","type":"legal"},{"title":"Canada: New Immigration Oversight Framework Proposed in Alberta (Fragomen)","url":"https://www.fragomen.com/insights/canadanew-immigration-oversight-framework-proposed-in-alberta.html","type":"legal"},{"title":"Alberta employers warn of red tape with proposed immigration changes (Human Resources Director)","url":"https://www.hcamag.com/ca/specialization/recruitment/alberta-employers-warn-of-red-tape-with-proposed-immigration-changes/571399","type":"news"},{"title":"Oversight or Overreach? Examining Alberta's New Immigration Oversight Act (Alberta Counsel)","url":"https://www.albertacounselnews.com/thenews/fcv1uxnu1wi8vlbfzeyvcoe5g01eus-wpayf-8zwsl-l298w-3t2c5-5g8de-ljmct-h4twt-m83x9-9p56g","type":"legal"}],"commentary":[{"source":"Canadian Federation of Independent Business (CFIB)","stance":"oppose","quote":"'This does not look like red tape reduction. This looks like duplication, more burdensome paperwork on the backs of employers who are just trying to survive, employ Albertans and support the economy.'","url":"https://www.hcamag.com/ca/specialization/recruitment/alberta-employers-warn-of-red-tape-with-proposed-immigration-changes/571399"},{"source":"Government of Alberta","stance":"support","quote":"Says Bill 26 gives the province more oversight of immigration, increases transparency, and reduces the mistreatment of newcomers through registration, licensing and enforcement tools.","url":"https://www.alberta.ca/strengthening-immigration-oversight"},{"source":"Fragomen (immigration law firm)","stance":"mixed","quote":"Analyzes the framework as a significant new layer of provincial registration and licensing obligations for employers, recruiters and consultants, advising affected parties to prepare for compliance.","url":"https://www.fragomen.com/insights/canadanew-immigration-oversight-framework-proposed-in-alberta.html"},{"source":"Alberta Counsel","stance":"mixed","quote":"In 'Oversight or Overreach?' notes the recurring jurisdiction question but explains immigration is constitutionally concurrent under s.95, so the bill is defensible provided it does not conflict with federal law.","url":"https://www.albertacounselnews.com/thenews/fcv1uxnu1wi8vlbfzeyvcoe5g01eus-wpayf-8zwsl-l298w-3t2c5-5g8de-ljmct-h4twt-m83x9-9p56g"}]},"ab-bill-30":{"officialUrl":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-030.pdf","factCheck":"Verified: Bill 30, the Expedited 120-Day Approvals Act, 2026, was tabled April 14, 2026 and has completed three readings; it lets cabinet designate 'qualified' major projects (generally requiring $250 million or more in capital investment) for a 120-day regulatory approval timeline, with implementing regulations expected in late 2026/early 2027. Common misinformation: the bill does not eliminate or bypass environmental impact assessment or Indigenous consultation — applicants must show those processes are at an appropriately advanced stage to qualify; however, legal/environmental critics caution consultation may still be ongoing when the 120-day clock starts, raising adequacy concerns.","sources":[{"title":"Bill 30 official text (31st Legislature, 2nd Session)","url":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-030.pdf","type":"official"},{"title":"Accelerating major project approvals (Government of Alberta)","url":"https://www.alberta.ca/accelerating-major-project-approvals","type":"official"},{"title":"Alberta government introduces 120-day approvals for major energy projects (CBC News)","url":"https://www.cbc.ca/news/canada/edmonton/alberta-government-120-day-approvals-major-energy-projects-9.7163707","type":"news"},{"title":"Bill 30, Expedited Project Approvals: Proponents Should Look Before They Leap (ABlawg, University of Calgary)","url":"https://ablawg.ca/2026/04/24/bill-30-expedited-project-approvals-proponents-should-look-before-they-leap/","type":"academic"},{"title":"Bill 30: Alberta's Expedited 120-Day Approvals Act, 2026 - What it Means for the Energy Sector (McCarthy Tetrault)","url":"https://www.mccarthy.ca/en/insights/blogs/canadian-energy-perspectives/bill-30-alberta-s-expedited-120-day-approvals-act-2026-what-it-means-for-the-energy-sector","type":"legal"},{"title":"Bill 30: Expedited 120-Day Approvals Act (Environmental Law Centre)","url":"https://elc.ab.ca/post-library/bill-30-expedited-120-day-approvals-act-bill-30-pits-regulatory-efficiency-against-trust-and-effectiveness-in-decision-making/","type":"advocacy"}],"commentary":[{"source":"Environmental Law Centre (ELC)","stance":"oppose","quote":"Warns the compressed timeline pits efficiency against sound decisions: 'Curtailing timelines and condensing the process inherently marginalizes substantive considerations, engagement, and deliberation, to the detriment of making the best decisions feasible.'","url":"https://elc.ab.ca/post-library/bill-30-expedited-120-day-approvals-act-bill-30-pits-regulatory-efficiency-against-trust-and-effectiveness-in-decision-making/"},{"source":"Government of Alberta (Minister Brian Jean)","stance":"support","quote":"Says faster approvals are needed to compete for investment, citing roughly $12 billion in energy capital lost to the U.S. in the past year due to uncertain and inefficient approval processes.","url":"https://www.alberta.ca/accelerating-major-project-approvals"},{"source":"ABlawg (University of Calgary Faculty of Law)","stance":"mixed","quote":"Cautions that proponents 'should look before they leap,' noting the expedited stream carries legal risk and consultation may still be ongoing when the 120-day clock begins.","url":"https://ablawg.ca/2026/04/24/bill-30-expedited-project-approvals-proponents-should-look-before-they-leap/"},{"source":"McCarthy Tetrault (energy law firm)","stance":"mixed","quote":"Describes the bill as a significant potential overhaul for energy developers that maintains environmental and Indigenous processes but leaves key details to forthcoming regulations.","url":"https://www.mccarthy.ca/en/insights/blogs/canadian-energy-perspectives/bill-30-alberta-s-expedited-120-day-approvals-act-2026-what-it-means-for-the-energy-sector"}]},"ab-bill-15":{"officialUrl":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-015.pdf","factCheck":"Verified: Bill 15, the Public Safety and Emergency Services Statutes Amendment Act, 2026, was introduced February 24, 2026 and received Royal Assent April 16, 2026; it enables Alberta Sheriffs to transition into the Alberta Sheriffs Police Service (ASPS), an independent Crown corporation overseen by a civilian board, creates a pathway for eligible sheriff peace officers to become police officers (subject to training/qualification), protects existing staff jobs/terms, and affirms a right to an independent association for collective bargaining. Common misinformation: the ASPS is a standalone provincial police service, not a replacement of the RCMP by legislative fiat — municipalities are not compelled by Bill 15 to switch from the RCMP, though critics (including the National Police Federation) view it as laying groundwork toward a provincial police force.","sources":[{"title":"Bill 15 official text (31st Legislature, 2nd Session)","url":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-015.pdf","type":"official"},{"title":"Building a modern police service (Government of Alberta)","url":"https://www.alberta.ca/building-a-modern-police-service","type":"official"},{"title":"Alberta police force bill getting mixed reaction from communities, unions (CBC News)","url":"https://www.cbc.ca/news/canada/calgary/alberta-police-agency-sheriffs-bill-reactions-1.7144639","type":"news"},{"title":"Alberta Moves To Transition Sheriffs Into New Independent Police Service (Blue Line)","url":"https://www.blueline.ca/alberta-moves-to-transition-sheriffs-into-new-independent-police-service/","type":"news"},{"title":"NDP questions training, price tag of proposed sheriffs police service (My Lethbridge Now)","url":"https://www.mylethbridgenow.com/60633/news/provincial/ndp-questions-training-price-tag-of-proposed-sheriffs-police-service/","type":"news"},{"title":"Government of Alberta Introduces Bill 15 (Rural Municipalities of Alberta)","url":"https://rmalberta.com/news/government-of-alberta-introduces-bill-15/","type":"advocacy"}],"commentary":[{"source":"Alberta NDP (Justice critic David Shepherd)","stance":"oppose","quote":"Questions the cost and training, saying it is 'hard to believe' an ASPS could serve communities more cheaply than the RCMP and asking whether six weeks of training is enough, accusing the government of leaving 'Albertans in an information vacuum.'","url":"https://www.mylethbridgenow.com/60633/news/provincial/ndp-questions-training-price-tag-of-proposed-sheriffs-police-service/"},{"source":"National Police Federation","stance":"oppose","quote":"Says it is 'deeply concerned and perplexed' that Alberta is building a new independent police agency and that its members are caught in a politicized debate over policing.","url":"https://www.cbc.ca/news/canada/calgary/alberta-police-agency-sheriffs-bill-reactions-1.7144639"},{"source":"Government of Alberta (Public Safety Minister Mike Ellis)","stance":"support","quote":"Says the bill modernizes policing by transitioning sheriffs into the ASPS without disrupting operations while protecting roughly 1,200 staff and their employment terms.","url":"https://www.alberta.ca/building-a-modern-police-service"},{"source":"Rural Municipalities of Alberta (RMA)","stance":"mixed","quote":"Notes the creation of the ASPS as an independent Crown corporation and seeks clarity for rural communities on how the new service will interact with existing RCMP policing arrangements and costs.","url":"https://rmalberta.com/news/government-of-alberta-introduces-bill-15/"}]},"ab-bill-1":{"officialUrl":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-001.pdf","factCheck":"Verified: Bill 1, the International Agreements Act, was a government priority bill of the 31st Legislature (2nd Session) that received Royal Assent November 26, 2025 and came into force immediately; modeled partly on Quebec's framework, it provides that international agreements signed by the federal government do not have effect in areas of Alberta's jurisdiction unless expressly adopted by Alberta, and broadens earlier law to cover all international agreements (not just trade/investment). Common misinformation: the Act does not, by its own terms, repeal Treaty or constitutional Indigenous rights — those are protected under s.35 of the Constitution; however, opposition members and First Nations critics warn it could be used to sideline instruments such as UNDRIP and the UN Convention on the Rights of the Child unless explicitly incorporated into statute, and the government declined an amendment to clarify it would not undermine Treaty rights.","sources":[{"title":"Bill 1 official text (31st Legislature, 2nd Session)","url":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-001.pdf","type":"official"},{"title":"Protecting provincial jurisdiction (Government of Alberta)","url":"https://www.alberta.ca/protecting-provincial-jurisdiction","type":"official"},{"title":"Making sense of Alberta's International Agreements Act (LawNow Magazine)","url":"https://www.lawnow.org/making-sense-of-albertas-international-agreements-act/","type":"legal"},{"title":"Alberta Bill 1: Provincial Sovereignty and International Agreements Explained (Western Wheel / Great West Media)","url":"https://www.westernwheel.ca/beyond-local/smith-opens-fall-session-with-focus-on-alberta-sovereignty-11426762","type":"news"}],"commentary":[{"source":"Alberta NDP (Official Opposition)","stance":"oppose","quote":"During debate, opposition members warned the law could be read as a tool to undermine UNDRIP and First Nations' Treaty rights, and criticized the government for declining an amendment to clarify it should not be used that way.","url":"https://www.lawnow.org/making-sense-of-albertas-international-agreements-act/"},{"source":"LawNow Magazine (Centre for Public Legal Education Alberta)","stance":"mixed","quote":"Explains that the Act means international human-rights instruments like the CRC and UNDRIP no longer apply in Alberta except where explicitly included in statutes, and that obligations under international agreements are not to be presumed part of Alberta law.","url":"https://www.lawnow.org/making-sense-of-albertas-international-agreements-act/"},{"source":"Government of Alberta (Premier Danielle Smith)","stance":"support","quote":"Frames the Act as protecting provincial jurisdiction by ensuring federally signed international agreements cannot bind Alberta in areas of provincial responsibility without the province's approval.","url":"https://www.alberta.ca/protecting-provincial-jurisdiction"}]},"ab-bill-31":{"officialUrl":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-031.pdf","factCheck":"Verified: Bill 31, the Red Tape Reduction Statutes Amendment Act, 2026, was introduced April 23, 2026 by Service Alberta and Red Tape Reduction Minister Dale Nally and (per reporting around May 11, 2026) passed third reading and proceeded to Royal Assent; it is an omnibus bill amending roughly 18 statutes, most notably renaming the Daylight Saving Time Act as the Official Time Act and anchoring Alberta at UTC-6 ('Alberta Time') year-round to end seasonal clock changes, plus numerous technical fixes (e.g., to the Land Titles Act, Residential Tenancies Act, Condominium Property Act). Common misinformation: ending the clock change does NOT move Alberta onto permanent standard time — the bill adopts permanent Mountain Daylight Time (more evening light), and the time-change provisions take effect on proclamation, not automatically on passage.","sources":[{"title":"Bill 31 official text (31st Legislature, 2nd Session)","url":"https://docs.assembly.ab.ca/LADDAR_files/docs/bills/bill/legislature_31/session_2/20251023_bill-031.pdf","type":"official"},{"title":"Implementing red tape reduction (Government of Alberta)","url":"https://www.alberta.ca/implementing-red-tape-reduction","type":"official"},{"title":"Cabinet minister talks about benefits of 'Alberta Time,' tables bill to eliminate clock changes (CBC News)","url":"https://www.cbc.ca/news/canada/edmonton/alberta-time-change-time-daylight-time-zone-red-tape-reduction-bill-gambling-9.7175365","type":"news"},{"title":"Alberta government moving to adopt daylight time year-round (CBC News)","url":"https://www.cbc.ca/news/canada/edmonton/daylight-saving-time-clock-change-time-zone-alberta-9.7171054","type":"news"},{"title":"Province proposes permanent daylight time under omnibus bill (St. Albert Gazette)","url":"https://www.stalbertgazette.com/local-news/province-proposes-permanent-daylight-time-under-omnibus-bill-12200891","type":"news"},{"title":"Bill 31: Bringing Alberta's Land Titles System into the 21st Century (Brownlee LLP)","url":"https://news.brownleelaw.com/post/102mryk/bill-31-bringing-albertas-land-titles-system-into-the-21st-century","type":"legal"}],"commentary":[{"source":"Government of Alberta (Minister Dale Nally)","stance":"support","quote":"Touts the benefits of permanent 'Alberta Time,' saying feedback was split with a slight preference for more light later in the day and that the move aligns Alberta with neighbours like Saskatchewan and B.C. that no longer change clocks.","url":"https://www.cbc.ca/news/canada/edmonton/alberta-time-change-time-daylight-time-zone-red-tape-reduction-bill-gambling-9.7175365"},{"source":"Ryan Turner, Renown Down Hole Solutions (oilfield services)","stance":"support","quote":"Says the Alberta-Saskatchewan time difference causes confusion and costly scheduling errors — 'It gets expensive quick when there's a screw-up' — and hopes a shared clock makes operations simpler.","url":"https://www.cbc.ca/news/canada/edmonton/alberta-time-change-time-daylight-time-zone-red-tape-reduction-bill-gambling-9.7175365"},{"source":"Brownlee LLP (municipal/real estate law firm)","stance":"mixed","quote":"Highlights that Bill 31 modernizes the Land Titles Act with roughly 79 amendments to bring digital concepts into a paper-based system, while flagging practical transition considerations for the property sector.","url":"https://news.brownleelaw.com/post/102mryk/bill-31-bringing-albertas-land-titles-system-into-the-21st-century"}]},"mb-bill-4":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b004e.php","factCheck":"Verified: Bill 4, The Constitutional Questions Amendment Act (sponsored by Justice Minister Matt Wiebe), received royal assent on June 1, 2026 (SM 2026, c. 4) after being reintroduced in the spring session following its failure to pass in fall 2025. Common misconception to correct: the bill does NOT prevent or ban use of the Charter's s. 33 notwithstanding clause; it only requires the government to refer any such invocation to the Manitoba Court of Appeal for an advisory opinion, which the court cannot use to stop the legislation.","sources":[{"title":"Bill 4 - The Constitutional Questions Amendment Act (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b004e.php","type":"official"},{"title":"NDP reintroduces notwithstanding clause bill as spring session starts at Manitoba Legislature","url":"https://www.cbc.ca/news/canada/manitoba/notwithstanding-clause-spring-legislative-session-march-4-2026-9.7114476","type":"news"},{"title":"Manitoba Government Acts to Protect Democracy and Fundamental Freedoms (news release)","url":"https://news.gov.mb.ca/news/index.html?item=71199","type":"official"},{"title":"Bill 4 - The Constitutional Questions Amendment Act (status tracker)","url":"https://www.civicsproject.org/regions/manitoba/bill/43/4?session=3","type":"advocacy"}],"commentary":[{"source":"Matt Wiebe, Manitoba Justice Minister (NDP)","stance":"support","quote":"Any future invocation of the notwithstanding clause in Manitoba needs to be subject to robust public discussion; the bill is a safeguard against future governments using s. 33 to override the rights of protected groups, including religious minorities and segments of the 2SLGBTQ+ community.","url":"https://www.cbc.ca/news/canada/manitoba/notwithstanding-clause-spring-legislative-session-march-4-2026-9.7114476"},{"source":"CBC News (analysis of bill mechanics)","stance":"mixed","quote":"A government that invokes the clause would have to lay out its rationale to an appeal court judge, who could comment on the merit of its use but would not have the power to stop the government from moving forward.","url":"https://www.cbc.ca/news/canada/manitoba/notwithstanding-clause-spring-legislative-session-march-4-2026-9.7114476"}]},"mb-bill-2":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b002e.php","factCheck":"Verified: Bill 2, The Non-Consensual Distribution of Intimate Images Amendment Act (Justice Minister Wiebe), received royal assent June 1, 2026 (SM 2026, c. 2). It broadens the law to cover 'fake intimate images' (deepfakes) that falsely depict an identifiable person, creates a tort for threatening to distribute images, extends protections after death and to unidentifiable persons, and empowers courts to order internet intermediaries to remove/de-index images. Note to avoid confusion: this is a distinct, newer act from Manitoba's earlier 2024 Intimate Image Protection legislation.","sources":[{"title":"Bill 2 - The Non-Consensual Distribution of Intimate Images Amendment Act (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b002e.php","type":"official"},{"title":"Manitoba government eyes more recourse for people who have intimate images shared (Global News)","url":"https://globalnews.ca/news/11536361/manitoba-government-eyes-more-recourse-for-people-who-have-intimate-images-shared","type":"news"},{"title":"Third Session Adjourns With Important Legislation (news release listing the Act)","url":"https://news.gov.mb.ca/news/index.html?item=71838","type":"official"},{"title":"Manitoba Passes Bill to Combat Non-Consensual Sharing of Intimate Images (ARPA Canada)","url":"https://arpacanada.ca/articles/manitoba-passes-bill-to-combat-non-consensual-sharing-of-intimate-images/","type":"advocacy"}],"commentary":[{"source":"ARPA Canada (Association for Reformed Political Action)","stance":"mixed","quote":"This is a good piece of legislation that would help to combat sexual extortion and online bullying; however, this legislation could go further, for example by penalizing possession of non-consensual intimate images, not just distribution.","url":"https://arpacanada.ca/articles/manitoba-passes-bill-to-combat-non-consensual-sharing-of-intimate-images/"},{"source":"Centre for International Governance Innovation (CIGI)","stance":"mixed","quote":"Provinces such as Manitoba, B.C. and Quebec have updated civil legislation to capture altered/deepfake images, but Canada must do more to protect women and girls from harmful deepfakes, as significant gaps remain in both civil and criminal law.","url":"https://www.cigionline.org/articles/canada-must-do-more-to-protect-women-and-girls-from-harmful-deepfakes/"}]},"mb-bills-8-9":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b008e.php","factCheck":"Verified: Both bills (Justice Minister Wiebe) received royal assent June 1, 2026 - Bill 8 The Long-Bladed Weapon Control Amendment Act (SM 2026, c. 7) and Bill 9 The Street Weapons Control Act (SM 2026, c. 8); both come into force on proclamation. Bill 8 regulates SALE of machetes/long-bladed weapons and pepper spray (ID checks, no sales under 18, record-keeping, online-retailer rules); Bill 9 makes it an offence to POSSESS such 'street weapons' in a public space in a population centre, with exemptions and an opt-in mechanism for First Nations. Correction: these are provincial regulatory measures, not a federal-style criminal weapons ban, and they do not prohibit possession on private property or in a residence.","sources":[{"title":"Bill 8 - The Long-Bladed Weapon Control Amendment Act (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b008e.php","type":"official"},{"title":"Bill 9 - The Street Weapons Control Act (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b009e.php","type":"official"},{"title":"Sick note reduction, machete ban among bills introduced by Manitoba government (CBC)","url":"https://www.cbc.ca/news/canada/manitoba/new-bills-health-crime-9.7116363","type":"news"},{"title":"Amazon agrees to province's request to halt sales of machetes to Manitobans (CBC)","url":"https://www.cbc.ca/news/canada/manitoba/manitoba-amazon-machetes-1.7480939","type":"news"},{"title":"The Long-Bladed Weapon Control Act (Manitoba Justice backgrounder)","url":"https://www.gov.mb.ca/justice/long-bladedweaponcontrol.html","type":"official"}],"commentary":[{"source":"Sel Burrows, Point Douglas community activist","stance":"support","quote":"The inner city really appreciates the government's action on controlling machetes, as they have no place on our streets.","url":"https://www.cbc.ca/news/canada/manitoba/machete-sales-bill-1.7348118"},{"source":"Wab Kinew, Premier of Manitoba (NDP)","stance":"support","quote":"Promised a street weapons ban modelled in part on Saskatchewan's approach to remove machetes and similar weapons from public spaces and improve community safety.","url":"https://www.ctvnews.ca/winnipeg/article/manitoba-premier-promises-street-weapons-ban-similar-law-in-saskatchewan/"}]},"mb-bill-11":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b011e.php","factCheck":"Verified: Bill 11, The Employment Standards Code Amendment Act (Sick Notes for Employee Absences), sponsored by Labour Minister Marcelino, received royal assent June 1, 2026 (SM 2026, c. 10) and comes into force October 1, 2026. Correction of a common overstatement: it does not fully 'abolish' sick notes - employers may still require one if an absence lasts more than one week (some reporting says seven consecutive days) or the worker has been off sick more than 10 scheduled workdays in a year; it also requires employers to reimburse the cost and to accept notes from a broad range of health professionals.","sources":[{"title":"Bill 11 - The Employment Standards Code Amendment Act (Sick Notes) (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b011e.php","type":"official"},{"title":"Restrictions on sick notes for Manitoba employers (MLT Aikins)","url":"https://www.mltaikins.com/insights/proposed-restrictions-on-sick-notes-for-manitoba-employers/","type":"legal"},{"title":"Doctors Manitoba gets action on sick note reform (CMA)","url":"https://www.cma.ca/about-us/what-we-do/health-care-unburdened-grant/doctors-manitoba-gets-action-sick-note-reform-and","type":"advocacy"},{"title":"Restrictions on sick notes for Manitoba employers effective October 1, 2026 (Mondaq)","url":"https://www.mondaq.com/canada/employee-rights-labour-relations/1797550/restrictions-on-sick-notes-for-manitoba-employers-to-be-effective-october-1-2026","type":"legal"}],"commentary":[{"source":"Doctors Manitoba","stance":"support","quote":"Manitoba was one of only two provinces that had not acted to limit sick notes; it now moves from worst to first in Canada, which is good for patients, employers and physicians by reducing unnecessary administrative burden.","url":"https://www.cma.ca/about-us/what-we-do/health-care-unburdened-grant/doctors-manitoba-gets-action-sick-note-reform-and"},{"source":"MLT Aikins LLP (employment lawyers)","stance":"mixed","quote":"The amendments meaningfully restrict when employers can demand a sick note and require reimbursement of the cost, so Manitoba employers should review absence-management policies before the October 1, 2026 in-force date.","url":"https://www.mltaikins.com/insights/proposed-restrictions-on-sick-notes-for-manitoba-employers/"}]},"mb-bill-13":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b013e.php","factCheck":"Important correction: Bill 13, The Residential Tenancies Amendment Act (Minister Sandhu), did NOT receive royal assent in the spring 2026 session - it was one of the bills the Progressive Conservative opposition declined to fast-track and that was delayed to the fall sitting (the legislature returns October 1, 2026), so it remains unproclaimed/not yet law. Described by the government as the 'largest expansion to rent controls in decades,' the package would (via the bill plus associated regulation) raise the rent-control exemption ceiling for older buildings and cut by 50% the share of capital costs landlords can recover through above-guideline rent increases, plus add landlord registration.","sources":[{"title":"Bill 13 - The Residential Tenancies Amendment Act (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b013e.php","type":"official"},{"title":"NDP plan to expand Manitoba rent control protections (CBC)","url":"https://www.cbc.ca/news/canada/manitoba/manitoba-residential-tenancies-changes-renters-9.7125916","type":"news"},{"title":"Bad Policy: The Consequences of Rental Regulatory Changes & Bill 13 (Canadian Property Tax Association)","url":"https://cpta.org/bad-policy-the-consequences-of-rental-regulatory-changes-bill-13/","type":"advocacy"},{"title":"Big rent hikes - a made-in-Manitoba problem (Canadian Centre for Policy Alternatives)","url":"https://www.policyalternatives.ca/news-research/big-rent-hikes-a-made-in-manitoba-problem/","type":"advocacy"}],"commentary":[{"source":"Canadian Property Tax Association","stance":"oppose","quote":"Under the proposed changes a typical 30-unit building needing standard capital work would generate a negative return on money spent, and lenders will not finance projects with negative returns - the policy will discourage building maintenance and investment.","url":"https://cpta.org/bad-policy-the-consequences-of-rental-regulatory-changes-bill-13/"},{"source":"Canadian Centre for Policy Alternatives (CCPA Manitoba)","stance":"support","quote":"Large above-guideline rent hikes are a made-in-Manitoba problem driven by loopholes; stronger rent regulation is needed to protect tenants from unaffordable increases.","url":"https://www.policyalternatives.ca/news-research/big-rent-hikes-a-made-in-manitoba-problem/"}]},"mb-bill-49":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b049e.php","factCheck":"Verified: Bill 49, The Business Practices Amendment Act (Minister Sandhu), passed Standing Committee unamended on April 22, 2026 and received royal assent June 1, 2026 (SM 2026, c. 41); detailed rules will follow in regulation. It makes it an unfair business practice for retailers and online marketplaces to use 'personalized algorithmic pricing' (dynamic pricing based on a specific consumer's data) to INCREASE the price charged to that consumer, with corporate fines up to $300,000 (first offence) and $1,000,000 (subsequent). It would make Manitoba the first Canadian jurisdiction to legislate on personalized algorithmic pricing. Note: it targets price increases to individuals, not ordinary discounts or uniform sales.","sources":[{"title":"Bill 49 - The Business Practices Amendment Act (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b049e.php","type":"official"},{"title":"Manitoba Proposes to Ban Personalized Pricing Under Bill 49 (Blakes / Blake, Cassels & Graydon LLP)","url":"https://www.blakes.com/insights/manitoba-proposes-to-ban-personalized-pricing-under-bill-49/","type":"legal"},{"title":"Manitoba's Bill 49 and personalized algorithmic pricing: what businesses need to know (MLT Aikins)","url":"https://www.mltaikins.com/insights/manitobas-bill-49-and-personalized-algorithmic-pricing/","type":"legal"},{"title":"Manitoba Algorithmic Pricing Bill (Retail Council of Canada)","url":"https://www.retailcouncil.org/manitoba-algorithmic-pricing-bill/","type":"advocacy"}],"commentary":[{"source":"Retail Council of Canada","stance":"mixed","quote":"RCC advocated for clearer definitions to ensure retailers are not limited in using modern technologies that lower costs and bring discounts, warning the bill protects consumers from a largely hypothetical future risk while preserving responsible pricing tools.","url":"https://www.retailcouncil.org/manitoba-algorithmic-pricing-bill/"},{"source":"Blake, Cassels & Graydon LLP (Blakes)","stance":"mixed","quote":"If enacted, the bill would make Manitoba the first Canadian jurisdiction to regulate personalized algorithmic pricing, with significant compliance implications for retailers and online marketplaces using dynamic pricing.","url":"https://www.blakes.com/insights/manitoba-proposes-to-ban-personalized-pricing-under-bill-49/"}]},"mb-bill-51":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b051e.php","factCheck":"Verified: Bill 51, The Public Sector Artificial Intelligence and Cybersecurity Governance Act (Innovation Minister Moroz), received royal assent June 1, 2026 (SM 2026, c. 43). It is a framework statute applying to prescribed public-sector entities (e.g., government, agencies, health authorities, universities, school divisions, municipalities), requiring AI transparency, accountability and risk management plus cybersecurity programs, with most substance left to future regulations and standards. Correction: it governs the PUBLIC sector's use of AI - it is not a general/private-sector AI law, and as of mid-2026 the detailed regulations had not yet been made.","sources":[{"title":"Bill 51 - The Public Sector Artificial Intelligence and Cybersecurity Governance Act (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b051e.php","type":"official"},{"title":"Manitoba's legislature gets busy with AI regulation (Teresa Scassa)","url":"https://teresascassa.substack.com/p/manitobas-legislature-gets-busy-with","type":"academic"},{"title":"Manitoba Eco-Network comments about Bill 51","url":"https://mbeconetwork.org/13866-2/","type":"advocacy"},{"title":"Standing Committee on Social and Economic Development, Apr 22, 2026 (Hansard)","url":"https://www.gov.mb.ca/legislature/hansard/43rd_3rd/sed_02/sed_02.html","type":"official"}],"commentary":[{"source":"Teresa Scassa, Canada Research Chair in Information Law and Policy (University of Ottawa)","stance":"mixed","quote":"Bill 51 closely resembles Ontario's Enhancing Digital Security and Trust Act, which over a year after taking effect still has no public-sector AI regulations in place - raising concern that a framework law without timely regulations may deliver little real governance.","url":"https://teresascassa.substack.com/p/manitobas-legislature-gets-busy-with"},{"source":"Manitoba Eco-Network","stance":"mixed","quote":"This is an important opportunity for Manitoba to lead on AI protections, but regulation must go beyond government use to include robust impact assessment and oversight of the computing infrastructure needed to run AI systems.","url":"https://mbeconetwork.org/13866-2/"}]},"mb-bill-53":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b053e.php","factCheck":"Verified: Bill 53, The Budget Implementation and Tax Statutes Amendment Act, 2026 (Finance Minister Sala), received royal assent June 1, 2026 (SM 2026, c. 44), with the PST removal from groceries taking effect July 1, 2026. The exemption covers most food and non-alcoholic beverages for human consumption (broader than the federal GST zero-rating, but excluding restaurant/venue purchases); the act also raises the Homeowners Affordability Tax Credit to $1,700 and Renters Affordability Tax Credit to $675. Context: the PCs delayed fast-tracking, demanding a 'meaningful' tax cut (an increase to the basic personal exemption), but the bill ultimately passed.","sources":[{"title":"Bill 53 - The Budget Implementation and Tax Statutes Amendment Act, 2026 (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b053e.php","type":"official"},{"title":"Third Session Ends with Passage of Bill to Remove PST from Groceries Starting July 1 (news release)","url":"https://news.gov.mb.ca/news/index.html?item=74040","type":"official"},{"title":"Manitoba PCs will delay budget bill unless 'meaningful' tax relief is added (CBC)","url":"https://www.cbc.ca/news/canada/manitoba/pcs-budget-implementation-bill-delay-9.7189864","type":"news"},{"title":"Manitoba Budget Removes PST from Most Groceries (Retail Council of Canada)","url":"https://www.retailcouncil.org/manitoba-budget-removes-pst-from-most-groceries/","type":"advocacy"}],"commentary":[{"source":"Nahanni Fontaine, Government House Leader (NDP)","stance":"support","quote":"Taking PST off groceries will make life more affordable for Manitobans - we're saving you money at the grocery store, more money for homeowners and renters, free child care to low-income families and free transit for youth.","url":"https://news.gov.mb.ca/news/index.html?item=74040"},{"source":"Obby Khan, Progressive Conservative Leader","stance":"mixed","quote":"The PCs will work to pass the budget implementation bill if the NDP bakes in a meaningful tax cut, such as raising the basic personal exemption to just under $21,000.","url":"https://www.cbc.ca/news/canada/manitoba/pcs-budget-implementation-bill-delay-9.7189864"}]},"mb-bill-28":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b028e.php","factCheck":"Verified: Bill 28, The Health System Governance and Accountability Amendment Act (Nurse-to-Patient Ratios), sponsored by Health Minister Asagwara, received royal assent June 1, 2026 (SM 2026, c. 21) and is described as the first legislation of its kind in Canada. Important clarification: the act enables the minister to ESTABLISH minimum nurse-to-patient ratios by regulation - it does not by itself set specific numeric ratios; as of June 2026 the implementation committee was still being finalized and ratios had not yet been set, so the change will roll out over time.","sources":[{"title":"Bill 28 - The Health System Governance and Accountability Amendment Act (Nurse-to-Patient Ratios) (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b028e.php","type":"official"},{"title":"Manitoba Government Passes Nurse-to-Patient Ratios Legislation, Releases Recommendations (news release)","url":"https://news.gov.mb.ca/news/index.html?item=74057","type":"official"},{"title":"Manitoba union wants nurse-patient ratios set as soon as possible (CBC)","url":"https://www.cbc.ca/news/canada/manitoba/nurse-to-patient-ratios-legislation-9.7225364","type":"news"},{"title":"Manitoba's nurse-to-patient ratios must be set soon, union urges (Global News)","url":"https://globalnews.ca/news/11893757/manitoba-nurse-patient-ratio-legislation-implementation/","type":"news"}],"commentary":[{"source":"Darlene Jackson, President, Manitoba Nurses Union","stance":"support","quote":"It is incredibly positive to see legislation on nurse-patient ratios - the first in Canada - but this will not happen overnight; we are now into June and the implementation committee has not been finalized, and it needs to be up and running.","url":"https://globalnews.ca/news/11893757/manitoba-nurse-patient-ratio-legislation-implementation/"},{"source":"Uzoma Asagwara, Minister of Health, Seniors and Long-Term Care (NDP)","stance":"support","quote":"It is really exciting for Manitoba to be the first and only jurisdiction in Canada to bring forward legislation that will establish and protect nurse-to-patient ratios in our health-care system.","url":"https://www.cbc.ca/news/canada/manitoba/manitoba-legislature-nurse-overtime-patient-ratios-9.7121746"}]},"mb-bill-36":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b036e.php","factCheck":"Verified: Bill 36, The Child and Family Services Amendment Act (Families Minister Fontaine), received royal assent June 1, 2026 (SM 2026, c. 29). It expands the definition of 'Indigenous law' to include child-welfare laws of recognized self-governing Indigenous bodies, creates a streamlined process for Indigenous service providers to request termination of provincial guardianship/supervision orders when an Indigenous law applies, and extends supports to young adults (ages 18-20). Note: this builds on Manitoba's earlier 2024 Indigenous-jurisdiction CFS reforms (SM 2024, c. 36) and is separate from a further CFS Indigenous-jurisdiction bill (Bill 22) that was only introduced near session's end.","sources":[{"title":"Bill 36 - The Child and Family Services Amendment Act (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b036e.php","type":"official"},{"title":"Manitoba CFS agencies now have option of placing kids with extended family, community (CBC)","url":"https://www.cbc.ca/news/canada/manitoba/child-welfare-manitoba-indigenous-children-1.7350370","type":"news"},{"title":"3rd Session - 43rd Legislature, Vol. 27b, Mar 12, 2026 (Hansard - second reading debate)","url":"https://manitoba.ca/legislature/hansard/43rd_3rd/vol_27b/h27b.html","type":"official"}],"commentary":[{"source":"Nahanni Fontaine, Minister of Families (NDP)","stance":"support","quote":"The amendments create a practical, collaborative process for Indigenous service providers to request termination of provincial supervision or guardianship orders, eliminating unnecessary court delays and removing barriers to Indigenous jurisdiction, and widen supports for young adults leaving care.","url":"https://manitoba.ca/legislature/hansard/43rd_3rd/vol_27b/h27b.html"},{"source":"Government of Manitoba (Families)","stance":"support","quote":"The reforms respond to Truth and Reconciliation Commission calls to reduce the number of Indigenous children in care and affirm the inherent right of Indigenous governments to deliver their own child welfare services, with 38 First Nations already signing on to a shared relationship declaration.","url":"https://www.cbc.ca/news/canada/manitoba/child-welfare-manitoba-indigenous-children-1.7350370"}]},"mb-bill-40":{"officialUrl":"https://web2.gov.mb.ca/bills/43-3/b040e.php","factCheck":"Verified: Bill 40, The Elections Amendment Act (Justice Minister Wiebe), received royal assent June 1, 2026 (SM 2026, c. 33) and applies to subsequent elections. It requires prospective candidates who are or were MLAs to disclose whether the Ethics Commissioner found they contravened The Conflict of Interest (Members and Ministers) Act in cases where the Assembly ordered a fine, a suspension, or that the member's seat be vacated. Clarification: disclosure is NOT required where the only sanction was a reprimand, so it captures only the more serious ethics findings.","sources":[{"title":"Bill 40 - The Elections Amendment Act (official text)","url":"https://web2.gov.mb.ca/bills/43-3/b040e.php","type":"official"},{"title":"3rd Session - 43rd Legislature, Vol. 27b, Mar 12, 2026 (Hansard - introduction)","url":"https://manitoba.ca/legislature/hansard/43rd_3rd/vol_27b/h27b.html","type":"official"},{"title":"Elections Manitoba - Legislation","url":"https://electionsmanitoba.ca/en/Resources/Legislation","type":"official"}],"commentary":[{"source":"Matt Wiebe, Manitoba Justice Minister (NDP)","stance":"support","quote":"The bill enhances transparency for the public around past ethics violations by current and former MLAs who choose to run again, bringing Manitoba to the forefront in Canada on accountability for elected officials.","url":"https://manitoba.ca/legislature/hansard/43rd_3rd/vol_27b/h27b.html"},{"source":"Government of Manitoba (Justice)","stance":"support","quote":"Candidates who were MLAs must disclose Ethics Commissioner findings of a conflict-of-interest contravention where the Assembly imposed a fine, suspension or vacating of a seat - reprimand-only findings are excluded.","url":"https://web2.gov.mb.ca/bills/43-3/b040e.php"}]},"mb-bill-12":{"officialUrl":"https://news.gov.mb.ca/news/index.html?item=71901","factCheck":"Important correction: Bill 12, The Manitoba Crown-Indigenous Corporation Act (sponsored by Minister Ian Bushie), was introduced for first reading but did NOT pass in the spring 2026 session - it appears under 'Introduction of Bills' on the June 1, 2026 order paper and has no enacted-chapter number or published text page in the official 43rd Legislature 3rd-Session bills index, so it is not yet law and is expected to be dealt with in a later sitting. The corporation, first announced December 9, 2025, is a Crown-Indigenous partnership (with the Assembly of Manitoba Chiefs and Manitoba Metis Federation) to lead the Churchill Plus rail-and-port expansion; because no bill text is publicly posted, the official source below is the government announcement rather than a bill page.","sources":[{"title":"Manitoba Government Announces New Crown-Indigenous Corporation to Lead Churchill Plus Project (news release)","url":"https://news.gov.mb.ca/news/index.html?item=71901","type":"official"},{"title":"Manitoba Legislative Assembly Order Paper, June 1, 2026 (lists Bill 12 at Introduction of Bills)","url":"https://www.gov.mb.ca/legislature/business/orderpaper.pdf","type":"official"},{"title":"New Crown corporation will ensure Indigenous involvement from start of major projects: Kinew (CBC)","url":"https://www.cbc.ca/news/canada/manitoba/indigenous-consultation-crown-corporation-9.7009608","type":"news"},{"title":"Manitoba announces new Crown-Indigenous corporation for Churchill project (Daily Commercial News / ConstructConnect)","url":"https://canada.constructconnect.com/joc/news/government/2025/12/manitoba-announces-new-crown-indigenous-corporation-for-churchill-project","type":"news"}],"commentary":[{"source":"Wab Kinew, Premier of Manitoba (NDP)","stance":"support","quote":"Churchill has always been a gateway to the world, and the Manitoba Crown-Indigenous Corporation is how we turn that potential into real progress, with Indigenous leadership central to planning and decision-making.","url":"https://news.gov.mb.ca/news/index.html?item=71901"},{"source":"CBC News (reporting on the initiative)","stance":"mixed","quote":"The new Crown corporation is intended to ensure Indigenous involvement from the start of major projects such as Churchill Plus, though the legislation to formally establish it had not yet been passed by mid-2026.","url":"https://www.cbc.ca/news/canada/manitoba/indigenous-consultation-crown-corporation-9.7009608"}]},"sk-bill-48":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-48.pdf","factCheck":"Verified: Bill 48, The Compassionate Intervention Act, was introduced Dec. 5, 2025 and passed (received Royal Assent) in early May 2026, creating a framework for involuntary/secure addictions treatment with the first assessment centre and inpatient unit at Saskatchewan Hospital North Battleford. Common misinformation correction: the Act is NOT yet operational at the time of passage; the government has said it will only come into force after regulations are finalized (expected fall 2026), and despite the 'compassionate' name it authorizes detention and involuntary treatment, which medical bodies and civil-liberties groups dispute is evidence-based.","sources":[{"title":"Bill No. 48 - The Compassionate Intervention Act (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-48.pdf","type":"official"},{"title":"Legislation Passes for Compassionate Intervention for Addictions Treatment (Govt of Saskatchewan)","url":"https://www.saskatchewan.ca/government/news-and-media/2026/may/05/legislation-passes-for-compassionate-intervention-for-addictions-treatment","type":"official"},{"title":"Involuntary addiction treatment now legal in Sask. despite medical groups' warnings (CBC News)","url":"https://www.cbc.ca/news/canada/saskatchewan/involuntary-addiction-treatment-now-legal-despite-medical-groups-warnings-9.7189731","type":"news"},{"title":"Joint Statement on The Compassionate Intervention Act (John Howard Society of Saskatchewan, CLASSIC, Elizabeth Fry Society)","url":"https://sk.johnhoward.ca/joint-statement-on-the-compassionate-intervention-act-and-the-state-of-voluntary-care-in-saskatchewan/","type":"advocacy"},{"title":"Joint SMA/CPSS Statement on the Compassionate Intervention Act (Saskatchewan Medical Association)","url":"https://www.sma.sk.ca/joint-sma-cpss-statement-on-the-compassionate-intervention-act/","type":"advocacy"}],"commentary":[{"source":"Government of Saskatchewan (Ministry of Mental Health and Addictions)","stance":"support","quote":"The Act is framed as supporting people with severe addictions who are not capable of seeking help despite serious health and safety risks, with secure assessment and treatment beginning at Saskatchewan Hospital North Battleford.","url":"https://www.saskatchewan.ca/government/news-and-media/2026/may/05/legislation-passes-for-compassionate-intervention-for-addictions-treatment"},{"source":"Saskatchewan Medical Association & College of Physicians and Surgeons of Saskatchewan","stance":"oppose","quote":"The medical bodies warn that involuntary addiction treatment is not supported by clinical evidence and can increase the risk of fatal overdose after release due to lost drug tolerance.","url":"https://www.sma.sk.ca/joint-sma-cpss-statement-on-the-compassionate-intervention-act/"},{"source":"John Howard Society of Saskatchewan, CLASSIC and Elizabeth Fry Society of Saskatchewan (joint statement)","stance":"oppose","quote":"Detaining people who have committed no crime against their will risks violating Charter rights, and recovery only works when those facing addiction choose to participate; the government should instead strengthen voluntary care.","url":"https://sk.johnhoward.ca/joint-statement-on-the-compassionate-intervention-act-and-the-state-of-voluntary-care-in-saskatchewan/"}]},"sk-bill-47":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-47.pdf","factCheck":"Verified: Bill 47, The Response to Illicit Drugs Act, was introduced Dec. 3, 2025, passed, and came into force June 1, 2026. It creates civil (not criminal) tools allowing the government and individuals to sue and recover costs of harms from those who produce, traffic, import or export Schedule I drugs, and lets the province void certain appointments, grants and agreements for those convicted of specified Schedule I offences. Common misinformation correction: the Act does NOT criminalize or target simple drug possession or drug users; it is a civil cost-recovery and accountability scheme aimed at traffickers.","sources":[{"title":"Bill No. 47 - The Response to Illicit Drugs Act (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-47.pdf","type":"official"},{"title":"Saskatchewan Introduces the Response to Illicit Drugs Act (Govt of Saskatchewan)","url":"https://www.saskatchewan.ca/government/news-and-media/2025/december/03/saskatchewan-introduces-the-response-to-illicit-drugs-act-to-strengthen-public-safety-and-support-sa","type":"official"},{"title":"Sask. govt introduces new law to respond to illicit drug trafficking (paNOW)","url":"https://panow.com/2025/12/04/sask-govt-introduces-new-law-act-to-respond-to-illicit-drug-trafficking/","type":"news"},{"title":"Saskatchewan introduces civil law to recover costs from drug traffickers (Meridian Source)","url":"https://meridiansource.ca/2026/06/04/saskatchewan-introduces-civil-law-to-recover-costs-from-drug-traffickers/","type":"news"}],"commentary":[{"source":"Government of Saskatchewan (Ministry of Justice / Attorney General Tim McLeod)","stance":"support","quote":"The Act strengthens accountability for drug traffickers and gives the government and individuals new civil tools to recover the costs of harms caused by illicit drug activity, while not applying to simple possession.","url":"https://www.saskatchewan.ca/government/news-and-media/2025/december/03/saskatchewan-introduces-the-response-to-illicit-drugs-act-to-strengthen-public-safety-and-support-sa"},{"source":"Nicole Sarauer, Saskatchewan NDP justice critic","stance":"mixed","quote":"The Opposition said it was still reviewing the legislation but was skeptical it would actually be effective at reducing drug-related harms.","url":"https://panow.com/2025/12/04/sask-govt-introduces-new-law-act-to-respond-to-illicit-drug-trafficking/"}]},"sk-bill-34":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-34.pdf","factCheck":"Verified: Bill 34, The Cyberstalking and Coercive Control Act, passed and became law on Dec. 4, 2025. It amends The Victims of Interpersonal Violence Act to expand the definition of interpersonal violence to include cyberstalking, online harassment, and patterns of coercive or controlling behaviour, giving victims access to provincial protections such as emergency intervention/restraining orders and a process to end long-term tenancies. Common misinformation correction: this is provincial civil/protective legislation expanding access to existing victim protections; it does NOT create a new criminal offence of coercive control (criminal law is federal).","sources":[{"title":"Bill No. 34 - The Cyberstalking and Coercive Control Act (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-34.pdf","type":"official"},{"title":"Government Passes Legislation to Strengthen Protections Against Interpersonal Violence (Govt of Saskatchewan)","url":"https://www.saskatchewan.ca/government/news-and-media/2025/november/27/government-passes-legislation-to-strengthen-protections-against-interpersonal-violence","type":"official"},{"title":"Sask. to table law recognizing coercive control, cyberstalking in interpersonal violence (CBC News)","url":"https://www.cbc.ca/news/canada/saskatchewan/interpersonal-violence-legislation-cyberstalking-coercive-control-9.6949661","type":"news"},{"title":"Saskatchewan's Cyberstalking and Coercive Control Act (PATHS)","url":"https://pathssk.org/cyberstalking-and-coercive-control-act/","type":"advocacy"},{"title":"Sask. adds cyberstalking, coercive control to definition of interpersonal violence (980 CJME)","url":"https://www.cjme.com/2025/11/30/sask-adds-cyberstalking-coercive-control-to-definition-of-interpersonal-violence/","type":"news"}],"commentary":[{"source":"Dr. Crystal Giesbrecht, Provincial Association of Transition Houses and Services of Saskatchewan (PATHS)","stance":"support","quote":"Amending the definition will make protective provisions available to those experiencing coercive or controlling behaviour or online stalking and harassment, increasing options and enhancing safety for victims and survivors.","url":"https://pathssk.org/cyberstalking-and-coercive-control-act/"},{"source":"Tim McLeod, Minister of Justice and Attorney General","stance":"support","quote":"The legislation strengthens protections for victims and clarifies that cyberstalking, online harassment and coercive control are recognized forms of abuse under Saskatchewan law.","url":"https://www.saskatchewan.ca/government/news-and-media/2025/november/27/government-passes-legislation-to-strengthen-protections-against-interpersonal-violence"}]},"sk-bill-42":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-42.pdf","factCheck":"Verified: Bill 42, The Saskatchewan Firearms Amendment Act, 2025, amends the existing Saskatchewan Firearms Act, was passed and received Royal Assent in 2026, and adds a 'deemed seizure' framework requiring fair-market compensation (within 12 months) before federally banned firearms are treated as seized, plus self-storage and provincial appraisal options for owners. Common misinformation correction: the law cannot block or override the federal firearms ban/buyback (criminal law and firearms regulation in this area are federal); it is largely a jurisdictional and political pushback measure imposing provincial conditions and compensation demands, and even supporters acknowledge parts may face a constitutional challenge.","sources":[{"title":"Bill No. 42 - An Act to amend The Saskatchewan Firearms Act (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-42.pdf","type":"official"},{"title":"Province to Introduce Amendments to the Saskatchewan Firearms Act (Govt of Saskatchewan)","url":"https://www.saskatchewan.ca/government/news-and-media/2025/november/25/province-to-introduce-amendments-to-the-saskatchewan-firearms-act","type":"official"},{"title":"Province Protecting Rights of Saskatchewan Firearms Owners Through Additional Storage and Appraisal Options (Govt of Saskatchewan)","url":"https://www.saskatchewan.ca/government/news-and-media/2026/march/11/province-protecting-rights-of-saskatchewan-firearms-owners-through-additional-storage-and-appraisal","type":"official"},{"title":"Why Saskatchewan's Bill 42 Matters - Even If You Don't Own a Firearm (Canadian Shooting Sports Association)","url":"https://cssa-cila.org/why-saskatchewans-bill-42-matters-even-if-you-dont-own-a-firearm/","type":"advocacy"},{"title":"Sask. gun owners can apply to keep recently banned firearms while seeking compensation (Prince Albert Daily Herald)","url":"https://paherald.sk.ca/sask-gun-owners-can-apply-to-keep-recently-banned-firearms-while-seeking-compensation/","type":"news"}],"commentary":[{"source":"Canadian Shooting Sports Association (CSSA)","stance":"support","quote":"The CSSA praises the 'deemed seizure' framework, arguing federal policy that imposes significant economic loss should come with real compensation and clear rules, and that the bill defends lawful firearms owners against federal confiscation.","url":"https://cssa-cila.org/why-saskatchewans-bill-42-matters-even-if-you-dont-own-a-firearm/"},{"source":"Government of Saskatchewan (Ministry of Corrections, Policing and Public Safety)","stance":"support","quote":"The government frames the amendments as protecting Saskatchewan firearms owners by requiring fair-market compensation and offering provincial storage and appraisal options while compensation disputes are resolved.","url":"https://www.saskatchewan.ca/government/news-and-media/2026/march/11/province-protecting-rights-of-saskatchewan-firearms-owners-through-additional-storage-and-appraisal"},{"source":"Legal/constitutional observers (as reported in Saskatchewan media)","stance":"mixed","quote":"Commentators note provisions touching on 'criminality aspects' raise the question of whether the bill can pass constitutional muster, since firearms criminal law falls under federal jurisdiction.","url":"https://paherald.sk.ca/sask-gun-owners-can-apply-to-keep-recently-banned-firearms-while-seeking-compensation/"}]},"sk-bill-38":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-38.pdf","factCheck":"Verified: Bill 38, The Building Schools Faster Act (sponsored by Hon. Everett Hindley), and its consequential companion Bill 39 (The Building Schools Faster Consequential Amendments Act, 2025) passed in spring 2026. The legislation aims to speed school construction by streamlining land, servicing and approval processes. Common misinformation correction: critics and even school divisions stress the Act 'will do nothing on its own to build schools faster'; it changes processes and cost-sharing rather than directly funding or constructing schools, and home-builder associations warn it could add roughly $8,000 to the cost of a new home through servicing-levy changes.","sources":[{"title":"Bill No. 38 - The Building Schools Faster Act (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-38.pdf","type":"official"},{"title":"Bill No. 39 - The Building Schools Faster Consequential Amendments Act, 2025 (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-39.pdf","type":"official"},{"title":"Building Schools Faster Act passes, but questions remain (SaskToday.ca)","url":"https://www.sasktoday.ca/provincial-news/building-schools-faster-act-passes-but-questions-remain-12219491","type":"news"}],"commentary":[{"source":"Hon. Everett Hindley (sponsoring minister) / Government of Saskatchewan","stance":"support","quote":"The government argues the legislation streamlines land servicing and approvals so schools can be built faster as communities grow.","url":"https://www.sasktoday.ca/provincial-news/building-schools-faster-act-passes-but-questions-remain-12219491"},{"source":"Saskatchewan Urban Municipalities Association (SUMA) and Regina-area school divisions","stance":"oppose","quote":"Engagement and transparency on the bill have been lacking, and the legislation 'will do nothing on its own to build schools faster.'","url":"https://www.sasktoday.ca/provincial-news/building-schools-faster-act-passes-but-questions-remain-12219491"},{"source":"Saskatoon and Regina home-builder associations","stance":"oppose","quote":"The bill 'will increase costs by roughly $8,000 for every new home built,' a significant cost passed to families during an affordability crisis.","url":"https://www.sasktoday.ca/provincial-news/building-schools-faster-act-passes-but-questions-remain-12219491"}]},"sk-bill-54":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-54.pdf","factCheck":"Verified: Bill 54, The Correctional Services Amendment Act, 2026, passed and was enacted in May 2026. It introduces a more structured, independent inmate-discipline process in which serious/major disciplinary matters are decided by Justices of the Peace, and pairs this with a partnership having the Saskatchewan Marshals Service investigate offences committed in provincial custody and lay charges where appropriate (beginning at Prince Albert Correctional Centre, Pine Grove Correctional Centre and the Prince Albert Youth Residence). Reporting links the discipline changes to a court ruling requiring more independent adjudication; No notable misinformation found beyond clarifying these are administrative/institutional reforms, not sentencing changes.","sources":[{"title":"Bill No. 54 - The Correctional Services Amendment Act, 2026 (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-54.pdf","type":"official"},{"title":"Modernizing Saskatchewan's Correctional Services Act (Govt of Saskatchewan)","url":"https://www.saskatchewan.ca/government/news-and-media/2026/may/06/modernizing-saskatchewans-correctional-services-act","type":"official"},{"title":"Inmate discipline rules change in Sask. in response to court ruling (CBC News)","url":"https://www.cbc.ca/news/canada/saskatchewan/inmate-correctional-jail-discipline-saskatchewan-9.7040359","type":"news"},{"title":"Modernized correctional services act enacted (620 CKRM)","url":"https://www.620ckrm.com/2026/05/07/modernized-correctional-services-act-enacted/","type":"news"}],"commentary":[{"source":"Government of Saskatchewan (Ministry of Corrections, Policing and Public Safety)","stance":"support","quote":"The amendments strengthen the correctional system's safety, fairness and consistency, with major discipline decided independently by Justices of the Peace and the Saskatchewan Marshals Service investigating in-custody offences.","url":"https://www.saskatchewan.ca/government/news-and-media/2026/may/06/modernizing-saskatchewans-correctional-services-act"},{"source":"Saskatchewan NDP (Nicole Sarauer, justice and community safety critic)","stance":"mixed","quote":"The NDP has raised broader concerns that expanding the Saskatchewan Marshals Service's role risks poaching officers from RCMP and municipal forces that already have vacancies, rather than solving staffing problems.","url":"https://www.cbc.ca/news/canada/saskatchewan/sask-marshals-poaching-rcmp-9.7228771"}]},"sk-bill-31":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-31.pdf","factCheck":"Verified: Bill 31, The Defamation Act (with consequential Bill 32, The Defamation Consequential Amendments Act, 2025), modernizes and replaces Saskatchewan's 1909-era Libel and Slander Act, following a 2024 Law Reform Commission report. It abolishes the libel/slander distinction (using a single concept of 'defamation'), establishes a single cause of action for a publication and its republications, removes outdated 'newspaper' framing to cover digital/online media, and lets courts order takedown and de-indexing of harmful online content. Common misinformation correction: Bill 31 is a general defamation-law modernization, NOT primarily an anti-SLAPP statute; although the Law Reform Commission discussed anti-SLAPP, the bill is best described as updating defamation rules rather than enacting Ontario-style anti-SLAPP protections.","sources":[{"title":"Bill No. 31 - The Defamation Act (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-31.pdf","type":"official"},{"title":"Bill No. 32 - The Defamation Consequential Amendments Act, 2025 (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-32.pdf","type":"official"},{"title":"Saskatchewan introduces legislation to modernize defamation laws (Law360 Canada)","url":"https://www.law360.ca/ca/articles/2408050/saskatchewan-introduces-legislation-to-modernize-defamation-laws","type":"legal"},{"title":"Reform of The Libel and Slander Act - Final Report (Law Reform Commission of Saskatchewan, March 2024)","url":"https://lawreformcommission.sk.ca/Final-Report-on-The-Libel-and-Slander-Act.pdf","type":"legal"},{"title":"Sask. government introduces legislation to update century-old defamation laws (650 CKOM)","url":"https://www.ckom.com/2025/11/05/sask-govt-to-update-and-simplify-century-old-defamation-laws/","type":"news"}],"commentary":[{"source":"Government of Saskatchewan (Ministry of Justice)","stance":"support","quote":"The changes were necessary to reflect today's media landscape, replacing century-old printed-media references with a single modern concept of defamation that covers all forms of media.","url":"https://www.ckom.com/2025/11/05/sask-govt-to-update-and-simplify-century-old-defamation-laws/"},{"source":"Law Reform Commission of Saskatchewan","stance":"support","quote":"The Commission recommended replacing the 1909 Libel and Slander Act with modern defamation legislation, including a single cause of action and updated rules for online publication.","url":"https://lawreformcommission.sk.ca/Final-Report-on-The-Libel-and-Slander-Act.pdf"},{"source":"Canadian Media Lawyers' Association (via Law Reform Commission consultation)","stance":"mixed","quote":"Media-law counsel provided written submissions on the reform, engaging with how the new rules on republication, takedown/de-indexing orders and limitation periods would affect publishers.","url":"https://www.law360.ca/ca/articles/2408050/saskatchewan-introduces-legislation-to-modernize-defamation-laws"}]},"sk-bill-57":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-57.pdf","factCheck":"Verified: Bill 57, The Information Services Corporation Amendment Act, 2026, was introduced April 22, 2026 and passed in spring 2026. It lifts the prior requirement that government hold at least ~15% of ISC (the former land-titles/registry Crown), strengthens the government's 'Golden Share' (keeping ISC's intellectual property, head office, jobs and service obligations in Saskatchewan and securing two board appointments), and enabled the subsequent sale of the province's roughly 30% stake (announced May 2026), netting about $277 million directed to health-care infrastructure. Common misinformation correction: ISC was already a publicly traded company (privatized via IPO in 2013), so Bill 57 enabled the government to sell its remaining minority stake and remove the ownership floor, rather than 'privatizing a Crown corporation' for the first time.","sources":[{"title":"Bill No. 57 - The Information Services Corporation Amendment Act, 2026 (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-57.pdf","type":"official"},{"title":"Saskatchewan Introduces Legislation to Amend the Information Services Corporation Act (Govt of Saskatchewan)","url":"https://www.saskatchewan.ca/Government/News-and-Media/2026/april/22/saskatchewan-introduces-legislation-to-amend-the-information-services-corporation-act","type":"official"},{"title":"Amid offers to buy ISC, Sask. government says legislation will protect residents' interests (CBC News)","url":"https://www.cbc.ca/news/canada/saskatchewan/sask-legislation-sale-of-information-services-corporation-9.7175155","type":"news"},{"title":"ISC sale sparks criticism over Sask. government's long-term investment plan (CBC News)","url":"https://www.cbc.ca/news/canada/saskatchewan/sask-information-services-corp-sale-debate-investment-plan-9.7206431","type":"news"},{"title":"Government of Saskatchewan Supports Information Services Corporation Acquisition (Govt of Saskatchewan)","url":"https://www.saskatchewan.ca/government/news-and-media/2026/may/19/government-of-saskatchewan-supports-information-services-corporation-acquisition","type":"official"}],"commentary":[{"source":"Government of Saskatchewan / Crown Investments Corporation","stance":"support","quote":"The amendments strengthen the Golden Share so ISC's intellectual property, head office and jobs stay in Saskatchewan and service obligations are maintained, while proceeds (about $277 million) fund health-care infrastructure.","url":"https://www.saskatchewan.ca/government/news-and-media/2026/may/19/government-of-saskatchewan-supports-information-services-corporation-acquisition"},{"source":"Aleana Young, Saskatchewan NDP Crown Investments Corporation critic","stance":"oppose","quote":"Removing the 15 per cent ownership cap and selling the province's stake means Saskatchewan people lose control of ISC, opening the door to fee hikes and even a future sale to a foreign owner.","url":"https://www.cbc.ca/news/canada/saskatchewan/sask-information-services-corp-sale-debate-investment-plan-9.7206431"}]},"sk-bill-608":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-608.pdf","factCheck":"Verified: Bill 608, The Rent Control Act, 2025, is an NDP private member's bill (sponsored by housing critic April ChiefCalf) introduced in November 2025 that would amend The Residential Tenancies Act to cap annual rent increases, tied to the Consumer Price Index averaged over a 12-month period. Common misinformation correction: this is an Opposition private member's bill and the Sask. Party majority government has repeatedly stated it opposes rent control, so the bill is not expected to pass; it remained at second reading as of mid-2026 and had not become law.","sources":[{"title":"Bill No. 608 - The Rent Control Act, 2025 (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-608.pdf","type":"official"},{"title":"Sask. NDP introduces rent control legislation, but government says it won't happen (CBC News)","url":"https://www.cbc.ca/news/canada/saskatchewan/sask-ndp-rental-cap-2025-9.6990504","type":"news"},{"title":"NDP introduces Rent Control Act in legislature; province says it would hurt housing supply (SaskToday.ca)","url":"https://www.sasktoday.ca/provincial-news/ndp-introduces-rent-control-act-in-legislature-11532952","type":"news"},{"title":"Carla Beck's NDP Introduces Rent Control Bill to Make Life More Affordable (Saskatchewan NDP Caucus)","url":"https://www.ndpcaucus.sk.ca/carla_beck_s_ndp_introduces_rent_control_bill_to_make_life_more_affordable","type":"advocacy"}],"commentary":[{"source":"April ChiefCalf / Carla Beck, Saskatchewan NDP","stance":"support","quote":"The Rent Control Act would restore balance for renters by tying maximum increases to inflation (CPI), helping make life more affordable in a system that isn't working for Saskatchewan residents.","url":"https://www.ndpcaucus.sk.ca/carla_beck_s_ndp_introduces_rent_control_bill_to_make_life_more_affordable"},{"source":"Government of Saskatchewan (Sask. Party)","stance":"oppose","quote":"Rent control 'has caused housing shortages and increased costs wherever it has been implemented,' and the government will not introduce it.","url":"https://www.sasktoday.ca/provincial-news/ndp-introduces-rent-control-act-in-legislature-11532952"},{"source":"Housing-supply economists (cited in regional coverage)","stance":"oppose","quote":"Experts warn rent caps can worsen housing shortages by discouraging new rental construction.","url":"https://www.620ckrm.com/2025/11/28/ndp-pushes-rent-control-bill-as-experts-warn-of-housing-shortages/"}]},"sk-bill-611":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-611.pdf","factCheck":"Verified: Bill 611, The Constitutional Questions (Notwithstanding Clause Referral) Amendment Act, is an NDP private member's bill (sponsored by House leader Nicole Sarauer) introduced in early December 2025. It would require that whenever Saskatchewan passes a law invoking section 33 of the Charter (the notwithstanding clause), the government must refer that law to the Court of Appeal within 90 days for an opinion on whether it violates Charter sections 2 or 7-15 and is justified under section 1. IMPORTANT misinformation correction: contrary to some circulating claims that it 'received assent,' the Sask. Party majority government rejected the bill (Justice Minister Tim McLeod opposed it), and as a defeated/stalled Opposition private member's bill it did NOT become law.","sources":[{"title":"Bill No. 611 - The Constitutional Questions (Notwithstanding Clause Referral) Amendment Act (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-611.pdf","type":"official"},{"title":"Government rejects NDP legislation reviewing future use of notwithstanding clause in Sask. (CBC News)","url":"https://www.cbc.ca/news/canada/saskatchewan/sask-ndp-notwithstanding-clause-review-9.7003404","type":"news"},{"title":"New NDP bill targets province's use of notwithstanding clause (SaskToday.ca)","url":"https://www.sasktoday.ca/provincial-news/new-ndp-bill-targets-provinces-use-of-notwithstanding-clause-11580410","type":"news"},{"title":"CUPE Saskatchewan backs new bill to safeguard workers' rights (CUPE)","url":"https://cupe.ca/cupe-saskatchewan-backs-new-bill-safeguard-workers-rights","type":"advocacy"}],"commentary":[{"source":"Nicole Sarauer, Saskatchewan NDP House leader (sponsor)","stance":"support","quote":"The bill is meant to protect workers' rights and wages from any attempt to use the notwithstanding clause to override collective bargaining; pointing to Alberta, 'we can't let the same thing happen here in Saskatchewan.'","url":"https://www.620ckrm.com/2025/12/04/new-ndp-bill-targets-provinces-use-of-notwithstanding-clause/"},{"source":"Tim McLeod, Minister of Justice and Attorney General (Sask. Party)","stance":"oppose","quote":"The notwithstanding clause is a right of the people of Saskatchewan for democratic consideration, not something that should be subject to mandatory judicial review.","url":"https://www.cbc.ca/news/canada/saskatchewan/sask-ndp-notwithstanding-clause-review-9.7003404"},{"source":"CUPE Saskatchewan","stance":"support","quote":"CUPE backs the bill as a safeguard for workers' rights, adding transparency and a check on unilateral use of the notwithstanding clause.","url":"https://cupe.ca/cupe-saskatchewan-backs-new-bill-safeguard-workers-rights"}]},"sk-bill-628":{"officialUrl":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-628.pdf","factCheck":"Verified: Bill 628, The Freedom of Information and Protection of Privacy Amendment Act, is an NDP private member's bill (sponsored by Meara Conway, MLA for Regina Elphinstone-Centre and a lawyer) that received first reading on May 13, 2026; it proposes amendments to Saskatchewan's FOIP Act. Common misinformation correction: as a recently introduced Opposition private member's bill, it is at an early stage and unlikely to pass without government support, and it should NOT be confused with the separate government bill on online-investigation/surveillance powers that drew privacy concerns in May 2026 - that is a different piece of legislation. (Note: detailed substantive provisions of Bill 628 were not fully confirmable from secondary sources; the official text is the authoritative reference.)","sources":[{"title":"Bill No. 628 - The Freedom of Information and Protection of Privacy Amendment Act (official text, 30L2S)","url":"https://docs.legassembly.sk.ca/legdocs/Bills/30L2S/Bill30-628.pdf","type":"official"},{"title":"Orders of the Day, May 13, 2026 - first reading of Bill No. 628 (Legislative Assembly of Saskatchewan)","url":"https://docs.legassembly.sk.ca/legdocs/Assembly/Orders/30L2S/20260513Orders-HTML.htm","type":"official"},{"title":"Meara Conway (Wikipedia) - confirms NDP MLA and Shadow Minister role","url":"https://en.wikipedia.org/wiki/Meara_Conway","type":"news"},{"title":"Office of the Saskatchewan Information and Privacy Commissioner","url":"https://oipc.sk.ca/","type":"official"}],"commentary":[{"source":"Meara Conway, Saskatchewan NDP MLA (sponsor)","stance":"support","quote":"Conway, an NDP MLA and lawyer, introduced the bill to amend Saskatchewan's access-to-information and privacy framework; as the sponsor she advances it as a transparency/accountability reform.","url":"https://docs.legassembly.sk.ca/legdocs/Assembly/Orders/30L2S/20260513Orders-HTML.htm"},{"source":"Office of the Saskatchewan Information and Privacy Commissioner (context)","stance":"mixed","quote":"Saskatchewan's privacy watchdog has repeatedly called for FOIP modernization, providing context for Opposition amendment efforts, though the IPC has not issued a specific endorsement of this private member's bill.","url":"https://oipc.sk.ca/legislation-main/"}]},"nb-bill-49":{"officialUrl":"https://www.legnb.ca/en/legislation/bills/61/2/24/pay-transparency-act","factCheck":"Bill 49, An Act Respecting Property Tax Reform (sponsor Hon. Aaron Kennedy), is from the 61st Legislature, 2nd Session and received Royal Assent on June 12, 2026; the official status page is at legnb.ca/en/legislation/bills/61/2/49. It tightens rules so municipal tax-rate increases require a public council vote and gives municipalities more room (raising the cap from roughly 41% to 50%) to set lower residential rates relative to commercial/industrial rates. A common point of confusion is conflating this Act with the earlier 2025 one-year assessment freeze; municipal critics' '$58 million' figure and the freeze relate to that prior affordability measure rather than to Bill 49 itself.","sources":[{"title":"Bill 49 - An Act Respecting Property Tax Reform (status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/49/","type":"official"},{"title":"N.B. property tax changes target municipal revenue windfalls fuelled by soaring assessments (CBC News)","url":"https://www.cbc.ca/news/canada/new-brunswick/new-brunswick-property-tax-changes-9.7214102","type":"news"},{"title":"Property Tax Reform: A Freeze That Undermines Municipalities (UMNB press release)","url":"https://umnb.ca/press-release-property-tax-reform-a-freeze-that-undermines-municipalities/","type":"advocacy"},{"title":"Province puts pressure on local governments with property tax reforms (Canadian Accountant)","url":"https://www.canadian-accountant.com/content/taxation/nb-property-tax-reforms","type":"news"}],"commentary":[{"source":"Hon. Aaron Kennedy, Minister of Local Government (NB)","stance":"support","quote":"New Brunswickers told us they are worried about unpredictable property tax bills and unclear assessment processes; these changes create a more stable, predictable and transparent system that taxpayers can trust and local governments can rely on.","url":"https://www.cbc.ca/news/canada/new-brunswick/new-brunswick-property-tax-changes-9.7214102"},{"source":"Union of Municipalities of New Brunswick (UMNB), Brittany Merrifield, President","stance":"oppose","quote":"An assessment freeze is not property tax reform. The freeze puts more pressure on property taxpayers as municipalities rely on property taxes for 85% of our budgets.","url":"https://umnb.ca/press-release-property-tax-reform-a-freeze-that-undermines-municipalities/"},{"source":"Canadian Accountant (industry analysis)","stance":"mixed","quote":"The reforms shift fiscal pressure onto local governments and constrain their revenue tools even as the province frames the package as taxpayer relief.","url":"https://www.canadian-accountant.com/content/taxation/nb-property-tax-reforms"}]},"nb-bill-45":{"officialUrl":"https://www.legnb.ca/en/legislation/bills/61/2/45/","factCheck":"Bill 45, the Mineral Resources Act (sponsor Hon. John Herron), passed and received Royal Assent on June 12, 2026; it replaces the 1985 Mining Act with a framework meant to streamline approvals for critical-minerals projects while leaving most detail to regulations to be developed over roughly 14 months after assent. It is provincial legislation and is distinct from the federal omnibus 'Bill C-45'; despite some claims it sidelines Indigenous communities, the province says it held consultations with First Nations leaders and that Indigenous leaders will be involved in drafting the regulations, though environmental and Indigenous groups dispute the adequacy of that engagement.","sources":[{"title":"Bill 45 - Mineral Resources Act (status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/45/","type":"official"},{"title":"New Brunswick Scraps Old Mining Act to Fast-Track Critical Minerals Projects (Investing News Network)","url":"https://investingnews.com/new-brunswick-mining-reform-bill/","type":"news"},{"title":"New Brunswick revamping mining regulations to spark critical minerals sector growth (Canadian Press)","url":"https://www.thecanadianpressnews.ca/business/new-brunswick-revamping-mining-regulations-to-spark-critical-minerals-sector-growth/article_54faa747-ac03-5517-b32b-8182e8145571.html","type":"news"},{"title":"Letter to NB Minister of Natural Resources: Recommended Amendments to Bill 45 (East Coast Environmental Law)","url":"https://www.ecelaw.ca/resources-library/letter-to-nb-minister-of-natural-resources-recommended-amendments-to-bill-45-mineral-resources-act","type":"legal"}],"commentary":[{"source":"Hon. John Herron, Minister of Natural Resources (NB)","stance":"support","quote":"The goal is for New Brunswick to become the top jurisdiction in Canada for mining development, cutting red tape and accelerating the permitting pipeline while upholding environmental standards and Indigenous rights.","url":"https://investingnews.com/new-brunswick-mining-reform-bill/"},{"source":"East Coast Environmental Law","stance":"mixed","quote":"The province has an opportunity to modernize mineral law in a way that supports responsible development while strengthening environmental protection, transparency, enforcement and public participation; the Bill should be amended to provide stronger tools to prevent harm and reduce long-term liabilities.","url":"https://www.ecelaw.ca/resources-library/letter-to-nb-minister-of-natural-resources-recommended-amendments-to-bill-45-mineral-resources-act"},{"source":"Glen Savoie, Progressive Conservative interim leader","stance":"mixed","quote":"My concerns lie with this government's ability to manage their way through this without taking shortcuts on either side, including consultation with First Nations.","url":"https://www.thecanadianpressnews.ca/business/new-brunswick-revamping-mining-regulations-to-spark-critical-minerals-sector-growth/article_54faa747-ac03-5517-b32b-8182e8145571.html"}]},"nb-bill-50":{"officialUrl":"https://www.legnb.ca/en/legislation/bills/61/2/50/","factCheck":"Bill 50, An Act Respecting the Enforcement of First Nations Laws and the Prosecution of Offences under First Nations Laws (sponsor Justice Minister Hon. Robert McKee), received Royal Assent on June 12, 2026; it amends the Provincial Offences Procedure Act so that provincial enforcement and prosecution procedures can apply to First Nations laws/bylaws where a First Nation chooses to opt in, extends probation and youth-corrections schemes to such matters, and lets First Nations enforcement officers issue tickets with fines returned to the community. It does not create a separate 'Indigenous tier' of courts or transfer Aboriginal-title questions; it routes enforcement of existing First Nations laws through the regular provincial court system, a point critics and supporters characterize very differently.","sources":[{"title":"Bill 50 (status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/50/","type":"official"},{"title":"Proposed amendments to support enforcement of First Nations bylaws (Government of New Brunswick news release)","url":"https://www.gnb.ca/en/news/n-b.2026.05.proposed-amendments-support-enforcement-first-nations-bylaws.html","type":"official"},{"title":"N.B. proposes legislation to support strength of First Nations bylaws (Law360 Canada)","url":"https://www.law360.ca/ca/criminal/articles/2482575","type":"legal"},{"title":"Jamie Sarkonak: New Brunswick's plan to add an Indigenous tier of justice to the courts (National Post)","url":"https://ca.news.yahoo.com/jamie-sarkonak-brunswicks-plan-add-100023617.html","type":"news"}],"commentary":[{"source":"Chief Allan Polchies, Sitansisk (St. Mary's) First Nation","stance":"support","quote":"These amendments are an important step forward in recognizing First Nations' authority to pass their own laws.","url":"https://www.gnb.ca/en/news/n-b.2026.05.proposed-amendments-support-enforcement-first-nations-bylaws.html"},{"source":"Chief George Ginnish, Natoaganeg (Eel Ground) First Nation","stance":"support","quote":"This legislation is a big step toward making our communities safe for our residents.","url":"https://www.gnb.ca/en/news/n-b.2026.05.proposed-amendments-support-enforcement-first-nations-bylaws.html"},{"source":"Jamie Sarkonak, National Post (opinion)","stance":"oppose","quote":"Seeing to the enforcement of First Nations bylaws is a federal responsibility; the province is taking on a federal obligation it has no jurisdiction over and straining already-stretched courts.","url":"https://ca.news.yahoo.com/jamie-sarkonak-brunswicks-plan-add-100023617.html"}]},"nb-bill-44":{"officialUrl":"https://www.legnb.ca/en/legislation/bills/61/2/44/","factCheck":"Bill 44, An Act to Amend the Lobbyists' Registration Act (sponsor Hon. Robert McKee), received Royal Assent on June 12, 2026; it requires all lobbyists (including in-house lobbyists) to register before lobbying, mandates monthly activity reporting, empowers the Integrity Commissioner to investigate and levy administrative penalties, and directs a lobbyist code of conduct, with a roughly one-year transition before penalties take effect. The change eliminates the prior ~20%-of-time threshold for in-house lobbyists, which officials and analysts expect to grow the registry from under 200 to potentially 2,000+ registrants; the law is enacted but its penalty provisions are not yet in force pending proclamation/transition.","sources":[{"title":"Bill 44 - An Act to Amend the Lobbyists' Registration Act (status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/44/","type":"official"},{"title":"Amendments to Lobbyists' Registration Act introduced (Government of New Brunswick news release)","url":"https://www.gnb.ca/en/news/n-b.2026.05.amendments-lobbyists-registration-act-introduced.html","type":"official"},{"title":"New Brunswick May Enact Canada's Most Onerous Lobbying Disclosure Law (Fasken)","url":"https://www.fasken.com/en/knowledge/2026/05/new-brunswick-may-enact-canadas-most-onerous-lobbying-disclosure-law","type":"legal"},{"title":"New Brunswick government proposes overhaul of lobbying rules (Canadian Press)","url":"https://www.thecanadianpressnews.ca/politics/new-brunswick-government-proposes-overhaul-of-lobbying-rules/article_9e5d92ec-bd30-5f87-9ff2-97a8e86302ab.html","type":"news"}],"commentary":[{"source":"Hon. Robert McKee, Attorney General / Justice Minister (NB)","stance":"support","quote":"We are committed to being an open and accountable government, and these amendments will increase transparency.","url":"https://www.gnb.ca/en/news/n-b.2026.05.amendments-lobbyists-registration-act-introduced.html"},{"source":"Fasken (law firm analysis)","stance":"mixed","quote":"The bill would transform the province's modest regime into arguably the most onerous public-disclosure system in the country, requiring monthly reporting and details of whom lobbyists met, when and where.","url":"https://www.fasken.com/en/knowledge/2026/05/new-brunswick-may-enact-canadas-most-onerous-lobbying-disclosure-law"},{"source":"State and Federal Communications","stance":"mixed","quote":"The amendments mandate monthly reporting and additional disclosures not currently required, and give the Integrity Commissioner authority to investigate violations and impose financial penalties.","url":"https://stateandfed.com/lobbyist-registration/bill-introduced-to-amended-provinces-lobbying-law/"}]},"nb-bill-42":{"officialUrl":"https://www.legnb.ca/en/legislation/bills/61/2/42/","factCheck":"Bill 42, An Act Respecting the Disclosure of Information to Professional Regulatory Bodies (sponsor Hon. Cindy Miles), received Royal Assent on June 12, 2026; rather than a single new statute, it amends several existing Acts (including the Child and Youth Well-Being Act s.22(5) and the Family Services Act s.11(3)) to create exceptions allowing otherwise-confidential information to be shared with a professional regulatory body that is authorized by a private Act to collect information as part of an investigation into the professional services provided by one of its members. It is a targeted disclosure-gateway measure for regulator investigations, not a general expansion of public access to or publication of personal information.","sources":[{"title":"Bill 42 - An Act Respecting the Disclosure of Information to Professional Regulatory Bodies (status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/42/","type":"official"},{"title":"Bill 42 full text (PDF, Legislative Assembly of New Brunswick)","url":"https://www.legnb.ca/content/house_business/61/2/bills/Bill-42.pdf","type":"official"},{"title":"College of Physicians and Surgeons of New Brunswick - Mandatory Reporting","url":"https://cpsnb.org/en/physicians/professional-standards2/professional-standards/436-mandatory-reporting","type":"official"}],"commentary":[{"source":"Hon. Cindy Miles, Minister of Social Development (NB)","stance":"support","quote":"The amendments allow information to be shared with professional regulatory bodies conducting investigations into their members, closing gaps that previously prevented disclosure for accountability purposes.","url":"https://www.gnb.ca/en/news/n-b.2026.05.amendments-lobbyists-registration-act-introduced.html"},{"source":"Progressive Conservative Opposition (NB)","stance":"mixed","quote":"Several of the Liberals' tabled bills, including these information-sharing amendments, amount largely to legislative 'housekeeping' rather than substantive reform.","url":"https://www.thealbertan.com/new-brunswick-news/nb-liberals-table-bills-on-tax-credits-patient-safety-tories-say-its-just-housekeeping-12236198"}]},"nb-bills-46-47":{"officialUrl":"https://www.legnb.ca/en/legislation/bills/61/2/46/","factCheck":"Bill 46 (Energy Sector Consumer Advocate Act) and Bill 47 (An Act Respecting the Energy Sector Consumer Advocate), both sponsored by Energy Minister Hon. René Legacy, received Royal Assent on June 12, 2026; together they create an Energy Sector Consumer Advocate to investigate complaints and represent residents and small businesses before the Energy and Utilities Board, replacing the existing public-intervener role, with the office expected to begin operating in fiscal 2027-2028. The package stems from the NB Power review (government accepted 44 of 50 recommendations); a frequent misconception is that it sets or freezes electricity rates, but the advocate cannot set rates, and the government has not committed to barring future rate intervention.","sources":[{"title":"Bill 46 - Energy Sector Consumer Advocate Act (status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/46/","type":"official"},{"title":"Bill 47 - An Act Respecting the Energy Sector Consumer Advocate (status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/47/","type":"official"},{"title":"Liberal bill creating energy advocate 'quite progressive,' ex-intervener says (CBC News)","url":"https://www.cbc.ca/news/canada/new-brunswick/liberal-bill-energy-advocate-9.7214011","type":"news"},{"title":"N.B. tables bill to create energy advocate to represent residents, small businesses (Global News)","url":"https://globalnews.ca/news/11864934/new-brunswick-energy-advocate/","type":"news"},{"title":"N.B. vows public utility overhaul, but doesn't commit to non-interference (Global News)","url":"https://globalnews.ca/news/11863219/nb-power-consumer-advocate-energy/","type":"news"}],"commentary":[{"source":"Hon. René Legacy, Minister of Energy (NB)","stance":"support","quote":"The advocate's office will give people a stronger voice and better support navigating the system; if there's non-resolution, they can escalate and the board can order a corrective measure.","url":"https://globalnews.ca/news/11864934/new-brunswick-energy-advocate/"},{"source":"Kris Austin, Progressive Conservative energy critic","stance":"mixed","quote":"I don't think it's going to be good or bad, I think it's just one of these neutral things; it won't adequately address affordability, and government should focus on stabilizing and lowering rates.","url":"https://globalnews.ca/news/11864934/new-brunswick-energy-advocate/"},{"source":"Lori Clark, NB Power CEO","stance":"mixed","quote":"Rate freezes have gotten us where we are today, and I'm not sure that is a good solution for the future.","url":"https://globalnews.ca/news/11863219/nb-power-consumer-advocate-energy/"}]},"nb-bill-24":{"officialUrl":"https://www.legnb.ca/en/legislation/bills/61/2/24/pay-transparency-act","factCheck":"Bill 24, the Pay Transparency Act (sponsor Hon. Lyne Chantal Boudreau), was introduced March 18, 2026 and received Royal Assent on June 12, 2026; it requires salary ranges in job postings, bars employers from relying on a candidate's salary history, protects employees from reprisal for discussing wages, and phases in annual pay-transparency reporting for 'reporting employers' with 50 or more employees. It is a transparency/disclosure law, not a full pay-equity regime for the private sector; advocates describe it as 'groundwork' for future private-sector pay equity, and many operational details (including reporting timelines and the employee-size phase-in) are to be set out in regulations.","sources":[{"title":"Bill 24 - Pay Transparency Act (status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/24/pay-transparency-act","type":"official"},{"title":"Bill to identify gaps in pay equity now law in N.B. (CBC News)","url":"https://www.cbc.ca/news/canada/new-brunswick/pay-transparency-act-equity-new-brunswick-workers-9.7233312","type":"news"},{"title":"Unifor-backed pay equity recommendations become law in New Brunswick (Unifor)","url":"https://www.unifor.org/news/all-news/unifor-backed-pay-equity-recommendations-become-law-new-brunswick","type":"advocacy"},{"title":"New Brunswick introduces pay transparency rules for job postings and wage discussions (HR Law Canada)","url":"https://hrlawcanada.com/2026/03/new-brunswick-introduces-pay-transparency-rules-for-job-postings-and-wage-discussions/","type":"legal"}],"commentary":[{"source":"New Brunswick Coalition for Pay Equity","stance":"support","quote":"This act sends a powerful message that transparency and equity are essential for building an inclusive workforce, and lays the groundwork for implementing pay equity in the private sector.","url":"https://www.cbc.ca/news/canada/new-brunswick/pay-transparency-act-equity-new-brunswick-workers-9.7233312"},{"source":"Unifor (Jennifer Murray, Atlantic Regional Director)","stance":"support","quote":"It's a huge step forward for workers, after decades of advocacy, toward closing the gender pay gap.","url":"https://www.unifor.org/news/all-news/unifor-backed-pay-equity-recommendations-become-law-new-brunswick"},{"source":"Retail Council of Canada","stance":"mixed","quote":"In principle, RCC is not opposed to such action, but much detail remains unknown because many requirements will be developed in regulations; we will be speaking with the Department on the Bill and resulting regulations.","url":"https://www.retailcouncil.org/new-brunswick-tables-bills-on-sick-leave-and-pay-transparency/"}]},"nb-bill-26":{"officialUrl":"https://www.legnb.ca/content/house_business/61/2/bills/Bill-26-e.htm","factCheck":"Bill 26, An Act to Amend the Employment Standards Act (long-term illness and injury leave), received Royal Assent on June 12, 2026; it creates a new job-protected, unpaid Long-Term Illness and Injury Leave of up to 27 weeks in any 52-week period for employees with more than 90 continuous days of service, supported by a medical certificate. The leave is unpaid (not paid sick leave) and is separate from, and does not replace, an employer's human-rights duty to accommodate; it brings New Brunswick roughly into line with the longer illness-leave entitlements in most other provinces and the federal jurisdiction.","sources":[{"title":"Bill 26 - An Act to Amend the Employment Standards Act (official text)","url":"https://www.legnb.ca/content/house_business/61/2/bills/Bill-26-e.htm","type":"official"},{"title":"Long-Term Illness and Injury Leave on the Horizon for Employers: NB Bill 26 (McInnes Cooper)","url":"https://www.mcinnescooper.com/publications/long-term-illness-and-injury-leave-on-the-horizon-for-employers-nb-bill-26/","type":"legal"},{"title":"Employment act amendments would bring N.B. in line with rest of Canada, law professor says (CBC News)","url":"https://www.cbc.ca/news/canada/new-brunswick/employment-act-amendments-law-professor-9.7148388","type":"news"},{"title":"New Brunswick proposes expanding unpaid illness leave to 27 weeks (HR Law Canada)","url":"https://hrlawcanada.com/2026/03/new-brunswick-proposes-expanding-unpaid-illness-leave-to-27-weeks/","type":"legal"}],"commentary":[{"source":"McInnes Cooper (employment law analysis)","stance":"mixed","quote":"This is a meaningful shift in New Brunswick's employment standards framework, expanding job-protected leave for employees while imposing new compliance obligations on employers; the leave does not displace the separate duty to accommodate.","url":"https://www.mcinnescooper.com/publications/long-term-illness-and-injury-leave-on-the-horizon-for-employers-nb-bill-26/"},{"source":"Law professor (CBC interview)","stance":"support","quote":"The amendments would bring New Brunswick in line with the rest of Canada, where much longer illness leaves are already standard, replacing the province's minimal five-day allowance.","url":"https://www.cbc.ca/news/canada/new-brunswick/employment-act-amendments-law-professor-9.7148388"},{"source":"Retail Council of Canada","stance":"mixed","quote":"Employers need clarity and lead time on the new long-term leave and its interaction with existing obligations before the requirements take effect.","url":"https://www.retailcouncil.org/new-brunswick-tables-bills-on-sick-leave-and-pay-transparency/"}]},"nb-bill-2":{"officialUrl":"https://www.legnb.ca/en/legislation/bills/61/2/2/","factCheck":"Bill 2, An Act to Amend the Public Health Act (sponsor Health Minister Hon. John Dornan), was read first time October 22, 2025 and received Royal Assent on December 12, 2025; it has the cabinet (Lieutenant-Governor in Council) appoint the Chief Medical Officer of Health from an eligibility list provided by the Minister for a term of up to seven years (renewable to a ten-year maximum), allows removal 'for cause' by cabinet, deems the CMOH a civil servant, and adds a deputy chief medical officer of health to the Act. Contrary to claims that it lets government fire the top doctor at will or strip the role's independence, removal is limited to 'for cause' and the Act adds a written-directive requirement; critics nonetheless argue cabinet appointment could increase political influence over the position.","sources":[{"title":"Bill 2 - An Act to Amend the Public Health Act (61st Leg., 2nd Sess., status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/2/","type":"official"},{"title":"Bill 2 full text (PDF, Legislative Assembly of New Brunswick)","url":"https://www.legnb.ca/content/house_business/61/2/bills/Bill-2.pdf","type":"official"},{"title":"Bill that would see N.B. cabinet appoint chief health officer draws mixed reaction (CBC News)","url":"https://www.cbc.ca/news/canada/new-brunswick/chief-medical-officer-health-bill-9.6952249","type":"news"},{"title":"Dr. Yves Léger officially appointed to replace Dr. Jennifer Russell as N.B.'s top doctor (CBC News)","url":"https://www.cbc.ca/news/canada/new-brunswick/yves-leger-chief-medical-officer-of-health-new-brunswick-jennifer-russell-1.7476667","type":"news"}],"commentary":[{"source":"Hon. John Dornan, Minister of Health (NB)","stance":"support","quote":"New Brunswickers deserve public health decisions rooted in science, not politics.","url":"https://ca.news.yahoo.com/bill-see-n-b-cabinet-090000071.html"},{"source":"Dr. Lise Babin, President, New Brunswick Medical Society","stance":"support","quote":"The changes would reduce the risk of political interference; it gives a certain protection.","url":"https://ca.news.yahoo.com/bill-see-n-b-cabinet-090000071.html"},{"source":"Bill Hogan, Progressive Conservative health critic","stance":"oppose","quote":"I think it makes it more political, and I question the purpose of giving cabinet authority over the chief medical officer's dismissal.","url":"https://ca.news.yahoo.com/bill-see-n-b-cabinet-090000071.html"},{"source":"David Coon, Green Party Leader","stance":"oppose","quote":"The amendments accomplish very little and miss the opportunity to rebuild the chief medical officer's mandate and resources.","url":"https://ca.news.yahoo.com/bill-see-n-b-cabinet-090000071.html"}]},"nb-bill-40":{"officialUrl":"https://www.legnb.ca/en/legislation/bills/61/2/40/","factCheck":"Bill 40, An Act Respecting Health Quality and Patient Safety (sponsor Health Minister Hon. John Dornan), received Royal Assent on June 12, 2026; it broadens definitions of patient-safety incidents, strengthens processes for reviewing serious incidents, and enables patient-safety committees across New Brunswick's two health networks (Horizon and Vitalité) to share information for system-wide learning. The minister has stated the bill was not prompted by any single incident but modernizes existing legislation; some opposition members characterized the Liberals' batch of tabled bills, including this one, as largely 'housekeeping.'","sources":[{"title":"Bill 40 - An Act Respecting Health Quality and Patient Safety (status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/40/","type":"official"},{"title":"N.B. introducing legislative changes for better patient safety, quality of care (Law360 Canada)","url":"https://www.law360.ca/ca/accesstojustice/articles/2474541","type":"legal"},{"title":"N.B. Liberals table bills on tax credits, patient safety; Tories say it's just 'housekeeping' (The Albertan / Canadian Press)","url":"https://www.thealbertan.com/new-brunswick-news/nb-liberals-table-bills-on-tax-credits-patient-safety-tories-say-its-just-housekeeping-12236198","type":"news"}],"commentary":[{"source":"Hon. John Dornan, Minister of Health (NB)","stance":"support","quote":"These amendments will help ensure we learn from patient safety incidents, share that knowledge, and take action to prevent them; this had nothing to do with a specific incident, it's modernizing our legislation.","url":"https://www.law360.ca/ca/accesstojustice/articles/2474541"},{"source":"Progressive Conservative Opposition (NB)","stance":"mixed","quote":"The tabled bills, including the patient-safety legislation, amount largely to 'housekeeping' rather than substantive new measures.","url":"https://www.thealbertan.com/new-brunswick-news/nb-liberals-table-bills-on-tax-credits-patient-safety-tories-say-its-just-housekeeping-12236198"}]},"nb-bill-21":{"officialUrl":"https://www.legnb.ca/en/legislation/bills/61/2/21/","factCheck":"Bill 21, An Act to Amend the Child and Youth Well-Being Act (sponsor Hon. Cindy Miles), was read first time November 21, 2025 and received Royal Assent in 2026; it amends subsection 47(3) to expressly let the Minister of Social Development enter into agreements (including custody or guardianship agreements) with a parent to protect a child's well-being without returning the child to the parent, and it retroactively deems such agreements made from January 26, 2024 onward to be valid agreements under the new paragraph 47(3)(b.1). This is a narrow, technical/curative amendment tied to operational gaps following the 2022 Child and Youth Well-Being Act's implementation; it should not be confused with the separate 2024 'child-protection legislative gap' that New Brunswick's Court of Appeal ultimately ruled did not exist.","sources":[{"title":"Bill 21 - An Act to Amend the Child and Youth Well-Being Act (status page)","url":"https://www.legnb.ca/en/legislation/bills/61/2/21/","type":"official"},{"title":"Bill 21 full text (PDF, Legislative Assembly of New Brunswick)","url":"https://www.legnb.ca/content/house_business/61/2/bills/Bill-21.pdf","type":"official"},{"title":"An Act Respecting Child and Youth Well-Being (SNB 2023, c 36) (CanLII)","url":"https://www.canlii.org/en/nb/laws/astat/snb-2023-c-36/latest/snb-2023-c-36.html","type":"legal"},{"title":"N.B.'s top court closes child protection 'gap' by saying it never existed (CBC News)","url":"https://www.cbc.ca/news/canada/new-brunswick/new-brunswick-court-closes-child-protection-gap-legislative-error-1.7112708","type":"news"}],"commentary":[{"source":"Hon. Cindy Miles, Minister of Social Development (NB)","stance":"support","quote":"The amendment confirms the Minister's authority to enter custody or guardianship agreements with a parent to protect a child without returning the child to the parent's care, and validates agreements already made on that basis.","url":"https://www.legnb.ca/content/house_business/61/2/bills/Bill-21.pdf"},{"source":"Progressive Conservative Opposition (NB)","stance":"mixed","quote":"Several of the government's tabled amendments, including child-welfare changes, are characterized as technical 'housekeeping' rather than substantive reform of the child-protection system.","url":"https://www.thealbertan.com/new-brunswick-news/nb-liberals-table-bills-on-tax-credits-patient-safety-tories-say-its-just-housekeeping-12236198"}]},"pe-operating-budget-2026-27-appropriation-act-bu":{"officialUrl":"https://www.princeedwardisland.ca/en/information/finance-and-affordability/provincial-budget-operating-budget","factCheck":"Verified: Finance Minister Jill Burridge tabled the 2026-27 operating budget on April 14, 2026, projecting a record ~$410M deficit (revenues ~$3.4B, spending ~$3.8B); it passed during the spring sitting. Key affordability/tax measures include a new PEI Essentials Benefit (replacing the eliminated 10% Energy Rebate Program after June 2026), an enhanced PEI Child Benefit, a higher basic personal amount, a new 20% top income-tax bracket on income over $200,000 starting 2027, and a higher non-resident property tax rate. A common misconception is that the budget cut electricity bills; in fact it scrapped the electricity rebate, so many Islanders' power bills are set to rise, with offsetting cash delivered via the Essentials Benefit.","sources":[{"title":"Provincial Budget: Operating Budget - Government of PEI (official)","url":"https://www.princeedwardisland.ca/en/information/finance-and-affordability/provincial-budget-operating-budget","type":"official"},{"title":"P.E.I. government projects $410M deficit, warns of tough choices ahead - CBC News","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-operating-budget-2026-2027-9.7163389","type":"news"},{"title":"Key tax updates from Prince Edward Island's 2026 budget - Baker Tilly","url":"https://www.bakertilly.ca/insights/tax-alert-pei-2026-budget","type":"legal"},{"title":"Highlights of the 2026 P.E.I. budget - KPMG","url":"https://kpmg.com/ca/en/insights/2026/04/highlights-of-the-2026-pei-budget.html","type":"legal"},{"title":"PEI Budget 2026: Red soil province awash in red - RBC Economics","url":"https://www.rbc.com/en/economics/canadian-analysis/provincial-and-fiscal-outlooks/provincial-budgets-and-economic-statements/pei-budget-2026-red-soil-province-awash-in-never-ending-red/","type":"academic"}],"commentary":[{"source":"Jill Burridge, PEI Finance Minister","stance":"support","quote":"“This is a budget of some very difficult decisions this year, absolutely... And it doesn't end here.” She framed the Essentials Benefit as putting cash directly into Islanders' pockets for groceries, housing or electricity.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-operating-budget-2026-2027-9.7163389"},{"source":"RBC Economics","stance":"mixed","quote":"Characterized PEI as a 'red soil province awash in never-ending red,' flagging the record deficit and rising net debt while noting the affordability spending.","url":"https://www.rbc.com/en/economics/canadian-analysis/provincial-and-fiscal-outlooks/provincial-budgets-and-economic-statements/pei-budget-2026-red-soil-province-awash-in-never-ending-red/"},{"source":"Office of the Auditor General of PEI","stance":"oppose","quote":"The AG has repeatedly warned the province to 'rein in spending,' cautioning that large deficits and rising debt pose long-term fiscal risks and calling recent spending levels 'unsustainable.'","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-operating-budget-2026-2027-9.7163389"}]},"pe-bill-102-2026-3rd-session":{"officialUrl":"https://www.assembly.pe.ca/legislative-business/bills","factCheck":"Verified: Bill 102, An Act to Amend the Conflict of Interest Act, was introduced April 17, 2026 by PC backbencher Brendan Curran (not by Sidney MacEwen). It was intended to let cabinet ministers (specifically then-minister Sidney MacEwen) keep a commercial fishing licence while in cabinet rather than placing it in a blind trust. MacEwen resigned from cabinet in late April 2026 before the bill advanced; on May 1, 2026 Curran stepped back from the bill after the Conflict of Interest Commissioner (Judy Burke) called it so broad it 'effectively negates the intent of the Act,' and a legislative committee recommended it not proceed. Correction to common framing: it is sometimes called the 'MacEwen bill,' but MacEwen did not sponsor it; it was a Progressive Conservative member's bill, and it was set aside/left on the order paper, not formally voted down or fully withdrawn.","sources":[{"title":"Legislative Assembly of PEI - Bills (official)","url":"https://www.assembly.pe.ca/legislative-business/bills","type":"official"},{"title":"Bill to keep Sidney MacEwen in cabinet shelved as commissioner calls it too broad - CBC News","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-bill-to-keep-sidney-macewan-put-on-hold-9.7183983","type":"news"},{"title":"Greens slam PC's conflict of interest bill as 'scramble' to keep MacEwen in cabinet - CBC News","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-legislature-conflict-of-interest-act-amendment-9.7167349","type":"news"},{"title":"Prince Edward Island drops controversial bill that would have softened ethics rules - The Canadian Press","url":"https://www.thecanadianpressnews.ca/business/prince-edward-island-abandons-bill-to-soften-ethics-rules-after-backlash/article_6e397501-837d-5380-b437-5c308c514566.html","type":"news"}],"commentary":[{"source":"Judy Burke, PEI Conflict of Interest Commissioner","stance":"oppose","quote":"“In my view the proposed amendment to the act is so broad that it effectively negates the intent of the Conflict of Interest Act... If this bill is enacted, where is the line?”","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-bill-to-keep-sidney-macewan-put-on-hold-9.7183983"},{"source":"Matt MacFarlane, Green Party Leader","stance":"oppose","quote":"Called the bill a 'scramble' to keep MacEwen in cabinet: 'This situation could have been put on the floor of the legislature at any time over the last seven years... now they're trying to scramble to find a way to allow him to continue.'","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-legislature-conflict-of-interest-act-amendment-9.7167349"},{"source":"Brendan Curran, PC MLA (sponsor)","stance":"mixed","quote":"“It's not necessarily that I'm pulling the bill. I'm just not going to pursue it currently... I am not going to stop this advocacy for the fishing sector.”","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-bill-to-keep-sidney-macewan-put-on-hold-9.7183983"},{"source":"Premier Rob Lantz","stance":"mixed","quote":"Said he respects Curran's decision to step back and sees it as an opportunity to take a closer look at the province's conflict-of-interest rules, noting the commissioner 'flagged some issues.'","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-bill-to-keep-sidney-macewan-put-on-hold-9.7183983"}]},"pe-lands-protection-act-amendment-2026-3rd-sessi":{"officialUrl":"https://www.princeedwardisland.ca/sites/default/files/publications/30498_pei_lands_pro_consult_2025_final.pdf","factCheck":"Verified: The PEI Department of Housing, Land and Communities proposed amending the Lands Protection Act so that non-residents (people who don't already own PEI property) buying a lot of one acre or less inside a municipality with an official plan would need Cabinet approval, while properties of five acres or less outside such municipalities would not. Note on status: this began as a government consultation released in spring 2025 (consultation document V05) and, as of mid-2026, the research could not confirm it had been introduced as a numbered government bill that passed; it is best described as a proposed amendment/consultation rather than enacted law. (Bill numbers can be reused across General Assemblies in PEI, so older 'Lands Protection Act' bill numbers should not be conflated with this proposal.)","sources":[{"title":"An Act to Amend the PEI Lands Protection Act - consultation draft (official PDF)","url":"https://www.princeedwardisland.ca/sites/default/files/publications/30498_pei_lands_pro_consult_2025_final.pdf","type":"official"},{"title":"Province implements actions on land - Government of PEI (official news)","url":"https://www.princeedwardisland.ca/en/news/province-implements-actions-on-land","type":"official"},{"title":"Proposed changes for non-Islanders buying municipal property facing criticism - CBC News","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-lands-protection-act-proposed-changes-1.7516945","type":"news"},{"title":"Lands Protection Act, RSPEI 1988, c L-5 - CanLII (current consolidated Act)","url":"https://www.canlii.org/en/pe/laws/stat/rspei-1988-c-l-5/latest/rspei-1988-c-l-5.html","type":"legal"}],"commentary":[{"source":"Satya Sen, Executive Director, Federation of PEI Municipalities","stance":"mixed","quote":"“I understand the government's rationale... Land protection is important. But there could be unintended consequences.” He warned 'bureaucratic red tape' could push buyers outside municipal boundaries and fuel sprawl, asking whether Cabinet is ready to approve even a single lot bought by an incoming doctor or nurse.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-lands-protection-act-proposed-changes-1.7516945"},{"source":"Government of PEI (Dept. of Housing, Land and Communities)","stance":"support","quote":"Says the amendment is meant to create more transparency and oversight over who owns land on the 1.4-million-acre Island, balancing population growth and protection of prime agricultural land.","url":"https://www.princeedwardisland.ca/en/news/province-implements-actions-on-land"},{"source":"PEI real estate / housing sector (via CBC reporting)","stance":"oppose","quote":"Realtors and housing advocates warned the extra cabinet-approval step could deter newcomers and immigration and complicate sales for local homeowners trying to sell modest properties.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-lands-protection-act-proposed-changes-1.7516945"}]},"pe-bill-25-2026-3rd-session":{"officialUrl":"https://docs.assembly.pe.ca/download/dms?objectId=09bd951e-bb88-4e8b-aa00-5b34af96b4ab&fileName=Bill+25+Government+Reorg+2026_INTRODUCED.pdf","factCheck":"Verified: Bill 25, the Government Reorganization Act (3rd Session, 67th General Assembly), received first reading April 17, 2026 and is sponsored by Hon. Bloyce Thompson (Minister of Justice and Public Safety / Attorney General). It is an administrative/'housekeeping' bill that reassigns ministerial and departmental responsibility for statutes to reflect the Spring 2026 reorganization of government; it does not itself set policy direction. No notable misinformation found.","sources":[{"title":"Bill 25 - Government Reorganization Act, 2026 (official PDF, Legislative Assembly of PEI)","url":"https://docs.assembly.pe.ca/download/dms?objectId=09bd951e-bb88-4e8b-aa00-5b34af96b4ab&fileName=Bill+25+Government+Reorg+2026_INTRODUCED.pdf","type":"official"},{"title":"Legislative Assembly of PEI - Bills (official)","url":"https://www.assembly.pe.ca/legislative-business/bills","type":"official"},{"title":"Bill 25, Government Reorganization Act - Codify Laws (bill tracker)","url":"https://codifylaws.com/canadian-bill-and-regulation-details/bill-2-government-reorganization-act-pei-bill-1","type":"legal"}],"commentary":[{"source":"Government of PEI (bill text / sponsor Hon. Bloyce Thompson)","stance":"support","quote":"Presented as a routine measure that 'makes changes in Ministerial and Departmental responsibility for acts to reflect the Spring 2026 reorganization of Government.'","url":"https://docs.assembly.pe.ca/download/dms?objectId=09bd951e-bb88-4e8b-aa00-5b34af96b4ab&fileName=Bill+25+Government+Reorg+2026_INTRODUCED.pdf"},{"source":"Codify Laws (legislative tracker)","stance":"mixed","quote":"Lists the bill as a government reorganization statute realigning departmental responsibilities, a typical accompaniment to a cabinet shuffle rather than substantive policy change.","url":"https://codifylaws.com/canadian-bill-and-regulation-details/bill-2-government-reorganization-act-pei-bill-1"}]},"pe-financial-administration-act-amendment-specia":{"officialUrl":"https://www.assembly.pe.ca/legislative-business/bills","factCheck":"Verified: Green Party Leader Matt MacFarlane introduced a private member's bill to amend the Financial Administration Act adding a requirement that a payment under a special warrant first be deemed 'urgently required,' aligning PEI with other Canadian jurisdictions. Notably, the bill PASSED with government support around late March/early April 2026 - a rare instance of a Green opposition bill being adopted. Context (verified): PEI's PC government has relied on special warrants more heavily than any other province that allows them, with the Auditor General warning this undercuts the legislature's spending-oversight role. No notable misinformation found.","sources":[{"title":"Legislative Assembly of PEI - Bills (official)","url":"https://www.assembly.pe.ca/legislative-business/bills","type":"official"},{"title":"Matt MacFarlane passes bill to help rein in reckless government spending - PEI Green Caucus","url":"https://peigreencaucus.ca/2026/04/matt-macfarlane-passes-bill-to-help-rein-in-reckless-government-spending/","type":"advocacy"},{"title":"P.E.I.'s reliance on special warrants undercuts democratic process, says watchdog - Yahoo/CBC","url":"https://ca.news.yahoo.com/p-e-reliance-special-warrants-145916879.html","type":"news"},{"title":"Financial Administration Act, PEI (consolidated, official)","url":"https://www.princeedwardisland.ca/sites/default/files/legislation/f-09-financial_administration_act.pdf","type":"official"}],"commentary":[{"source":"Matt MacFarlane, Green Party Leader (sponsor)","stance":"support","quote":"“This small but significant change will add another layer of accountability regarding government's use, and misuse, of special warrants... and will allow MLAs the ability to further hold government accountable for its spending.”","url":"https://peigreencaucus.ca/2026/04/matt-macfarlane-passes-bill-to-help-rein-in-reckless-government-spending/"},{"source":"Office of the Auditor General of PEI","stance":"support","quote":"Has warned that PEI's heavy reliance on special warrants - roughly 10% of the operating budget at one point, more than any comparable province - undercuts the democratic, legislative spending-approval process.","url":"https://ca.news.yahoo.com/p-e-reliance-special-warrants-145916879.html"}]},"pe-electric-power-act-amendment-2026-3rd-session":{"officialUrl":"https://www.assembly.pe.ca/legislative-business/bills","factCheck":"Verified: Bill 108, An Act to Amend the Electric Power Act, was a Green private member's bill sponsored by MLA Peter Bevan-Baker. It would have shifted Maritime Electric from a cost-of-service model toward a performance-based regulatory framework - tying utility profits to reliability, sustainability and affordability targets and requiring cheaper alternatives be considered before major (largely fossil-fuel) investments. It was DEFEATED in the legislature on May 14, 2026, with the PC majority voting against it. Clarification: Premier Rob Lantz called it 'half-baked' and claimed it would raise prices; Bevan-Baker disputed this, calling it 'incredibly well-researched.' The bill did not 'lower electricity rates' on its own - it aimed to change how rates and investments are regulated.","sources":[{"title":"Legislative Assembly of PEI - Bills (official)","url":"https://www.assembly.pe.ca/legislative-business/bills","type":"official"},{"title":"MLA 'extraordinarily disappointed' after P.E.I. electricity bill defeated - CBC News","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-electricity-bill-defeat-9.7202462","type":"news"},{"title":"Green bill to make PEI's energy system accountable, reliable, and affordable voted down by PC government - PEI Green Caucus","url":"https://peigreencaucus.ca/2026/05/green-bill-to-make-peis-energy-system-accountable-reliable-and-affordable-voted-down-by-pc-government/","type":"advocacy"},{"title":"Electric Power Act, PEI (consolidated, official)","url":"https://www.princeedwardisland.ca/sites/default/files/legislation/e-04-electric_power_act.pdf","type":"official"}],"commentary":[{"source":"Peter Bevan-Baker, Green MLA (sponsor)","stance":"support","quote":"“It's a real loss for Islanders... This was not a half-baked bill. This was an incredibly well-researched bill,” adding it would have forced Maritime Electric to be 'a lot more thoughtful' and take customers' needs and the environment into account.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-electricity-bill-defeat-9.7202462"},{"source":"Premier Rob Lantz","stance":"oppose","quote":"Called the legislation 'half-baked,' arguing the government is already modernizing energy regulation and that Bill 108 would have the opposite effect and increase prices.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-electricity-bill-defeat-9.7202462"},{"source":"Brennan McDuffee, Energy Democracy Now","stance":"support","quote":"Explained the bill would shift Maritime Electric from a cost-of-service to a performance-based model so that 'if Maritime Electric performs well on those performance indicators... their shareholders benefit.'","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-electricity-bill-defeat-9.7202462"}]},"pe-community-care-facilities-and-nursing-homes-a":{"officialUrl":"https://www.assembly.pe.ca/legislative-business/bills","factCheck":"Verified: Green Party Leader Matt MacFarlane introduced a private member's bill to amend the Community Care Facilities and Nursing Homes Act requiring government to set maximum daily accommodation rates annually, beginning July 1, 2026, to make long-term-care rates predictable. The motivation (verified) is that PEI is an outlier - one of the only provinces with no cap on long-term-care/community-care rate increases - with some residents facing increases reported around 24-38% over recent years. Status caveat: research confirmed the bill was tabled in the 2026 spring sitting but could not definitively confirm its final disposition; given the PC majority defeated several other Green private members' bills that sitting (e.g., the electricity and sick-note bills), readers should verify whether it passed before treating it as law.","sources":[{"title":"Legislative Assembly of PEI - Bills (official)","url":"https://www.assembly.pe.ca/legislative-business/bills","type":"official"},{"title":"Matt MacFarlane tabling bill to make long-term care rates fair and predictable for Islanders - PEI Green Caucus","url":"https://peigreencaucus.ca/2026/03/matt-macfarlane-tabling-bill-to-make-long-term-care-rates-fair-and-predictable-for-islanders/","type":"advocacy"},{"title":"P.E.I. Green Party calls for oversight as province remains outlier on long-term care rate controls - CBC News","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-green-party-calls-long-term-care-rate-controls-legislature-9.6992142","type":"news"},{"title":"Community Care Facilities and Nursing Homes Act, PEI (consolidated, official)","url":"https://www.princeedwardisland.ca/sites/default/files/legislation/c-13-community_care_facilities_and_nursing_homes_act.pdf","type":"official"}],"commentary":[{"source":"Matt MacFarlane, Green Party Leader (sponsor)","stance":"support","quote":"Argues seniors deserve the same protection as renters: 'Any other Islander who rents their home is provided strict rate protections under the Residential Tenancy Act,' and pressed government to 'implement fair, transparent and affordable long-term care rates.'","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-green-party-calls-long-term-care-rate-controls-legislature-9.6992142"},{"source":"Mark McLane, PEI Minister of Health and Wellness","stance":"mixed","quote":"Pointed to 'significant' government investments (staff wage parity, allied health in homes) and said 'those costs are expensive... we have held costs for a couple years,' while not committing to legislated rate caps.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-green-party-calls-long-term-care-rate-controls-legislature-9.6992142"}]},"pe-lands-protection-act-amendment-public-land-in":{"officialUrl":"https://www.assembly.pe.ca/legislative-business/bills","factCheck":"Verified: This Green private member's bill, sponsored by Green Party Leader Matt MacFarlane, amends the Lands Protection Act to require that final Island Regulatory and Appeals Commission (IRAC) land-investigation reports and supporting documents be made public/tabled in the legislature (within 15 days of completion), including investigations currently underway. It passed second reading unanimously on November 12, 2025 and was among the bills the Greens 'passed' during the fall sitting that wrapped November 27, 2025. It was prompted by the discovery that a long-sought 2018 IRAC report on Buddhist groups' land holdings did not actually exist. Clarification: the bill is about transparency of IRAC investigations - it does not itself force divestment of any land; PEI's privacy commissioner cautioned that releasing supporting documents must be balanced against privacy (e.g., bank details, religious/political beliefs, confidential informants).","sources":[{"title":"Legislative Assembly of PEI - Bills (official)","url":"https://www.assembly.pe.ca/legislative-business/bills","type":"official"},{"title":"Green Party bill to make land investigations public passes in P.E.I. Legislature - CBC News","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-bill-make-irac-land-investigations-public-passes-second-reading-9.6976663","type":"news"},{"title":"Accusations that Buddhist groups own too much land leads to P.E.I. passing bill that makes investigations go public - CP24/CTV","url":"https://www.cp24.com/news/canada/2025/11/12/pei-passes-bill-to-make-land-investigations-public-amid-scrutiny-of-buddhist-holdings/","type":"news"},{"title":"Matt MacFarlane tabling bill to make land investigations public to Islanders - PEI Green Caucus","url":"https://peigreencaucus.ca/2025/10/matt-macfarlane-tabling-bill-to-make-land-investigations-public-to-islanders/","type":"advocacy"}],"commentary":[{"source":"Matt MacFarlane, Green Party Leader (sponsor)","stance":"support","quote":"“It's time to remove the shroud of secrecy around IRAC... that this government and the ones before it have not only allowed to happen, but have encouraged.”","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-bill-make-irac-land-investigations-public-passes-second-reading-9.6976663"},{"source":"Cory Deagle, Minister of Housing, Land and Communities","stance":"support","quote":"“Overall, I think it's a good thing, and if it can help bring some level of trust back to IRAC, then I think that's something that we can support,” while noting government may revisit it after seeing how it works in practice.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-bill-make-irac-land-investigations-public-passes-second-reading-9.6976663"},{"source":"Denise Doiron, PEI Information and Privacy Commissioner","stance":"mixed","quote":"Raised concerns that the right to know investigation details must be balanced against privacy, since supporting documents could expose bank account numbers, religious or political beliefs, or the identity of a confidential informant.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-bill-make-irac-land-investigations-public-passes-second-reading-9.6976663"},{"source":"Great Enlightenment Buddhist Institute Society (GEBIS)","stance":"support","quote":"Said it 'supports all efforts that provide clarity through new legislation and the release of any materials related to investigations, as these measures can help strengthen trust among Islanders.'","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-bill-make-irac-land-investigations-public-passes-second-reading-9.6976663"}]},"pe-bill-15-2025-2nd-session-foundational-now-in-":{"officialUrl":"https://www.assembly.pe.ca/legislative-business/bills","factCheck":"Verified: Bill 15, the Interprovincial Trade and Mobility Act, was tabled April 11, 2025 by Premier Rob Lantz and passed during the spring sitting (the PC government passed 19 bills that session, with royal assent given on the final day, May 16, 2025). It provides for mutual recognition so that goods/services and certain occupational certifications approved in reciprocating provinces are accepted in PEI without duplicate testing or licensing. It mirrors Nova Scotia's law and complements the federal One Canadian Economy Act. Clarification: it is reciprocal/mutual-recognition legislation that only takes effect with partner provinces - it does not unilaterally deregulate all standards, and (like Manitoba's) it carves out some regulated professions; critics, including PEI's own Financial and Consumer Services Division and opposition parties, warned the consultation was rushed and could raise public-safety concerns.","sources":[{"title":"Legislative Assembly of PEI - Bills (official)","url":"https://www.assembly.pe.ca/legislative-business/bills","type":"official"},{"title":"P.E.I. bill to reduce trade barriers passes 2nd reading despite opposition complaints - CBC News","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-legislature-trade-barrier-bill-1.7515775","type":"news"},{"title":"Even parts of the P.E.I. government say we're moving to eliminate trade barriers too quickly - CBC News","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-interprovincial-trade-government-officials-1.7513457","type":"news"},{"title":"CFIB Highlights Landmark PEI Bill to Boost Trade and Mobility - CFIB","url":"https://www.cfib-fcei.ca/en/media/cfib-highlights-landmark-pei-bill-to-boost-trade-and-mobility","type":"advocacy"},{"title":"Bill 15, Interprovincial Trade and Mobility Act - Codify Laws (bill tracker)","url":"https://codifylaws.com/canadian-bill-and-regulation-details/bill-15-interprovincial-trade-and-mobility-act-pei-bill","type":"legal"}],"commentary":[{"source":"Canadian Federation of Independent Business (CFIB)","stance":"support","quote":"“The passage of this important legislation is a win for small and medium-sized businesses across Prince Edward Island,” crediting it for cutting duplicate testing/certification and easing labour mobility.","url":"https://www.cfib-fcei.ca/en/media/cfib-highlights-landmark-pei-bill-to-boost-trade-and-mobility"},{"source":"Premier Rob Lantz","stance":"support","quote":"Called the Act a personal high point of the sitting and said all provinces are working to smooth interprovincial trade, with PEI aiming to have it in place by Canada Day in the face of U.S. tariff instability.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-interprovincial-trade-government-officials-1.7513457"},{"source":"Steve Dowling, Director, PEI Financial and Consumer Services Division","stance":"oppose","quote":"In emails tabled in the legislature, complained the division was given only a three-day window to review the parallel legislative initiative: 'It is unfortunate the division was not made aware of this... initiative,' warning of rushed timelines and potential public-safety risks.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-interprovincial-trade-government-officials-1.7513457"},{"source":"PEI opposition parties (Green/Liberal)","stance":"mixed","quote":"Supported reducing trade barriers in principle but argued the government was 'moving too fast on easing interprovincial trade restrictions,' with too little consultation before passage.","url":"https://www.cbc.ca/news/canada/prince-edward-island/pei-legislature-trade-barrier-bill-1.7515775"}]},"nl-bill-16-bill-17":{"officialUrl":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2616.htm","factCheck":"Verified: Both bills passed the 51st General Assembly (1st Session) and received Royal Assent on June 2, 2026 (Bill 16 = SNL c.14; Bill 17 = SNL c.15). Bill 16 raises the basic personal amount to $15,000 (from $11,188 — NOT '$7,410 to $13,094' as some scraped summaries state), doubles the volunteer firefighter and search-and-rescue tax credits to $6,000, and phases the small-business corporate rate down to 2% (2026), 1.5% (2027) and 1% (2028); Bill 17 ('No. 2') is a separate technical bill dealing with corporate credit transfers (manufacturing, green technology, film) and a six-month Child Benefit extension after a child's death, not the headline affordability cuts.","sources":[{"title":"Bill 16 — An Act to Amend the Income Tax Act, 2000 (official text)","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2616.htm","type":"official"},{"title":"Bill 17 — An Act to Amend the Income Tax Act, 2000 No. 2 (official text)","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2617.htm","type":"official"},{"title":"Budget 2026 News Release (Government of NL)","url":"https://www.gov.nl.ca/budget/2026/news-release/","type":"official"},{"title":"Canada: Tax measures in 2026 budget (Newfoundland and Labrador) — KPMG","url":"https://kpmg.com/us/en/taxnewsflash/news/2026/04/canada-tax-measures-2026-newfoundland-labrador.html","type":"legal"},{"title":"Newfoundland and Labrador 2026 Budget Highlights — MNP","url":"https://www.mnp.ca/en/insights/directory/newfoundland-and-labrador-2026-budget-highlights","type":"legal"},{"title":"Budget 2026: Opposition parties say first Tory budget doesn't meet expectations — NTV","url":"https://ntv.ca/news/budget-2026-opposition-parties-say-first-tory-budget-doesnt-meet-expectations/","type":"news"}],"commentary":[{"source":"Craig Pardy, Minister of Finance (PC government)","stance":"support","quote":"We are steadfast in our commitment to improving the overall quality of life for residents by making everyday living more affordable. The higher basic personal amount is projected to save roughly 285,000 taxpayers hundreds of dollars a year.","url":"https://www.gov.nl.ca/budget/2026/news-release/"},{"source":"Jim Dinn, Leader, NL NDP","stance":"oppose","quote":"The budget fails to deliver real relief from the crushing cost of living and is overall a missed opportunity; the tax measures don't meet expectations for those struggling most.","url":"https://ntv.ca/news/budget-2026-opposition-parties-say-first-tory-budget-doesnt-meet-expectations/"},{"source":"KPMG (tax advisory)","stance":"mixed","quote":"Summarizes the measures neutrally: basic personal amount increased to $15,000 from $11,188, small-business rate cut to 2% in 2026 declining to 1% by 2028, and the volunteer firefighter and search-and-rescue credits doubled to $6,000.","url":"https://kpmg.com/us/en/taxnewsflash/news/2026/04/canada-tax-measures-2026-newfoundland-labrador.html"}]},"nl-bill-9":{"officialUrl":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2609.htm","factCheck":"Verified: Bill 9 (An Act to Amend the Future Fund Act) passed third reading May 5, 2026 and received Royal Assent June 2, 2026 (SNL c.7). It removes the mandatory deposit of non-renewable resource royalties (deposits now occur only when the province has a 'surplus cash position', plus net proceeds over $5M from Crown asset sales), and — most controversially — broadens permitted withdrawals to pay down debt and certain liabilities. Clarification of a common misframing: the bill does not abolish or 'empty' the ~$550M fund; it changes the contribution trigger and lifts prior withdrawal restrictions, and critics note the fund's ~7.36% return exceeds the province's ~3.8% debt-interest cost, so drawing it down to repay debt can be a net loss.","sources":[{"title":"Bill 9 — An Act to Amend the Future Fund Act (official text)","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2609.htm","type":"official"},{"title":"Provincial Government Introduces Amendments to the Future Fund Act (news release)","url":"https://www.gov.nl.ca/releases/2026/fin/0422n02/","type":"official"},{"title":"Legislation to Amend the Future Fund Act Passes Third Reading (news release)","url":"https://www.gov.nl.ca/releases/2026/fin/0505n04/","type":"official"},{"title":"PCs propose raiding N.L.'s $550M future fund in order to tackle debt — CBC News","url":"https://www.cbc.ca/news/canada/newfoundland-labrador/future-fund-amendments-9.7172134","type":"news"},{"title":"Newfoundland government's Future Fund proposals steeped in short-term thinking — Fraser Institute","url":"https://www.fraserinstitute.org/commentary/newfoundland-governments-future-fund-proposals-steeped-short-term-thinking","type":"academic"},{"title":"Future Fund Act (SNL2022 c. F-27) — current statute","url":"https://www.assembly.nl.ca/Legislation/sr/statutes/f27.htm","type":"official"}],"commentary":[{"source":"Craig Pardy, Minister of Finance (PC government)","stance":"support","quote":"It does not make sense to borrow money to put into the Future Fund — especially when many Newfoundlanders and Labradorians are facing affordability pressures and challenges accessing essential services.","url":"https://www.cbc.ca/news/canada/newfoundland-labrador/future-fund-amendments-9.7172134"},{"source":"Fraser Institute","stance":"oppose","quote":"The proposals are 'steeped in short-term thinking'; weakening contribution rules and allowing withdrawals undermines the fund's purpose of building long-term savings and intergenerational fairness.","url":"https://www.fraserinstitute.org/commentary/newfoundland-governments-future-fund-proposals-steeped-short-term-thinking"},{"source":"Opposition critics (as reported by CBC)","stance":"oppose","quote":"Calling it 'irresponsible' to open the fund to spending, critics note it earned about 7.36% last year — nearly double the ~3.8% the province pays on debt — so using principal to pay debt is a net loss.","url":"https://www.cbc.ca/news/canada/newfoundland-labrador/future-fund-amendments-9.7172134"}]},"nl-bill-7":{"officialUrl":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2607.htm","factCheck":"Verified: Bill 7 (An Act to Amend the Endangered Species Act) passed third reading March 17, 2026 and received Royal Assent June 2, 2026 (SNL c.5). It sharply raises fines (individuals: first offence $3,000–$50,000 up from $1,000–$50,000; corporations up to $2 million), adds telewarrant authority and clearer search/seizure and forfeiture powers for conservation officers, adds definitions of 'corporation' and 'vehicle', extends a ministerial response window from 90 to 180 days, and modernizes language. No notable misinformation found; note the higher fines and equipment/vehicle seizure provisions were the main point of public concern, not a change to which species are listed.","sources":[{"title":"Bill 7 — An Act to Amend the Endangered Species Act (official text)","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2607.htm","type":"official"},{"title":"Provincial Government Proposing Amendments to Endangered Species Act (news release)","url":"https://www.gov.nl.ca/releases/2026/fal/0312n07/","type":"official"},{"title":"NL Government Proposes Tougher Penalties for Endangered Species Violations — NewfoundNews","url":"https://www.newfoundnews.ca/post/newfoundland-and-labrador-government-proposes-tougher-penalties-for-endangered-species-violations","type":"news"},{"title":"Bill 7 — An Act to Amend the Endangered Species Act — The Civics Project","url":"https://www.civicsproject.org/regions/newfoundland-and-labrador/bill/51/7?session=1","type":"advocacy"}],"commentary":[{"source":"Government of Newfoundland and Labrador (Forestry, Agriculture and Lands)","stance":"support","quote":"Higher fines and stronger enforcement tools create a stronger deterrent to illegal activity that harms species protected under the Endangered Species Act.","url":"https://www.gov.nl.ca/releases/2026/fal/0312n07/"},{"source":"Public engagement respondents (as reported)","stance":"mixed","quote":"There was overall public support for increasing fines, but some warned the steep fines, daily penalties and vehicle/equipment seizures could be excessive for small operators or rural residents who make honest mistakes.","url":"https://www.newfoundnews.ca/post/newfoundland-and-labrador-government-proposes-tougher-penalties-for-endangered-species-violations"}]},"nl-bill-1":{"officialUrl":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2601.htm","factCheck":"Verified: Bill 1 (Disability Advocate Act) passed third reading March 19, 2026 and received Royal Assent April 20, 2026 (SNL c.D-24.1), creating an independent Office of the Disability Advocate as a Statutory Office of the House of Assembly with powers to investigate disability services, mediate, research and make recommendations. No notable misinformation found; note the advocate is appointed by resolution of the House (like the Child and Youth Advocate), and disability groups pressed for a genuinely independent, competitive appointment rather than a government pick.","sources":[{"title":"Bill 1 — Disability Advocate Act (official text)","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2601.htm","type":"official"},{"title":"Premier Wakeham Committed to Establishing Independent Office of the Disability Advocate (news release)","url":"https://www.gov.nl.ca/releases/2026/exec/0305n06/","type":"official"},{"title":"Bill 1 — An Act Respecting the Disability Advocate Passes Third Reading (news release)","url":"https://www.gov.nl.ca/releases/2026/exec/0319n06/","type":"official"},{"title":"An advocacy group questions whether N.L. will keep promise to create a disability advocate — CBC News","url":"https://www.cbc.ca/news/canada/newfoundland-labrador/coalition-for-persons-with-disabilities-calls-for-advocate-1.7515196","type":"news"},{"title":"Disabilities Advocate passes third reading in House of Assembly — NTV","url":"https://ntv.ca/politics/disabilities-advocate-passes-third-reading-in-house-of-assembly/","type":"news"}],"commentary":[{"source":"Tony Wakeham, Premier (PC government)","stance":"support","quote":"People with disabilities have long struggled to navigate government services; establishing an independent Office of the Disability Advocate is about changing that.","url":"https://www.gov.nl.ca/releases/2026/exec/0305n06/"},{"source":"Nancy Reid, Executive Director, Coalition of Persons with Disabilities NL","stance":"mixed","quote":"Surprised and excited that there is a real commitment to do this, but clear and hopeful that the position will be competitive in nature and not simply appointed by the provincial government.","url":"https://www.cbc.ca/news/canada/newfoundland-labrador/coalition-for-persons-with-disabilities-calls-for-advocate-1.7515196"}]},"nl-bill-2":{"officialUrl":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2602.htm","factCheck":"Verified: Bill 2 (Seniors' Advocate Act, 2026) passed third reading June 2, 2026 and received Royal Assent the same day (SNL c.S-13.0003). It repeals and replaces the older Seniors Advocate Act, adding full investigatory powers — the advocate can compel information and records, summon and examine witnesses under oath, enter premises of departments/agencies/service providers, and act without a formal complaint — enabling individual (not just systemic) advocacy. No notable misinformation found; the change responds directly to auditor-general findings on personal care homes and brings NL closer to powers seen in provinces like New Brunswick.","sources":[{"title":"Bill 2 — Seniors' Advocate Act, 2026 (official text)","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2602.htm","type":"official"},{"title":"House of Assembly Spring Sitting Wraps Up (news release listing Bill 2)","url":"https://www.gov.nl.ca/releases/2026/exec/0602n08/","type":"official"},{"title":"Seniors' advocate, NAPE say they aren't surprised by findings in AG report on personal care homes — CBC News","url":"https://www.cbc.ca/news/canada/newfoundland-labrador/auditor-general-personal-care-homes-reaction-1.7499459","type":"news"},{"title":"Office of the Seniors' Advocate NL — official site","url":"https://www.seniorsadvocatenl.ca/","type":"official"}],"commentary":[{"source":"Susan Walsh, Seniors' Advocate of Newfoundland and Labrador","stance":"support","quote":"Advocates in other provinces such as New Brunswick already have broader investigative powers; with that power here there would be far more oversight of personal and long-term care homes and the ability to advocate for individuals in dangerous situations.","url":"https://www.cbc.ca/news/canada/newfoundland-labrador/auditor-general-personal-care-homes-reaction-1.7499459"},{"source":"Government of Newfoundland and Labrador","stance":"support","quote":"Replacing the Office of the Seniors' Advocate with a new Act provides full investigation powers and the ability to provide individual advocacy — a major step forward in protecting older adults' rights.","url":"https://www.gov.nl.ca/releases/2026/exec/0602n08/"}]},"nl-bill-12":{"officialUrl":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2612.htm","factCheck":"Verified: Bill 12 (An Act to Amend the Children's Law Act and the Family Law Act) passed third reading May 7, 2026 and received Royal Assent June 2, 2026 (SNL c.10). It replaces 'custody/access' with 'decision-making responsibility', 'parenting time' and 'contact', adds a statutory definition of family violence that courts must weigh in best-interests determinations, creates child-relocation notice/objection procedures, and adds duties to encourage family dispute resolution — broadly aligning provincial law with the modernized federal Divorce Act. No notable misinformation found (this NL Bill 12 is unrelated to a Quebec 'Bill 12' on filiation that appears in searches).","sources":[{"title":"Bill 12 — An Act to Amend the Children's Law Act and the Family Law Act (official text)","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2612.htm","type":"official"},{"title":"Provincial Government Proposing Changes to Family Law (news release)","url":"https://www.gov.nl.ca/releases/2026/jps/0507n05/","type":"official"},{"title":"Children's Law Act (RSNL1990 c. C-13) — current statute","url":"https://assembly.nl.ca/legislation/sr/statutes/c13.htm","type":"official"},{"title":"Family Violence — Supreme Court of Newfoundland and Labrador (Family Division)","url":"https://www.court.nl.ca/supreme/family-division/info-common-legal-issues/family-violence/","type":"legal"}],"commentary":[{"source":"Helen Conway Ottenheimer, Minister of Justice and Public Safety / Attorney General","stance":"support","quote":"These amendments will modernize our laws to reflect today's realities, reduce unnecessary conflict, and ensure that the well-being of children is always the guiding principle.","url":"https://www.gov.nl.ca/releases/2026/jps/0507n05/"},{"source":"Government of Newfoundland and Labrador (JPS)","stance":"support","quote":"The changes place the best interests of children at the centre of decisions when families separate, replace adversarial 'custody/access' language, define family violence, and direct parents toward mediation where appropriate.","url":"https://www.gov.nl.ca/releases/2026/jps/0507n05/"}]},"nl-bill-4":{"officialUrl":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2604.htm","factCheck":"Verified: Bill 4 (An Act to Amend the Revenue Administration Act) repeals the sugar-sweetened beverage tax; it passed third reading May 4, 2026 and received Royal Assent June 2, 2026 (SNL c.3). Clarification on timing/misinformation: the tax (Canada's first such provincial tax, in effect since Sept. 1, 2022) was effectively eliminated July 1, 2025 by ministerial action after Premier John Hogan's announcement, and Bill 4 is the statutory clean-up that formally strikes Part IX.2 from the Act — so the levy was already gone before this bill passed. Health officials confirmed scrapping it would not end the related glucose-monitoring/diabetes programs.","sources":[{"title":"Bill 4 — An Act to Amend the Revenue Administration Act (official text)","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2604.htm","type":"official"},{"title":"Government of NL Eliminates the Sugar Sweetened Beverage Tax (news release, 2025)","url":"https://www.gov.nl.ca/releases/2025/exec/0530n05/","type":"official"},{"title":"NOTICE: Elimination of Sugar Sweetened Beverage Tax — Dept. of Finance","url":"https://www.gov.nl.ca/fin/sugar-sweetened-beverage-tax/","type":"official"},{"title":"Walking back pop tax comes at a cost to Newfoundland and Labradorians — Heart & Stroke Foundation","url":"https://www.heartandstroke.ca/what-we-do/media-centre/news-releases/walking-back-pop-tax-comes-at-a-cost-to-newfoundland-and-labradorians","type":"advocacy"},{"title":"Newly minted Premier John Hogan says he'll axe controversial sugar tax — CBC News","url":"https://www.cbc.ca/news/canada/newfoundland-labrador/house-of-assembly-sugar-tax-1.7532906","type":"news"},{"title":"Scrapped sugar tax won't hurt glucose monitoring program, says health minister — CBC News","url":"https://www.cbc.ca/news/canada/newfoundland-labrador/house-of-assemly-may-14-1.7535057","type":"news"}],"commentary":[{"source":"Katie Greene, Senior VP, Heart & Stroke (Newfoundland)","stance":"oppose","quote":"Walking it back raises real concerns about the impact on the health of people in Newfoundland and Labrador — what happens to school breakfast and lunch programs or prenatal nutrition supplements if this funding disappears?","url":"https://www.heartandstroke.ca/what-we-do/media-centre/news-releases/walking-back-pop-tax-comes-at-a-cost-to-newfoundland-and-labradorians"},{"source":"John Hogan, Premier (Liberal, at announcement)","stance":"support","quote":"Pledged to axe the controversial sugar tax, framing the repeal as an affordability measure for residents.","url":"https://www.cbc.ca/news/canada/newfoundland-labrador/house-of-assembly-sugar-tax-1.7532906"},{"source":"Retail Council of Canada","stance":"support","quote":"Welcomed the elimination of the sugar-sweetened beverage tax as a win for retailers and consumers and the removal of an administrative and cost burden.","url":"https://www.retailcouncil.org/free-of-sugars-free-of-tax-rccs-game-changing-win/"}]},"nl-bill-10":{"officialUrl":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2610.htm","factCheck":"Verified: Bill 10 (An Act to Amend the Workplace Health, Safety and Compensation Act, 2022) passed third reading May 7, 2026 and received Royal Assent June 2, 2026 (SNL c.8). It adds a definition of 'temporary earnings loss benefits' and changes the retirement-benefit calculation so temporary earnings-loss benefits paid beyond 24 months count toward the retirement benefit; the government says it is retroactive to January 1, 2019, would benefit roughly 3,100 current and former WorkplaceNL claimants (average increase about $5,800) with no impact on the 2026 average employer assessment rate. No notable misinformation found; note a separate independent committee to review the broader workers' compensation system was announced June 11, 2026.","sources":[{"title":"Bill 10 — An Act to Amend the Workplace Health, Safety and Compensation Act, 2022 (official text)","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2610.htm","type":"official"},{"title":"N.L. government proposes changes to boost retirement benefits for injured workers — NewfoundNews","url":"https://www.newfoundnews.ca/post/n-l-government-proposes-changes-to-boost-retirement-benefits-for-injured-workers","type":"news"},{"title":"Independent Committee Appointed to Review Workers' Compensation System (news release)","url":"https://www.gov.nl.ca/releases/2026/government-services/0611n01/","type":"official"},{"title":"Federation of Labour Releases Budget and Legislative Priorities — NL Federation of Labour","url":"https://nlfed.ca/federation-of-labour-releases-budget-and-legislative-priorities-calls-for-action-on-affordability-and-worker-safety/","type":"advocacy"}],"commentary":[{"source":"Government of Newfoundland and Labrador (as reported)","stance":"support","quote":"Including temporary earnings-loss benefits paid beyond 24 months in the retirement-benefit calculation, retroactive to January 1, 2019, would give about 3,100 current and former claimants an average increase of roughly $5,800, with over 700 receiving lump-sum payments and no impact on the 2026 average employer assessment rate.","url":"https://www.newfoundnews.ca/post/n-l-government-proposes-changes-to-boost-retirement-benefits-for-injured-workers"},{"source":"Newfoundland and Labrador Federation of Labour","stance":"mixed","quote":"Has pressed government to strengthen worker health and safety and improve supports for injured workers as a legislative priority — supportive of better injured-worker benefits while pushing for broader reform of the compensation system.","url":"https://nlfed.ca/federation-of-labour-releases-budget-and-legislative-priorities-calls-for-action-on-affordability-and-worker-safety/"}]},"nl-bill-19":{"officialUrl":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2619.htm","factCheck":"Verified: Bill 19 (An Act to Amend the Pharmaceutical Services Act) passed third reading June 2, 2026 and received Royal Assent the same day (SNL c.17). It gives pharmacists and dispensing physicians more flexibility with controlled drugs by clarifying that telephoned prescriptions may be dispensed where the federal Controlled Drugs and Substances Act permits, and by removing the tamper-resistant prescription-pad requirement in three situations: prescriptions transferred between pharmacists/physicians (where federal law allows), prescriptions delivered directly from prescriber to pharmacy, and therapeutic substitution of one controlled drug for another with equivalent effect. No notable misinformation found; the bill aligns provincial rules with existing federal authorities rather than loosening controls beyond them.","sources":[{"title":"Bill 19 — An Act to Amend the Pharmaceutical Services Act (official text)","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2619.htm","type":"official"},{"title":"House of Assembly Spring Sitting Wraps Up (news release listing Bill 19)","url":"https://www.gov.nl.ca/releases/2026/exec/0602n08/","type":"official"},{"title":"Pharmaceutical Services Act (current statute) — assembly.nl.ca","url":"https://www.assembly.nl.ca/Legislation/sr/statutes/p12-01.htm","type":"official"}],"commentary":[{"source":"Government of Newfoundland and Labrador","stance":"support","quote":"Listed among health-care measures, the amendments support health care by giving pharmacists and dispensing physicians more practical flexibility to dispense controlled drugs consistent with federal rules.","url":"https://www.gov.nl.ca/releases/2026/exec/0602n08/"},{"source":"Explanatory note, Bill 19 (legislative drafters)","stance":"support","quote":"Removes the tamper-resistant prescription-pad requirement where a controlled-drug prescription is transferred between practitioners, delivered directly from prescriber to pharmacy, or substituted for another controlled drug of equivalent therapeutic effect, and clarifies telephone-prescription dispensing where federal law authorizes it.","url":"https://www.assembly.nl.ca/HouseBusiness/Bills/ga51session1/bill2619.htm"}]},"yt-first-appropriation-act-2026-27-sy-2026-c-6-a":{"officialUrl":"https://laws.yukon.ca/cms/acts-by-year.html","factCheck":"Verified: Budget 2026 totals ~$2.46B ($2.07B O&M + $385M capital) with an ~$81.8M deficit and ~$804M net debt; tabled March 19 and passed May 11, 2026, and the territory has reached its $1.2B federal debt cap. No notable misinformation found.","sources":[{"title":"Yukon premier tables $82M deficit budget, blames previous gov't for 'unsustainable spending' (CBC News)","url":"https://www.cbc.ca/news/canada/north/yukon-party-government-budget-2026-27-9.7134152","type":"news"},{"title":"Yukon tables $2.46B budget as Dixon warns territory has hit debt cap (Yukon News)","url":"https://yukon-news.com/2026/03/19/yukon-tables-2-46b-budget-as-dixon-warns-territory-has-hit-debt-cap/","type":"news"},{"title":"Spring sitting culminates in majority Yukon Party's 1st full budget passing (CBC News)","url":"https://www.cbc.ca/news/canada/north/yukon-government-budget-passes-9.7196935","type":"news"},{"title":"Budget 2026 begins road to fiscal recovery (Government of Yukon)","url":"https://yukon.ca/en/news/budget-2026-begins-road-fiscal-recovery","type":"official"},{"title":"Yukon Annual Acts 2026 (laws.yukon.ca)","url":"https://laws.yukon.ca/cms/acts-by-year.html","type":"legal"}],"commentary":[{"source":"Premier Currie Dixon (Yukon Party)","stance":"support","quote":"Dixon described the $1.2-billion debt limit as both 'real and dangerous' and called Budget 2026 the first step on the road to fiscal recovery after years of unsustainable spending.","url":"https://yukon-news.com/2026/03/19/yukon-tables-2-46b-budget-as-dixon-warns-territory-has-hit-debt-cap/"},{"source":"Kate White, Leader of the Official Opposition (Yukon NDP)","stance":"oppose","quote":"White questioned 'How does this budget support people?' and pointed to the 'irony' of the government spending on conference travel and speechwriting while telling Yukoners it is broke.","url":"https://www.cbc.ca/news/canada/north/yukon-government-budget-passes-9.7196935"},{"source":"Debra-Leigh Reti, interim Yukon Liberal leader (MLA, Vuntut Gwitchin)","stance":"oppose","quote":"Reti suggested Yukon Party campaign promises, such as rolling back rising electricity rates, may now have to wait given the fiscal situation.","url":"https://www.cbc.ca/news/canada/north/yukon-government-budget-passes-9.7196935"}]},"yt-bill-no-5-act-to-amend-the-health-authority-a":{"officialUrl":"https://yukon.ca/en/news/statement-minister-cathers-passing-bill-no-5-act-amend-health-authority-act","factCheck":"Verified: Bill No. 5 passed 10-6 on March 31, 2026, lets the minister pause the health authority and shields government/board from civil suit; the interim board resigned April 27, and Dixon pledged at the May 8 Yukon Forum not to repeal the Act or amend further in the fall. No notable misinformation found.","sources":[{"title":"Critics slam Yukon Party's 'sneaky' move to table bill to pause work on health authority (CBC News)","url":"https://www.cbc.ca/news/canada/north/critics-slam-yukon-party-s-sneaky-move-to-table-bill-to-pause-work-on-health-authority-9.7142813","type":"news"},{"title":"Yukon government passes bill to allow it to halt health authority, minister says (CBC News)","url":"https://www.cbc.ca/news/canada/north/health-authority-implementation-pause-9.7150780","type":"news"},{"title":"Stripped of mandate and funding, entire Yukon health board resigns (CBC News)","url":"https://www.cbc.ca/news/canada/north/yukon-health-board-resigns-9.7178979","type":"news"},{"title":"Premier announces commitment not to repeal Health Authority Act at Yukon Forum (Yukon News)","url":"https://yukon-news.com/2026/05/14/premier-announces-commitment-not-to-repeal-health-authority-act-at-yukon-forum/","type":"news"},{"title":"NEWS RELEASE: Health Authority Act tabled in the Yukon Legislative Assembly (Council of Yukon First Nations)","url":"https://cyfn.ca/news-release-health-authority-act-tabled-in-the-yukon-legislative-assembly/","type":"advocacy"},{"title":"Statement from Minister Cathers on the passing of Bill No. 5 (Government of Yukon)","url":"https://yukon.ca/en/news/statement-minister-cathers-passing-bill-no-5-act-amend-health-authority-act","type":"official"}],"commentary":[{"source":"Kate White, Leader of the Official Opposition (Yukon NDP)","stance":"oppose","quote":"White said the amendments were unilateral and warned they would damage long-standing relationships with First Nations, noting the original act was co-developed.","url":"https://www.cbc.ca/news/canada/north/health-authority-implementation-pause-9.7150780"},{"source":"Council of Yukon First Nations / Chiefs Committee on Health","stance":"oppose","quote":"The Council said the move disregards years of joint planning and threatens long-promised health-system reforms, and joined the Chiefs Committee on Health in condemning the decision.","url":"https://cyfn.ca/news-release-health-authority-act-tabled-in-the-yukon-legislative-assembly/"},{"source":"Stephen Mills, resigning chair of Shaw Kwa'a (interim health authority board)","stance":"oppose","quote":"All seven board members resigned after being told their proposed $1.5M budget would not be approved, saying they were left with no clear path forward once stripped of mandate and funding.","url":"https://www.cbc.ca/news/canada/north/yukon-health-board-resigns-9.7178979"},{"source":"Minister Brad Cathers (Yukon Party)","stance":"support","quote":"Cathers said pausing the authority lets the government direct resources to frontline services, recruit health professionals and improve hospitals, and that the civil-immunity clause was added partly in response to the interim board chair's concerns.","url":"https://yukon.ca/en/news/statement-minister-cathers-passing-bill-no-5-act-amend-health-authority-act"}]},"yt-bill-no-2-act-to-repeal-the-clean-energy-act-":{"officialUrl":"https://laws.yukon.ca/cms/acts-by-year.html","factCheck":"Verified: Bill No. 2 repealed the 2022 Clean Energy Act (passed 12-6, March 30, 2026), ending legislated emissions targets/reporting and the EV mandate, and cancelled EV/e-bike rebates with ~$946K shifted to heating incentives; CYFN says it was not consulted. No notable misinformation found.","sources":[{"title":"Yukon gov't torches Clean Energy Act, subsidies for EVs and e-bikes (CBC News)","url":"https://www.cbc.ca/news/canada/north/yukon-government-torches-clean-energy-act-9.7147939","type":"news"},{"title":"With Yukon's Clean Energy Act gone, some experts wonder how the gov't will now tackle emissions (CBC News)","url":"https://www.cbc.ca/news/canada/north/yukon-clean-energy-act-gone-9.7163847","type":"news"},{"title":"Yukon repeals Clean Energy Act, pivots funding to reduce peak power load (Yukon News)","url":"https://yukon-news.com/2026/04/01/yukon-repeals-clean-energy-act-pivots-funding-to-reduce-peak-power-load/","type":"news"},{"title":"First Nations say Yukon risks backsliding on climate action as EV rebates, emissions targets axed (96.1 The Rush / CKRW)","url":"https://www.ckrw.com/2026/03/31/8369/","type":"news"},{"title":"Yukon government takes steps to address energy needs (Government of Yukon)","url":"https://yukon.ca/en/news/yukon-government-takes-steps-address-energy-needs","type":"official"}],"commentary":[{"source":"Ted Laking, Minister of Energy, Mines and Resources (Yukon Party)","stance":"support","quote":"Laking said December's cold snap showed the territory was one outage away from rolling blackouts, that the Act's targets were not achievable and were driving electricity demand beyond what the grid can support, so government must cut peak load.","url":"https://www.cbc.ca/news/canada/north/yukon-government-torches-clean-energy-act-9.7147939"},{"source":"Brian Horton, director of climate change research, Yukon University","stance":"oppose","quote":"'It's very discouraging that the Yukon is just repealing the act rather than possibly revisiting some policies, possibly rethinking its targets. But eliminating them all together... sets us back in terms of accountability.'","url":"https://www.cbc.ca/news/canada/north/yukon-clean-energy-act-gone-9.7163847"},{"source":"Council of Yukon First Nations","stance":"oppose","quote":"CYFN said it was not consulted, that the Act was built through partnership and provided accountability on emissions, and that repeal risks reversing progress and sends a troublesome signal about Yukon's commitment to combating climate change.","url":"https://www.ckrw.com/2026/03/31/8369/"}]},"yt-bill-no-3-opioid-damages-and-health-care-cost":{"officialUrl":"https://yukon.ca/en/news/government-yukon-introduces-opioid-litigation-legislation","factCheck":"Verified: passed unanimously April 2, 2026 (assent April 7), it lets Yukon join the B.C.-led national opioid class action using aggregate/statistical data instead of individual health records, mirroring B.C.'s SCC-upheld model; trial set for Feb 2028. No notable misinformation found.","sources":[{"title":"Yukon passes bill to participate in B.C.-led lawsuit against opioid makers (CBC News)","url":"https://www.cbc.ca/news/canada/north/yukon-lawsuit-against-opioid-makers-9.7163758","type":"news"},{"title":"Yukon passes opioid cost-recovery bill as minister moves to join national suit (Yukon News)","url":"https://yukon-news.com/2026/04/16/yukon-passes-opioid-cost-recovery-bill-as-minister-moves-to-join-national-suit/","type":"news"},{"title":"Government of Yukon introduces opioid litigation legislation (Government of Yukon)","url":"https://yukon.ca/en/news/government-yukon-introduces-opioid-litigation-legislation","type":"official"},{"title":"BC's Opioid Damages and Health Care Costs Recovery Act, SBC 2018, c 35 (CanLII)","url":"https://www.canlii.org/en/bc/laws/stat/sbc-2018-c-35/latest/sbc-2018-c-35.html","type":"legal"},{"title":"BC law that lets province file opioids class action with other governments constitutional, SCC rules (Canadian Lawyer)","url":"https://www.canadianlawyermag.com/news/general/bc-law-that-lets-province-file-opioids-class-action-with-other-governments-constitutional-scc-rules/390069","type":"legal"}],"commentary":[{"source":"Government of Yukon (Minister Brad Cathers)","stance":"support","quote":"The government said the Act ensures Yukon can pursue damages for the public costs of opioid-related illness and lets it join the national class action without onerous documentary discovery, using statistical and population-based evidence rather than identifying individuals.","url":"https://yukon.ca/en/news/government-yukon-introduces-opioid-litigation-legislation"},{"source":"Yukon Legislative Assembly (all parties)","stance":"support","quote":"MLAs from all parties passed the bill unanimously on April 2, 2026, reflecting rare cross-party agreement to join the B.C.-led suit.","url":"https://www.cbc.ca/news/canada/north/yukon-lawsuit-against-opioid-makers-9.7163758"},{"source":"Torys LLP / Canadian Lawyer (legal analysis of the B.C. model)","stance":"mixed","quote":"Analysts note the model gives governments substantial litigation advantages - reverse onuses, aggregate proof, suspended limitation periods and retroactivity - which the Supreme Court of Canada upheld 6-1 as constitutional.","url":"https://www.canadianlawyermag.com/news/general/bc-law-that-lets-province-file-opioids-class-action-with-other-governments-constitutional-scc-rules/390069"}]},"yt-bill-no-4-act-to-amend-the-financial-administ":{"officialUrl":"https://laws.yukon.ca/cms/acts-by-year.html","factCheck":"Verified: the amendment creates a $100M voted contingency in the main estimates to fund emergencies/unforeseen costs and reduce fall supplementary budgets; assented during the 2026 spring sitting. No notable misinformation found.","sources":[{"title":"Yukon spring sitting ends with four policy bills passed and budget strain noted (Yukon News)","url":"https://yukon-news.com/2026/05/13/yukon-spring-sitting-ends-with-four-policy-bills-passed-and-budget-strain-noted/","type":"news"},{"title":"Budget 2026 begins road to fiscal recovery (Government of Yukon)","url":"https://yukon.ca/en/news/budget-2026-begins-road-fiscal-recovery","type":"official"},{"title":"Yukon Annual Acts 2026 (laws.yukon.ca)","url":"https://laws.yukon.ca/cms/acts-by-year.html","type":"legal"}],"commentary":[{"source":"Government of Yukon finance officials (technical briefing)","stance":"support","quote":"Officials said the $100M voted contingency is meant to reduce the need for fall supplementary budgets for predictable but uncertain costs such as wildfires, providing timely response to emergencies.","url":"https://yukon.ca/en/news/budget-2026-begins-road-fiscal-recovery"},{"source":"Yukon News (spring sitting wrap)","stance":"mixed","quote":"Reporting framed the Financial Administration Act amendment as creating a voted contingency fund within the broader context of a budget under strain at the federal debt cap.","url":"https://yukon-news.com/2026/05/13/yukon-spring-sitting-ends-with-four-policy-bills-passed-and-budget-strain-noted/"}]},"nt-bill-47-20-1":{"officialUrl":"https://www.ntlegislativeassembly.ca/documents-proceedings/bills/appropriation-act-operations-expenditures-2026-2027","factCheck":"Verified: the 2026-27 operating budget (Bill 47) passed third reading March 5, 2026 by a 15-3 vote with ~$40M added during debate and received Assent March 6, 2026; it contains no new taxes.","sources":[{"title":"GNWT releases Budget 2026-2027 (Government of the NWT)","url":"https://www.gov.nt.ca/en/newsroom/gnwt-releases-budget-2026-2027","type":"official"},{"title":"Bills & Legislation — 20th Assembly, 1st Session (Legislative Assembly of the NWT)","url":"https://www.ntlegislativeassembly.ca/documents-proceedings/bills","type":"official"},{"title":"2026-27 Budget Address and Economic Outlook (NWT Dept. of Finance, PDF)","url":"https://www.fin.gov.nt.ca/sites/fin/files/2026-27_budget_address_and_economic_outlook_and_fiscal_review_papers.pdf","type":"official"},{"title":"NWT's 2026-27 budget passes with additional $40M in spending (Cabin Radio)","url":"https://cabinradio.ca/282309/news/politics/nwts-2026-27-budget-passes-with-additional-40m-in-spending/","type":"news"},{"title":"NWT, 'expecting a lot' in 2026, unveils budget for the year ahead (Cabin Radio)","url":"https://cabinradio.ca/278245/news/politics/nwt-expecting-a-lot-in-2026-unveils-budget-for-the-year-ahead/","type":"news"}],"commentary":[{"source":"Caroline Wawzonek, Finance Minister","stance":"support","quote":"Budget 2026-27 proposes no new taxes; several fees and some property mill rates will be indexed to inflation.","url":"https://www.gov.nt.ca/en/newsroom/gnwt-releases-budget-2026-2027"},{"source":"Robert Hawkins, MLA (Yellowknife Centre)","stance":"oppose","quote":"Hawkins said the government 'got away very cheap,' with fewer than 25 per cent of regular MLAs' requests met in the final budget.","url":"https://cabinradio.ca/282309/news/politics/nwts-2026-27-budget-passes-with-additional-40m-in-spending/"},{"source":"Richard Edjericon, MLA (Tu Nedhé-Wiilideh)","stance":"oppose","quote":"Edjericon criticized the lack of investment in his district despite annual submissions of community needs.","url":"https://cabinradio.ca/282309/news/politics/nwts-2026-27-budget-passes-with-additional-40m-in-spending/"}]},"nt-bill-42-20-1":{"officialUrl":"https://www.ntlegislativeassembly.ca/documents-proceedings/bills","factCheck":"Verified: the Tłegǫ́hłı̨ Got'įnę Final Self-Government Agreement was signed in September 2025 after ~20 years of negotiation, and the NWT enacted implementing legislation (Bill 42) that received Assent March 6, 2026; the TGG does not govern the Town of Norman Wells proper.","sources":[{"title":"Tłegǫ́hłı̨ Got'įnę, NWT, Canada sign final self-government agreement (Cabin Radio)","url":"https://cabinradio.ca/259351/news/politics/tleg%C7%ABhli%CC%A8-gotine-nwt-canada-sign-final-self-government-agreement/","type":"news"},{"title":"Tłegǫ́hłı̨ Got'įnę in Norman Wells, N.W.T. nears self-government (CBC North)","url":"https://www.cbc.ca/news/canada/north/t%C5%82eg%C7%AB-h%C5%82%C4%B1-got-%C4%AFn%C4%99-in-norman-wells-n-w-t-nears-self-government-1.7387892","type":"news"},{"title":"Tłegǫ́hłı̨ Got'įnę sign final self-government agreement with Ottawa and NWT (CKLB Radio)","url":"https://cklbradio.com/2025/09/18/tleg%C7%ABhli%CC%A8-gotine-sign-final-self-government-agreement-with-ottawa-and-nwt/","type":"news"},{"title":"Bills & Legislation — 20th Assembly, 1st Session (Legislative Assembly of the NWT)","url":"https://www.ntlegislativeassembly.ca/documents-proceedings/bills","type":"official"}],"commentary":[{"source":"Sherry Hodgson, President, Tłegǫ́hłı̨ Got'įnę Government","stance":"support","quote":"The agreement represents 'Canada's formal recognition of the identity, culture, and inherent right to self-government' of her people.","url":"https://cabinradio.ca/259351/news/politics/tleg%C7%ABhli%CC%A8-gotine-nwt-canada-sign-final-self-government-agreement/"},{"source":"Crown-Indigenous Relations and Northern Affairs Canada","stance":"support","quote":"Initialling of the final self-government agreement marks an important step in the nation-to-nation relationship with the Tłegǫ́hłı̨ Got'įnę.","url":"https://www.canada.ca/en/crown-indigenous-relations-northern-affairs/news/2024/11/initialling-of-final-self-government-agreement-for-the-tegoh-gotine-marks-an-important-step-in-nation-to-nation-relationship.html"}]},"nt-bill-45-20-1":{"officialUrl":"https://www.ntlegislativeassembly.ca/documents-proceedings/bills/civil-forfeiture-act","factCheck":"Verified: Bill 45 would allow seizure of crime-linked property through civil court on the balance of probabilities without a criminal conviction; it received first/second reading March 4-5, 2026 and was referred to committee, where MLAs questioned its retroactive 'reach-back' and lack of a minimum-offence threshold — it had not yet passed third reading as of mid-June 2026.","sources":[{"title":"Civil Forfeiture Act — Bill 45-20(1) status page (Legislative Assembly of the NWT)","url":"https://www.ntlegislativeassembly.ca/documents-proceedings/bills/civil-forfeiture-act","type":"official"},{"title":"N.W.T.'s proposed SCAN and civil forfeiture laws criticized as potentially unfair, redundant (CBC North)","url":"https://www.cbc.ca/news/canada/north/proposed-nwt-scan-and-civil-forfeiture-acts-draw-criticism-9.6987077","type":"news"},{"title":"MLAs reviewing civil forfeiture law focus on its ability to reach back (Cabin Radio)","url":"https://cabinradio.ca/288677/news/politics/mlas-reviewing-civil-forfeiture-law-focus-on-its-ability-to-reach-back/","type":"news"},{"title":"Have Your Say — Public Safety Legislation (Government of the NWT engagement)","url":"https://haveyoursay.nwt-tno.ca/public-safety-legislation","type":"official"},{"title":"Crime, criminality alarm communities across NWT, says report (CKLB Radio)","url":"https://cklbradio.com/2026/06/01/crime-criminality-alarm-communities-across-nwt-says-report/","type":"news"}],"commentary":[{"source":"Jay Macdonald, Minister of Justice","stance":"support","quote":"We need to provide the tools in the system that allow us to disrupt that activity.","url":"https://cabinradio.ca/288677/news/politics/mlas-reviewing-civil-forfeiture-law-focus-on-its-ability-to-reach-back/"},{"source":"Shauna Morgan, MLA (Yellowknife North)","stance":"mixed","quote":"On the lack of a minimum-offence threshold, Morgan questioned whether minor violations should trigger seizure — 'Do you deserve to have your car taken away for that?'","url":"https://cabinradio.ca/288677/news/politics/mlas-reviewing-civil-forfeiture-law-focus-on-its-ability-to-reach-back/"},{"source":"CBC North (reporting civil-rights critique)","stance":"oppose","quote":"A lawyer and civil rights groups say similar legislation has been deemed unconstitutional, and that those targeted are often vulnerable, already involved with the justice or child-welfare systems, and rarely hire counsel to contest seizures.","url":"https://www.cbc.ca/news/canada/north/proposed-nwt-scan-and-civil-forfeiture-acts-draw-criticism-9.6987077"}]},"nt-bill-49-20-1":{"officialUrl":"https://www.ntlegislativeassembly.ca/documents-proceedings/bills/safer-communities-and-neighbourhoods-act","factCheck":"Verified: Bill 49 (SCAN) was introduced June 1-2, 2026 by Justice Minister Jay Macdonald and creates a civil process to address properties used for illegal activity; it had not yet received final passage/Assent as of mid-June 2026, and a Yukon lawyer plus social-service groups have warned parts of comparable laws have been ruled unconstitutional.","sources":[{"title":"Minister Macdonald introduces Safer Communities and Neighbourhoods Act (Government of the NWT)","url":"https://www.gov.nt.ca/en/newsroom/minister-macdonald-introduces-safer-communities-and-neighbourhoods-act-support-safe","type":"official"},{"title":"Yukon lawyer says N.W.T.'s proposed eviction legislation targeting drug dealers could be unconstitutional (CBC North)","url":"https://www.cbc.ca/news/canada/north/scan-yukon-nwt-1.7505078","type":"news"},{"title":"N.W.T.'s proposed SCAN and civil forfeiture laws criticized as potentially unfair, redundant (CBC North)","url":"https://www.cbc.ca/news/canada/north/proposed-nwt-scan-and-civil-forfeiture-acts-draw-criticism-9.6987077","type":"news"},{"title":"NWT formally introduces SCAN legislation for consideration by MLAs (Cabin Radio)","url":"https://cabinradio.ca/293433/news/politics/nwt-formally-introduces-scan-legislation-for-consideration-by-mlas/","type":"news"},{"title":"Crime, criminality alarm communities across NWT, says report (CKLB Radio)","url":"https://cklbradio.com/2026/06/01/crime-criminality-alarm-communities-across-nwt-says-report/","type":"news"}],"commentary":[{"source":"Jay Macdonald, Minister of Justice","stance":"support","quote":"Every Northerner deserves to feel safe in their home, in their neighbourhood, and in their community... [SCAN targets] illegal activity that can endanger communities, disrupt neighbourhoods and create space for organized crime — not those dealing with addiction, poverty, homelessness or mental health challenges.","url":"https://www.gov.nt.ca/en/newsroom/minister-macdonald-introduces-safer-communities-and-neighbourhoods-act-support-safe"},{"source":"Yukon lawyer (via CBC North)","stance":"oppose","quote":"A lawyer and civil rights groups say similar legislation has been deemed unconstitutional; targets are often very vulnerable, already involved with the criminal-justice or child-and-family-services systems, and don't usually hire legal counsel to fight an eviction notice.","url":"https://www.cbc.ca/news/canada/north/scan-yukon-nwt-1.7505078"},{"source":"Hay River resident (via CBC North, public engagement)","stance":"mixed","quote":"If the SCAN officer has no more say than our MLA, or the housing authority, or the police, and it's just another person doing the same thing without any added benefit, then I'm not certain that there's a point to it.","url":"https://www.cbc.ca/news/canada/north/proposed-nwt-scan-and-civil-forfeiture-acts-draw-criticism-9.6987077"}]},"nt-bill-46-20-1":{"officialUrl":"https://www.ntlegislativeassembly.ca/committees/government-operations","factCheck":"Verified: Bill 46 is a private member's anti-SLAPP bill introduced by MLA George Nerysoo (at Elder Lawrence Norbert's request), passed second reading in March 2026 and is in committee; it does not protect deliberately false, hateful or malicious speech, and if passed would be the first anti-SLAPP law in a Canadian territory.","sources":[{"title":"Could the NWT be the first territory to pass an anti-SLAPP law? (Cabin Radio)","url":"https://cabinradio.ca/288493/news/politics/could-the-nwt-be-the-first-territory-to-pass-an-anti-slapp-law/","type":"news"},{"title":"Bill aims to protect citizens' right to speak on matters of public interest (CKLB Radio)","url":"https://cklbradio.com/2026/05/13/bill-aims-to-protect-citizens-right-to-speak-on-matters-of-public-interest-without-fear-of-legal-retribution/","type":"news"},{"title":"NWT legislators review bill to protect free speech from reprisals (The Regional)","url":"https://www.theregional.com/nwt-legislators-review-bill-to-protect-free-speech-from-reprisals/","type":"news"},{"title":"Standing Committee on Government Operations (Legislative Assembly of the NWT)","url":"https://www.ntlegislativeassembly.ca/committees/government-operations","type":"official"}],"commentary":[{"source":"Lawrence Norbert, Tsiigehtchic Elder (bill's instigator)","stance":"support","quote":"We are finally finding our voices. We cannot allow lawsuits to take them away.","url":"https://cklbradio.com/2026/05/13/bill-aims-to-protect-citizens-right-to-speak-on-matters-of-public-interest-without-fear-of-legal-retribution/"},{"source":"Kieron Testart, MLA (Range Lake)","stance":"support","quote":"Any tools we can bring forward to protect... Charter rights of citizens to speak their piece... is a huge benefit.","url":"https://cabinradio.ca/288493/news/politics/could-the-nwt-be-the-first-territory-to-pass-an-anti-slapp-law/"},{"source":"Denny Rodgers, MLA (Inuvik Boot Lake)","stance":"support","quote":"Rodgers called it 'a good private member's bill' that MLAs could 'move forward.'","url":"https://cabinradio.ca/288493/news/politics/could-the-nwt-be-the-first-territory-to-pass-an-anti-slapp-law/"}]},"nt-bill-34-20-1":{"officialUrl":"https://www.ntlegislativeassembly.ca/documents-proceedings/bills/trespass-property-act","factCheck":"Verified: Bill 34, the NWT's first trespass statute, passed with unanimous support of the 18 voting MLAs and received Assent March 6, 2026; it includes explicit safeguards stating Indigenous and treaty rights take precedence in any conflict.","sources":[{"title":"The NWT gets a Trespass Act for the first time (Cabin Radio)","url":"https://cabinradio.ca/282356/news/politics/the-nwt-gets-a-trespass-act-for-the-first-time/","type":"news"},{"title":"Trespass to Property Act — Bill 34-20(1) status page (Legislative Assembly of the NWT)","url":"https://www.ntlegislativeassembly.ca/documents-proceedings/bills/trespass-property-act","type":"official"},{"title":"Have Your Say — Public Safety Legislation (Government of the NWT engagement)","url":"https://haveyoursay.nwt-tno.ca/public-safety-legislation","type":"official"},{"title":"Bills & Legislation — 20th Assembly, 1st Session (Legislative Assembly of the NWT)","url":"https://www.ntlegislativeassembly.ca/documents-proceedings/bills","type":"official"}],"commentary":[{"source":"Jay Macdonald, Minister of Justice","stance":"support","quote":"The proposed bill includes significant safeguards for Indigenous rights, including explicit recognition of Indigenous and treaty rights – ensuring Indigenous and treaty rights take precedence in the event of conflict.","url":"https://cabinradio.ca/282356/news/politics/the-nwt-gets-a-trespass-act-for-the-first-time/"},{"source":"Shauna Morgan, MLA (Yellowknife North)","stance":"mixed","quote":"Morgan worried about expanding enforcement powers beyond the RCMP, questioning whether bylaw officers or security personnel should have authority to detain people simply for trespassing without causing specific trouble.","url":"https://cabinradio.ca/282356/news/politics/the-nwt-gets-a-trespass-act-for-the-first-time/"},{"source":"Kieron Testart, MLA (Range Lake)","stance":"mixed","quote":"Testart emphasized that regulating private security companies connects directly to public-safety priorities, after security guards were charged with assaulting an Elder.","url":"https://cabinradio.ca/282356/news/politics/the-nwt-gets-a-trespass-act-for-the-first-time/"}]},"nu-bill-1-spring-2026":{"officialUrl":"https://www.assembly.nu.ca/sites/default/files/2026-05/Bill_1_Appropriation_%28OM%29_Act_2026-2027_EF.pdf","factCheck":"Verified: the $2.47B operations budget was tabled May 25, 2026 by Premier/Finance Minister John Main and received royal assent June 11, 2026; figure and 8% increase confirmed across CBC, Nunatsiaq News and Nunavut News.","sources":[{"title":"Bills and Legislation - Legislative Assembly of Nunavut","url":"https://www.assembly.nu.ca/bills-and-legislation","type":"official"},{"title":"Bill 1 - Appropriation (Operations and Maintenance) Act, 2026-2027 (PDF)","url":"https://www.assembly.nu.ca/sites/default/files/2026-05/Bill_1_Appropriation_%28OM%29_Act_2026-2027_EF.pdf","type":"official"},{"title":"'Not the time for new shoes': GN tables 'disciplined' $2.5B budget - Nunatsiaq News","url":"https://nunatsiaq.com/stories/article/not-the-time-for-new-shoes-gn-tables-disciplined-2-5b-budget/","type":"news"},{"title":"Premier proposes doubling the Nunavut Child Benefit and increasing health spending in $2.47 billion budget - Nunavut News","url":"https://nunavutnews.com/2026/05/25/premier-proposes-doubling-the-nunavut-child-benefit-and-increasing-health-spending-in-2-47-billion-budget/","type":"news"},{"title":"Budget 2026-27 - Government of Nunavut","url":"https://www.gov.nu.ca/en/department-finance/budget-2026-27","type":"official"}],"commentary":[{"source":"Premier/Finance Minister John Main (budget address, via Nunatsiaq News)","stance":"support","quote":"It was not the time for new shoes - Main characterized the budget as 'disciplined,' emphasizing fiscal restraint rather than expansion.","url":"https://nunatsiaq.com/stories/article/not-the-time-for-new-shoes-gn-tables-disciplined-2-5b-budget/"},{"source":"Nunavut News","stance":"mixed","quote":"Health received the largest allocation at $663 million, up nearly $83 million ... [but] MLAs must still debate and vote before approval.","url":"https://nunavutnews.com/2026/05/25/premier-proposes-doubling-the-nunavut-child-benefit-and-increasing-health-spending-in-2-47-billion-budget/"}]},"nu-bill-4-spring-2026":{"officialUrl":"https://www.assembly.nu.ca/sites/default/files/2026-05/Bill_4_AATA_Income_Tax_Act_EF.pdf","factCheck":"Verified: the basic Nunavut Child Benefit rises from $348 to $696 per child annually and the 3% CPI floor is removed to index it to inflation; assent June 11, 2026, effective July 1, 2026, first increased payments September 2026. Confirmed by Nunatsiaq News, CBC and the GN.","sources":[{"title":"MLAs approve doubling Nunavut Child Benefit payments - Nunatsiaq News","url":"https://nunatsiaq.com/stories/article/mlas-approve-doubling-nunavut-child-benefit-payments/","type":"news"},{"title":"Nunavut Premier proposes doubling child benefits - Eye on the Arctic (RCI)","url":"https://www.rcinet.ca/eye-on-the-arctic/2026/05/26/nunavut-premier-proposes-doubling-child-benefits/","type":"news"},{"title":"Bill 4 - An Act to Amend the Income Tax Act (PDF)","url":"https://www.assembly.nu.ca/sites/default/files/2026-05/Bill_4_AATA_Income_Tax_Act_EF.pdf","type":"official"},{"title":"Nunavut Child Benefit (NUCB) - Government of Nunavut","url":"https://www.gov.nu.ca/en/social-supports/nunavut-child-benefit-nucb","type":"official"},{"title":"Nunavut - Welfare in Canada (Maytree)","url":"https://maytree.com/changing-systems/data-measuring/welfare-in-canada/nunavut/","type":"academic"}],"commentary":[{"source":"Premier John Main (via Nunatsiaq News)","stance":"support","quote":"Poverty and lack of food is a big problem, and it really affects small children, and it affects them in a bad way.","url":"https://nunatsiaq.com/stories/article/mlas-approve-doubling-nunavut-child-benefit-payments/"},{"source":"Premier John Main (via CBC North)","stance":"mixed","quote":"Main acknowledged the changes are small, but he hopes they'll help Nunavummiut cope with the rising cost of living.","url":"https://www.cbc.ca/news/canada/north/4-things-to-know-as-the-nunavut-legislature-wraps-up-spring-sitting-9.7233115"},{"source":"Public commenters (reported by Nunatsiaq News)","stance":"oppose","quote":"Some commenters argued the doubled amount remains insufficient and that eligibility thresholds should expand to reach more families.","url":"https://nunatsiaq.com/stories/article/mlas-approve-doubling-nunavut-child-benefit-payments/"}]},"nu-bill-2-spring-2026":{"officialUrl":"https://www.assembly.nu.ca/sites/default/files/2026-05/Bill_2_Supp._Appropriation_%28Capital%29_Act_1_2026-2027_EF.pdf","factCheck":"Verified: ~$273.9M in supplementary 2026-27 capital across ~10 departments (largest share ~$123M to Transportation & Infrastructure), assent June 11, 2026; part of an overall ~$3.7B package per CBC and Nunatsiaq News.","sources":[{"title":"Bill 2 - Supplementary Appropriation (Capital) Act, No. 1, 2026-2027 (PDF)","url":"https://www.assembly.nu.ca/sites/default/files/2026-05/Bill_2_Supp._Appropriation_%28Capital%29_Act_1_2026-2027_EF.pdf","type":"official"},{"title":"4 things to know as the Nunavut legislature wraps up spring sitting - CBC North","url":"https://www.cbc.ca/news/canada/north/4-things-to-know-as-the-nunavut-legislature-wraps-up-spring-sitting-9.7233115","type":"news"},{"title":"Bills and Legislation - Legislative Assembly of Nunavut","url":"https://www.assembly.nu.ca/bills-and-legislation","type":"official"}],"commentary":[{"source":"CBC North","stance":"mixed","quote":"The $3.7-billion spending package includes almost $274 million for capital projects ... the biggest chunk, some $123 million, will go to the transportation and infrastructure department.","url":"https://www.cbc.ca/news/canada/north/4-things-to-know-as-the-nunavut-legislature-wraps-up-spring-sitting-9.7233115"},{"source":"Nunatsiaq News","stance":"support","quote":"$273.9 million in additional capital spending for 2026-27 for projects and purchases across 10 GN departments [received assent on the final day].","url":"https://nunatsiaq.com/stories/article/mlas-approve-doubling-nunavut-child-benefit-payments/"}]},"nu-bill-3-spring-2026":{"officialUrl":"https://www.assembly.nu.ca/sites/default/files/2026-05/Bill_3_MSAA_Spring_2026_EF.pdf","factCheck":"Verified: a Miscellaneous Statutes Amendment Act making technical/plain-language updates to various territorial laws passed the spring 2026 sitting with assent June 11, 2026 (CBC, Nunatsiaq News). Detailed clause list not publicly itemized in coverage; the official bill text is the authoritative source.","sources":[{"title":"Bill 3 - Miscellaneous Statutes Amendment Act, Spring 2026 (PDF)","url":"https://www.assembly.nu.ca/sites/default/files/2026-05/Bill_3_MSAA_Spring_2026_EF.pdf","type":"official"},{"title":"4 things to know as the Nunavut legislature wraps up spring sitting - CBC North","url":"https://www.cbc.ca/news/canada/north/4-things-to-know-as-the-nunavut-legislature-wraps-up-spring-sitting-9.7233115","type":"news"},{"title":"Bills and Legislation - Legislative Assembly of Nunavut","url":"https://www.assembly.nu.ca/bills-and-legislation","type":"official"}],"commentary":[{"source":"CBC North","stance":"mixed","quote":"A bill called the Miscellaneous Statutes Amendment Act updated the language in various territorial laws.","url":"https://www.cbc.ca/news/canada/north/4-things-to-know-as-the-nunavut-legislature-wraps-up-spring-sitting-9.7233115"},{"source":"Legislative Assembly of Nunavut (official)","stance":"support","quote":"Listed as Bill 3, Miscellaneous Statutes Amendment Act - passed, assent June 11, 2026.","url":"https://www.assembly.nu.ca/bills-and-legislation"}]},"nu-draft-devolution-package-tabled-june-12-2026-":{"officialUrl":"https://nunatsiaq.com/stories/article/nunavut-premier-releases-draft-versions-of-devolution-legislation/","factCheck":"Verified: on June 12, 2026 Premier Main released DRAFT versions (not formally introduced) of the Public Lands Act, Waters Act, Surface Rights Tribunal Act and Archaeological and Palaeontological Sites Act, to be formally introduced in fall 2026/winter 2027; devolution takes effect April 1, 2027 under the Jan 18, 2024 agreement. Confirmed by Nunatsiaq News, CBC and legal analyses (Osler).","sources":[{"title":"Nunavut premier releases draft versions of devolution legislation - Nunatsiaq News","url":"https://nunatsiaq.com/stories/article/nunavut-premier-releases-draft-versions-of-devolution-legislation/","type":"news"},{"title":"Meet MNRL - Nunavut's new Department of Mines, Natural Resources and Land - Nunatsiaq News","url":"https://nunatsiaq.com/stories/article/meet-mnrl-nunavuts-new-department-of-mines-natural-resources-and-land/","type":"news"},{"title":"Nunavut to take control of Crown land within territory following devolution agreement with Canada - Osler","url":"https://www.osler.com/en/insights/updates/nunavut-to-take-control-of-crown-land-within-territory-following-devolution-agreement-with-canada/","type":"legal"},{"title":"Nunavut has 1 year left before devolution comes into effect. Is the territory ready? - CBC News","url":"https://www.cbc.ca/news/canada/north/nunavut-devolution-one-year-9.7147588","type":"news"},{"title":"Nunavut Devolution: A Nation-Building Moment for Canada's Third Territory - Ontario Bar Association","url":"https://oba.org/nunavut-devolution-a-nation-building-moment-for-canada-s-third-territory/","type":"legal"}],"commentary":[{"source":"Premier John Main (via Nunatsiaq News)","stance":"support","quote":"Allowing this review period now will help support a more efficient legislative process when these bills are formally introduced during the fall 2026 and winter 2027 sittings.","url":"https://nunatsiaq.com/stories/article/nunavut-premier-releases-draft-versions-of-devolution-legislation/"},{"source":"Osler, Hoskin & Harcourt LLP (legal analysis)","stance":"mixed","quote":"Nunavut is required under the Agreement to enact territorial legislation that substantially mirrors federal Acts before April 1, 2027.","url":"https://www.osler.com/en/insights/updates/nunavut-to-take-control-of-crown-land-within-territory-following-devolution-agreement-with-canada/"},{"source":"Ontario Bar Association","stance":"support","quote":"Nunavut Devolution: A Nation-Building Moment for Canada's Third Territory.","url":"https://oba.org/nunavut-devolution-a-nation-building-moment-for-canada-s-third-territory/"}]},"nu-bill-1-winter-2026":{"officialUrl":"https://www.assembly.nu.ca/bills-and-legislation","factCheck":"Verified: the winter sitting (Feb 22 - Mar 16, 2026) passed a $724.9M interim O&M budget, a $373.2M capital plan, and supplementary bills ($158.6M O&M; $41.9M capital) for 2025-26; assent given mid-March 2026. Confirmed by Nunatsiaq News and CBC.","sources":[{"title":"More than $1B on the table in legislative assembly - Nunatsiaq News","url":"https://nunatsiaq.com/stories/article/more-than-1b-on-the-table-in-legislative-assembly/","type":"news"},{"title":"4 spending bills passed as legislative assembly nears close - Nunatsiaq News","url":"https://nunatsiaq.com/stories/article/4-spending-bills-passed-as-legislative-assembly-nears-close/","type":"news"},{"title":"Money bills and a 'how' mandate: Premier previews winter legislative sitting - Nunatsiaq News","url":"https://nunatsiaq.com/stories/article/money-bills-and-a-how-mandate-premier-previews-winter-legislative-sitting/","type":"news"},{"title":"Bills and Legislation - Legislative Assembly of Nunavut","url":"https://www.assembly.nu.ca/bills-and-legislation","type":"official"}],"commentary":[{"source":"Nunatsiaq News","stance":"support","quote":"Premier John Main tabled Bill 1 of the seventh assembly: a $724.9-million interim operations and maintenance budget for the 2026-27 fiscal year ... covering the cost of running 14 government departments.","url":"https://nunatsiaq.com/stories/article/more-than-1b-on-the-table-in-legislative-assembly/"},{"source":"Nunatsiaq News","stance":"mixed","quote":"The interim bill acted as a stopgap until the Finance Department tabled a full operations spending plan ... delayed by October's territorial election.","url":"https://nunatsiaq.com/stories/article/4-spending-bills-passed-as-legislative-assembly-nears-close/"}]}};
